-- Poems batch 350
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fec18d0f-a5f7-4cd6-9be1-e9c205cc474b','松風','釋智圓','宋','宋诗','song-poetry','','[]','青青數樹松，扶疏空庭裏。',121,'全唐诗/poet.song.7000.json','["青青數樹松，扶疏空庭裏。", "微風從南來，清聲四向起。", "俗兮聞必愁，吾也聞則喜。", "昂頭離石枕，扶立式憑藤几。", "側聽復遙觀，移晷不能已。", "細葉舞輕煙，密影搖寒水。", "何必鈞天奏，豈羨霓裳妓。", "萬事更無求，深山此爲美。", "寂寥信爲樂，軒冕誠堪恥。", "誰謂茆山中，只悅陶公耳。"]'),
('4e8ba0f0-964d-4610-9fe1-03883fcea272','古劍','釋智圓','宋','宋诗','song-poetry','','[]','精剛經百鍊，可折不可柔。',108,'全唐诗/poet.song.7000.json','["精剛經百鍊，可折不可柔。", "三尺青蛇活，一匣止水秋。", "解截蛟龍軀，能斷佞臣頭。", "下去蒼生害，上除天子讎。", "在昔埋酆城，精光射斗牛。", "雷煥張華輩，得之亦悠悠。", "二賢既云亡，潭底化雙虬。", "劍利人或愛，劍道人不求。", "劍道如之何，達者惟莊周。"]'),
('2a1a1562-30f2-44da-9302-974aa3b0bab9','自勉','釋智圓','宋','宋诗','song-poetry','','[]','達人貴無念，市朝亦山林。',216,'全唐诗/poet.song.7000.json','["達人貴無念，市朝亦山林。", "曲士居山林，難息市朝心。", "坐馳一室中，紛然萬境侵。", "紐蘭羨珮玉，坐石思黄金。", "羊質虎其皮，隼翼鳳其音。", "志在求世利，口唱無生吟。", "吾非斯人徒，夷曠期復古。", "去住既任緣，喧靜亦隨所。", "陶然且無求，相命何足語。", "人生百歲壽，稀得七十死。", "吾今四十五，氣力漸無似。", "去年成二毛，今年動一齒。", "縱得至七十，光陰能幾許。", "學道宜無疲，進善宜無止。", "自餘百雜就，克己盡除去。", "勉強扶幻軀，旦暮加藥餌。", "此身乃外物，何況外於是。", "內外一如夢，勉矣當觀此。"]'),
('8eb2745d-24ba-4ea0-8fa2-ff19d341a68a','病起自敘','釋智圓','宋','宋诗','song-poetry','','[]','盜跖死牖下，伯牛遭惡疾。',288,'全唐诗/poet.song.7000.json','["盜跖死牖下，伯牛遭惡疾。", "報應似無徵，蒼蒼意難悉。", "乃考竺乾教，其旨明踰日。", "業以三世論，事匪二生訖。", "伊余本好道，執善長慮失。", "無端六腑病，每苦我形質。", "百骸失調暢，四時少安逸。", "今歲夏云滿，秋熟如火室。", "脾疾因茲生，頓覺減寢食。", "無何誤服藥，到瀉苦非一。", "過客爲憂惶，兒童亦戰慄。", "吾心暗且喜，浮生從此畢。", "發言囑後學，此事汝無恤。", "吾年四十五，去矣非短屈。", "至理無去來，妄想分凶吉。", "我先鑿山窟，汝宜即藏密。", "不用報親朋，無學世哭泣。", "四時爲送葬，庶物甚充給。", "遺文三百卷，空言或可習。", "見惡如探湯，見善如不及。", "湛湛無生源，深淺當自挹。", "囑之語方終，忽覺病小醒。", "扶几起暫坐，漸漸四體輕。", "又過三五日，倚杖登危亭。"]'),
('cfc6e609-46d1-4e50-b2eb-3b3431c9444b','獨遊','釋智圓','宋','宋诗','song-poetry','','[]','城市非無親，不見歲已深。',96,'全唐诗/poet.song.7000.json','["城市非無親，不見歲已深。", "江湖非無友，經年無來音。", "因知疏拙性，不合時人心。", "清景將誰觀，荷策只自尋。", "乃登嵯峨峰，乃縱酸寒吟。", "狎我惟野麋，和我惟幽禽。", "但見雲起滅，不知誰升沈。", "盤桓紅樹下，秋露濕衣襟。"]'),
('f6e56dcd-07e0-426a-a675-5e611a79b3c5','言志','釋智圓','宋','宋诗','song-poetry','','[]','疇昔學爲文，擬盡周孔道。',252,'全唐诗/poet.song.7000.json','["疇昔學爲文，擬盡周孔道。", "心勞道未至，壯歲成衰老。", "疇昔學爲詩，模範風雅詞。", "立言多諷喻，反爲時人嗤。", "爲詩復爲文，嗟嗟不復古。", "訓世無纖益，何爲自勞苦。", "權門既不游，青山寧合負。", "一來林下居，四載不出戶。", "退省爲佛徒，講經自裨補。", "憧憧來學輩，往往入深塢。", "智者乃吾宗，龍猛乃吾祖。", "寒窗夜摛毫，虛堂晝揮麈。", "翼此二聖心，欲令萬物睹。", "羸羸長抱疾，行年四十五。", "草堂三四間，牢落連雲洞。", "經時無客來，衡門絕迎送。", "榻有無弦琴，向風時一弄。", "窗列楞嚴典，要言長諷誦。", "真妄一無得，超然誰與共。", "凡聖病眼花，死生春夜夢。", "病差夢已醒，萬彙徒營營。"]'),
('647d9890-8a7a-4e1f-bdd9-7da9e6963831','病中翫月','釋智圓','宋','宋诗','song-poetry','','[]','歲歲中秋夜，翫月泛平湖。',192,'全唐诗/poet.song.7000.json','["歲歲中秋夜，翫月泛平湖。", "今爲病所侵，伏枕此約辜。", "輾轉席蓐間，四體如松枯。", "辛酸滋味加，閑況適興徂。", "入夜月漸高，晃晃照廊廡。", "冷色射軒窗，爽氣襲庭蕪。", "澤畔唳孤鶴，聲聲若相呼。", "是時披衣起，頓覺病魂穌。", "倚杖來前軒，竹榻教人鋪。", "與月相對坐，歡翫如同徒。", "流睇及羣物，光彩一何殊。", "遙山列銀屏，空潭開玉壺。", "樓臺飾瓊瑤，階除若冰敷。", "寄語求仙輩，何必去玄都。", "逡巡月西落，竚立更踟躕。", "一別又一年，明年知在無。"]'),
('f8e9ea02-9472-40c9-9e23-97ccdeb490b5','潛夫詠','釋智圓','宋','宋诗','song-poetry','','[]','有叟匿姓名，自號爲潛夫。',180,'全唐诗/poet.song.7000.json','["有叟匿姓名，自號爲潛夫。", "潛身在雲泉，潛心入虛無。", "身心俱已潛，質直反若諭。", "智者謂之智，愚者謂之愚。", "愚智自彼異，潛夫未曾殊。", "陶陶樂天和，任性何曾拘。", "宗儒述孟軻，好道注陰符。", "虛堂踞高臺，往往談浮圖。", "漫衍雖無家，大方貴無隅。", "俗人每側目，訂之爲狂徒。", "素隱而行怪，執政宜先誅。", "天公既保全，幸得存微軀。", "衝雪登高山，乘月泛平湖。", "性靈敵雲閑，形骸類松枯。", "何以免饑寒，認得衣中珠。"]'),
('8641cb72-2a8e-4f45-9d64-447ff9df01d7','松下自遣','釋智圓','宋','宋诗','song-poetry','','[]','聚氣成此身，假緣暫寄世。',216,'全唐诗/poet.song.7000.json','["聚氣成此身，假緣暫寄世。", "可憐自在性，本無煩惱繫。", "傍水與登山，翛然有深詣。", "日在林下游，暮在林下宿。", "供飲巖畔泉，充庖檻前菊。", "半月一剃髪，半年一洗浴。", "但得恣疏懶，何曾有榮辱。", "新秋雨初霽，圓月照我屋。", "扶病起看月，坐久偶成曲。", "人生天地間，性分各自足。", "捧檄何必喜，途窮何必哭。", "容彭不爲長，顔楊不爲促。", "四者俱如夢，何爲自羈束。", "彼笑我太狂，我笑彼太俗。", "彼我更相笑，是非無實錄。", "不如長默默，恬淡過昏旭。", "淵魚與林鳥，各得隨所欲。", "舉頭誰是友，風月與松竹。"]'),
('2b7baaa1-9ea3-4633-9279-41940b79a592','哭葉授','釋智圓','宋','宋诗','song-poetry','','[]','今春聞落第，爲君心悽然。',96,'全唐诗/poet.song.7000.json','["今春聞落第，爲君心悽然。", "束書獨南還，憤氣胸間闐。", "跡寄浙河旁，家延南海邊。", "遘疾既彌留，一命成棄捐。", "囊中無餘金，零落空文編。", "龜鶴本微類，享壽皆千年。", "如何君子儒，三十歸重泉。", "天高不可問，爲君強問天。"]'),
('94148502-1ed3-4f24-a8e8-1e22e45ff4f0','讀白樂天集','釋智圓','宋','宋诗','song-poetry','','[]','李杜之爲詩，句亦模山水。',168,'全唐诗/poet.song.7000.json','["李杜之爲詩，句亦模山水。", "錢郎之爲詩，旨類圖神鬼。", "諷刺義不明，風雅猶不委。", "於鑠白樂天，崛起冠唐賢。", "下視十九章，上踵三百篇。", "句句歸勸誡，首首成規箴。", "謇諤賀雨詩，激切秦中吟。", "樂府五十章，譎諫何幽深。", "美哉詩人作，展矣君子心。", "豈顧鑠金口，志遏亂雅音。", "齪齪無識徒，鄙這元白體。", "良玉爲碔砆，人參呼荒苨。", "須知百世下，自有知音者。", "所以長慶集，于今滿朝野。"]'),
('d97d5f45-6fa0-465a-85d4-f10637ba685f','孤山種桃','釋智圓','宋','宋诗','song-poetry','','[]','領童閑荷鋤，埋核間羣木。',120,'全唐诗/poet.song.7000.json','["領童閑荷鋤，埋核間羣木。", "他人顧我笑，豈察我心曲。", "我欲千樹桃，夭夭徧山谷。", "山椒如錦斕，山墟若霞簇。", "下照平湖水，上繞幽人屋。", "清香滿鄰里，濃艷蔽林麓。", "奪取武陵春，來悅游人目。", "花開復花落，知榮必有辱。", "榮辱苟能齊，人人心自足。", "須知我種桃，可以化風俗。"]'),
('059e4695-b3af-4824-bb91-8cf92d3e32e8','寄林逋處士','釋智圓','宋','宋诗','song-poetry','','[]','湖山淡相映，世塵那得侵。',96,'全唐诗/poet.song.7000.json','["湖山淡相映，世塵那得侵。", "杳杳煙波色，蒼蒼雲木陰。", "苔荒石徑險，犬吠桃源深。", "中有上皇人，高眠適閑心。", "花開還獨酌，花落還獨吟。", "空庭長瑤草，幽樹鳴仙禽。", "不見已三載，鄙吝盈虛襟。", "終期秋月明，乘興閑相尋。"]'),
('929b1834-badb-4f6c-8b67-4492e16ff871','早秋','釋智圓','宋','宋诗','song-poetry','','[]','雨歇變氣候，空庭葉颼颼。',84,'全唐诗/poet.song.7000.json','["雨歇變氣候，空庭葉颼颼。", "閑聽一夜風，乃知千里秋。", "百蟲鳴四壁，新月生高樓。", "登樓看明月，清光滿林丘。", "人生呼吸間，何爲苦憂愁。", "髪白不再黑，兔走難暫留。", "徘徊感古人，勸我秉燭遊。"]'),
('df3bf550-fdc2-4ad4-9d68-b7e10659d6c6','心交如美玉','釋智圓','宋','宋诗','song-poetry','','[]','心交如美玉，經火終不熱。',60,'全唐诗/poet.song.7000.json','["心交如美玉，經火終不熱。", "面交如浮雲，頃刻即變滅。", "對坐成參商，咫尺成胡越。", "我有心交者，不見幾歲月。", "山疊水茫茫，含情向誰說。"]'),
('b32f33e1-6c8d-453c-b170-729efdf28144','古人與今人','釋智圓','宋','宋诗','song-poetry','','[]','古人與今人，祿仕一何異。',72,'全唐诗/poet.song.7000.json','["古人與今人，祿仕一何異。", "古今貴行道，今人貴有位。", "古人貴及親，今人貴說意。", "古人同白日，光明溢天地。", "今人如履險，動足易顛墜。", "古道如可行，斯言不遐棄。"]'),
('a32370f2-e9fc-4e14-a458-906faa715e2e','代書寄奉蟾上人','釋智圓','宋','宋诗','song-poetry','','[]','君居武康山，昔年我曾游。',144,'全唐诗/poet.song.7000.json','["君居武康山，昔年我曾游。", "崎嶇松徑寒，冷落竹房秋。", "握手既歡笑，拂榻且相留。", "一駐十旬餘，旦夕樂清幽。", "因話凈名事，滌硯勉操修。", "蠻香爇古篆，山茶分越甌。", "看雪同擁爐，乘月共浮舟。", "喻心指太虛，視世類浮漚。", "明春我歸去，湖上隱林丘。", "杜門過五載，脾疾日少瘳。", "閑宵坐月下，往事來心頭。", "書之將寄君，路遠水悠悠。"]'),
('ba055a84-5ff8-4e31-87b8-22ca709a440c','湖居感傷','釋智圓','宋','宋诗','song-poetry','','[]','迷真渺無始，飄業產錢唐。',288,'全唐诗/poet.song.7000.json','["迷真渺無始，飄業產錢唐。", "外族宗南郡，門風祖偃王。", "微緣先劫種，宿習妙齡彰。", "父母憐多病，親賓怪異常。", "布花模講道，畫石學題章。", "戒印齓年佩，心猿志學狂。", "榮名虛準擬，簪組妄思量。", "禮樂師周孔，虛無學老莊。", "躁嫌成器晚，心競寸陰忙。", "翼翼修天爵，孜孜恥面牆。", "內藏儒志氣，外假佛衣裳。", "每惡銷金口，時勞疾惡腸。", "手中期得桂，箭下待穿腸。", "騃鹿方隨燄，堅冰忽遇陽。", "繫珠知在體，甘露忝親嘗。", "要道傳三觀，真機得妙常。", "不然心迹火，任結鬢根霜。", "覺路雙輪駕，真空兩翅翔。", "饑來還遇膳，渴去已逢漿。", "靜處如來室，高眠解脫床。", "理高山峭拔，道大海汪洋。", "力戰魔軍散，功扶佛化昌。", "空山憐寂寂，塵路笑茫茫。", "觸境知無著，閑居貴坐忘。"]'),
('24b39be6-a796-4688-8582-ed5e53432fca','讀清塞集','釋智圓','宋','宋诗','song-poetry','','[]','立意造平淡，冥搜出常情。',48,'全唐诗/poet.song.7000.json','["立意造平淡，冥搜出常情。", "何人知所得，後世謾傳名。", "雲樹饑猨斷，冰潭片月傾。", "如無子期聽，綠綺爲誰鳴。"]'),
('cde83803-3d91-4ce1-8be1-e536de11cf24','寄趙璞','釋智圓','宋','宋诗','song-poetry','','[]','故鄉勾踐國，解印掛帆歸。',48,'全唐诗/poet.song.7000.json','["故鄉勾踐國，解印掛帆歸。", "吟苦容雖瘦，官情道自肥。", "堂幽山屐在，廚冷甑塵飛。", "莫向雲門下，高歌便採薇。"]'),
('da2fd4e6-2e49-45e5-8090-413c01cb1c35','山中與友人夜話','釋智圓','宋','宋诗','song-poetry','','[]','草舍閑宵坐，消搖事可評。',48,'全唐诗/poet.song.7000.json','["草舍閑宵坐，消搖事可評。", "澄心防有著，深隱貴無名。", "砌月移松影，風泉混磬聲。", "共期吾道在，萬事任營營。"]'),
('c9ad4a46-8b7e-43d1-b915-1aaae1668264','閑居書事','釋智圓','宋','宋诗','song-poetry','','[]','淡然忘外事，林下自怡情。',48,'全唐诗/poet.song.7000.json','["淡然忘外事，林下自怡情。", "室冷秋苔色，軒閑夜月明。", "眠雲慚道薄，鉺藥覺身輕。", "擬學鴟夷子，時時變姓名。"]'),
('a3e1791c-8259-4598-8fd2-bd72f2a3a335','禹廟','釋智圓','宋','宋诗','song-poetry','','[]','洪水不爲害，黎元受賜多。',48,'全唐诗/poet.song.7000.json','["洪水不爲害，黎元受賜多。", "道尊由揖讓，功大匪干戈。", "任上諸侯貢，貽謀五子歌。", "稽山千古在，宮闕倚嵯峨。"]'),
('0939f742-2c0c-4d94-bc77-581253988f94','早行','釋智圓','宋','宋诗','song-poetry','','[]','杖錫無同侶，衝霜獨自行。',48,'全唐诗/poet.song.7000.json','["杖錫無同侶，衝霜獨自行。", "斷橋殘月在，孤店曉雞鳴。", "灌木棲禽散，荒原宿霧平。", "迴觀遠山色，已覺太陽明。"]'),
('5350c8f3-0459-4d94-82bc-6578775152fd','江上聞笛','釋智圓','宋','宋诗','song-poetry','','[]','夜久聞橫笛，寥寥景更賒。',48,'全唐诗/poet.song.7000.json','["夜久聞橫笛，寥寥景更賒。", "天容垂極岸，月色冷平沙。", "靜引鄉心遠，閑驚旅鬢華。", "哀音殊未已，可處落梅花。"]'),
('6d012a30-a603-4c68-b0ec-16a634a5b415','詠燕','釋智圓','宋','宋诗','song-poetry','','[]','來去知時候，堪憐異衆禽。',48,'全唐诗/poet.song.7000.json','["來去知時候，堪憐異衆禽。", "雙飛春雨細，對語畫堂深。", "寄宿雕梁穩，銜泥柳岸陰。", "棲身自有處，鷹隼莫相侵。"]'),
('efd51e89-e390-47d4-94df-f12a0cc23907','讀杜牧集','釋智圓','宋','宋诗','song-poetry','','[]','讒佞當面唾，輕生不得殳。',48,'全唐诗/poet.song.7000.json','["讒佞當面唾，輕生不得殳。", "去邪空有志，嫉惡奈無徒。", "後世名垂遠，當時道亦孤。", "荒齋獨懷感，殘日照庭蕪。"]'),
('5b9c5bcb-4ded-4516-9b0c-22488f8db09c','寄題聰上人房庭竹','釋智圓','宋','宋诗','song-poetry','','[]','結根依靜砌，蕭灑映禪房。',48,'全唐诗/poet.song.7000.json','["結根依靜砌，蕭灑映禪房。", "高節欺羣木，青陰過短牆。", "夜聲喧夢枕，秋露滴琴床。", "遙想添吟思，閑觀到夕陽。"]'),
('4a03c23f-fb65-414f-bc1f-85c28ac534dd','武肅廟','釋智圓','宋','宋诗','song-poetry','','[]','土德衰微後，忠誠道不羣。',48,'全唐诗/poet.song.7000.json','["土德衰微後，忠誠道不羣。", "誓功陳带礪，霸業擬桓文。", "妙略姦雄懾，英聲四海聞。", "山旁遺廟在，牢落閉深雲。"]'),
('2e533ee7-d6e2-4b29-bd32-63a3927b7c11','寄蜀川王道士','釋智圓','宋','宋诗','song-poetry','','[]','鶴駕幾遲留，岷峨水石幽。',48,'全唐诗/poet.song.7000.json','["鶴駕幾遲留，岷峨水石幽。", "御風同列子，夢蝶擬莊周。", "醉臥空林月，狂歌古觀秋。", "何時歸閬苑，閑共老仙遊。"]'),
('1ab7f981-bd6e-4173-a15d-8acbd479a1d4','寄道士','釋智圓','宋','宋诗','song-poetry','','[]','長聞披鶴氅，城市往來頻。',48,'全唐诗/poet.song.7000.json','["長聞披鶴氅，城市往來頻。", "得道人難測，和光迹易親。", "堂閑秋擣藥，壇冷夜朝真。", "幾憶蓬壺頂，蟠桃斕漫春。"]'),
('1aa00b06-2d61-4c83-bb37-100c6fcaf408','寄定海許少府','釋智圓','宋','宋诗','song-poetry','','[]','見說梅仙邑，波濤接杳冥。',48,'全唐诗/poet.song.7000.json','["見說梅仙邑，波濤接杳冥。", "訟庭秋蘚合，吟閣海雲醒。", "愛月宵留客，尋僧晝掩扃。", "公餘幽興在，時夢故山青。"]'),
('91243df9-fc90-4b63-a4e7-ad3a5d600c84','寄若訥上人','釋智圓','宋','宋诗','song-poetry','','[]','江濱方話別，倏忽十年餘。',48,'全唐诗/poet.song.7000.json','["江濱方話別，倏忽十年餘。", "感舊空闕夢，閑眠懶寄書。", "砌涼鳴蟋蟀，潭冷照蟾蜍。", "北望滄波闊，無由訪所居。"]'),
('58ce6959-639d-4d42-a350-9cfcd130d7f8','山中尋羽客不遇','釋智圓','宋','宋诗','song-poetry','','[]','杖蔾尋隱迹，重疊過林泉。',48,'全唐诗/poet.song.7000.json','["杖蔾尋隱迹，重疊過林泉。", "花暖幽禽語，堂空瑞獸眠。", "澗松寒有韻，茶竈冷無煙。", "知在何峰頂，高談會列仙。"]'),
('e7d7495c-ca9a-45e0-8371-b71518fb4f5e','送人南遊','釋智圓','宋','宋诗','song-poetry','','[]','難阻南遊興，酣歌出故林。',48,'全唐诗/poet.song.7000.json','["難阻南遊興，酣歌出故林。", "路分滄海闊，山疊瘴雲深。", "馬援碑寧在，重華廟可尋。", "他年卻歸此，閑話學夷音。"]'),
('1a4f76e9-66d9-40f7-b816-aa071b546fd8','懷同志','釋智圓','宋','宋诗','song-poetry','','[]','孤吟成白首，十載別同聲。',48,'全唐诗/poet.song.7000.json','["孤吟成白首，十載別同聲。", "海國書難到，空堂夢易成。", "淳風心共樂，直道世多輕。", "未卜重相見，波濤萬里程。"]'),
('f6731ec3-4051-436e-be90-2f66422551a5','聞蛩','釋智圓','宋','宋诗','song-poetry','','[]','沉沉向秋暮，切切聲相續。',24,'全唐诗/poet.song.7000.json','["沉沉向秋暮，切切聲相續。", "夜靜草堂深，閑床照孤燭。"]'),
('3bf5b183-2e52-468d-a013-f226ce542506','湖上閑坐','釋智圓','宋','宋诗','song-poetry','','[]','終日湖亭坐，悠悠萬慮閑。',24,'全唐诗/poet.song.7000.json','["終日湖亭坐，悠悠萬慮閑。", "眼前何所有，寒水與秋山。"]'),
('6ba96d55-ce14-42b6-b12f-a1a79baf281e','池上','釋智圓','宋','宋诗','song-poetry','','[]','漚生復漚滅，水濕元無異。',24,'全唐诗/poet.song.7000.json','["漚生復漚滅，水濕元無異。", "盡日倚欄看，無人知此意。"]'),
('ecc65090-ca6f-4cef-97bf-c8376665b30a','草堂即事','釋智圓','宋','宋诗','song-poetry','','[]','經歲人不到，騰騰養疏拙。',48,'全唐诗/poet.song.7000.json','["經歲人不到，騰騰養疏拙。", "心期物外閑，緣向漚中絕。", "入室容清風，升堂許明月。", "空庭何所有，冷落唯松雪。"]'),
('4ef4cefc-e515-4cb6-87f7-f0c264c32603','讀楞嚴經','釋智圓','宋','宋诗','song-poetry','','[]','案上楞嚴典，時看浣病愁。',48,'全唐诗/poet.song.7000.json','["案上楞嚴典，時看浣病愁。", "階閑移短影，窗冷值高秋。", "眼病花無菓，心狂照失頭。", "指空期識月，認指更悠悠。"]'),
('52d2774b-46fe-4659-8803-38e37780225d','病中懷石壁行紹上人','釋智圓','宋','宋诗','song-poetry','','[]','石壁春歸去，孤山秋未來。',24,'全唐诗/poet.song.7000.json','["石壁春歸去，孤山秋未來。", "夜深扶病坐，明月照蒼苔。"]'),
('6fdb31df-54e4-4b9f-9a88-b03eaa435fec','謝可牧上人惠楞嚴般若二經並治脾藥','釋智圓','宋','宋诗','song-poetry','','[]','經妙蕩煩惑，藥靈醫病身。',48,'全唐诗/poet.song.7000.json','["經妙蕩煩惑，藥靈醫病身。", "道明無去住，方驗有君臣。", "靜翫知心寂，時飡覺氣均。", "徘徊感知己，於我分彌親。"]'),
('a037159f-3a67-4b63-82b2-55b1fe8bc52a','懷南遊道友','釋智圓','宋','宋诗','song-poetry','','[]','曾聞飛錫入南閩，鶴態雲蹤不可親。',64,'全唐诗/poet.song.7000.json','["曾聞飛錫入南閩，鶴態雲蹤不可親。", "靜夜獨吟空對月，昔年聚話更無人。", "波濤路阻書難到，泉石房閑夢自頻。", "未省相逢在何日，西風蕭索浙河濱。"]'),
('d704f2a8-c456-43e4-ac70-0ae9083117ba','栽花','釋智圓','宋','宋诗','song-poetry','','[]','移花來種草堂前，紅紫紛紜間淡煙。',32,'全唐诗/poet.song.7000.json','["移花來種草堂前，紅紫紛紜間淡煙。", "莫嘆朝開還暮落，人生榮辱事皆然。"]'),
('9b660dcb-9ac2-4284-8823-d7f89987f701','病起二首  其一','釋智圓','宋','宋诗','song-poetry','','[]','衡門牢落雨苔斑，病起深秋氣象閑。',65,'全唐诗/poet.song.7000.json','["衡門牢落雨苔斑，病起深秋氣象閑。", "照水未能嗟白髮，倚欄重得見青山。", "風高砌木蟬猶噪，社近茆堂燕已還。", "孤坐孤孤吟又終日，有誰來此問衰顔。"]'),
('1a9e1961-de9e-491f-8230-596b6596e0db','病起二首  其二','釋智圓','宋','宋诗','song-poetry','','[]','湖天淡蕩雁參差，行樂搘筇繞所居。',65,'全唐诗/poet.song.7000.json','["湖天淡蕩雁參差，行樂搘筇繞所居。", "古壁苔荒鳴蟋蟀，水軒風冷謝芙蕖。", "看本來默誦空王偈，拂榻閑開孔聖書。", "閉戶無人慰寥索，草堂深夜照蟾蜍。"]'),
('ed0e69ba-8c86-4199-8920-f8972803cf32','寄題虎丘山','釋智圓','宋','宋诗','song-poetry','','[]','崛起孤峰號虎丘，奇蹤寧與衆山儔。',63,'全唐诗/poet.song.7000.json','["崛起孤峰號虎丘，奇蹤寧與衆山儔。", "月涵秦始劍池冷，蘚駮生公講石幽。", "招隱未居絕頂，臥雲空欲學前修。", "披圖盡日身難到，杳杳煙波茂苑秋。"]'),
('37b7af40-5cff-4da5-8622-f4c5c56993b3','漁父','釋智圓','宋','宋诗','song-poetry','','[]','鶴髪閑梳小棹輕，蘆花深處最怡情。',64,'全唐诗/poet.song.7000.json','["鶴髪閑梳小棹輕，蘆花深處最怡情。", "自憐身外唯煙月，肯信人間有利名。", "閑脫綠蓑春雨霽，醉眠深浦夕陽明。", "陶陶終歲無人識，應笑三閭話獨清。"]'),
('0d83938e-34b8-4d32-b066-a77d86bf364e','水','釋智圓','宋','宋诗','song-poetry','','[]','本性澄明萬古同，滔滔潤物信無窮。',64,'全唐诗/poet.song.7000.json','["本性澄明萬古同，滔滔潤物信無窮。", "百川奔注歸滄海，五服安居賴禹功。", "動带晚風衝島嶼，靜涵秋色混虛空。", "浮舟葬骨成何事，范蠡知機伍相忠。"]'),
('3819b379-2d2a-4d85-9c02-b0b726bfda26','白蓮','釋智圓','宋','宋诗','song-poetry','','[]','栽種空池歲已賒，暑天開處異羣花。',64,'全唐诗/poet.song.7000.json','["栽種空池歲已賒，暑天開處異羣花。", "澄波照影疑秋鷺，靜夜擎香混月華。", "雪態自堪憐翡翠，玉苞終恥近蒹葭。", "閑來倚檻看無厭，爲似禪心本絕瑕。"]'),
('93e0a9f2-9616-4eee-b29f-cee1977502d2','暮秋','釋智圓','宋','宋诗','song-poetry','','[]','嗈嗈賓雁又隨陽，兔走烏飛兩共忙。',64,'全唐诗/poet.song.7000.json','["嗈嗈賓雁又隨陽，兔走烏飛兩共忙。", "露冷小池荷減綠，風高幽砌菊添黄。", "圓明自喜心如月，皓白誰愁鬢似霜。", "閑臥不堪思往事，星河耿耿夜偏長。"]'),
('105c0229-0772-4217-830f-62b1cff1b463','煙疾','釋智圓','宋','宋诗','song-poetry','','[]','深院無人疾漸輕，西風黄葉滿閑庭。',64,'全唐诗/poet.song.7000.json','["深院無人疾漸輕，西風黄葉滿閑庭。", "行披老子五千字，坐讀楞嚴十軸經。", "籬下清香寒有菊，窗間微影夜無螢。", "誰知夜裏珠長在，堪嘆悠悠醉未醒。"]'),
('3f1aa75a-b86e-4ff9-8790-000a88ae74ff','君不來','釋智圓','宋','宋诗','song-poetry','','[]','前年送君空江上，張帆正值西風起。',32,'全唐诗/poet.song.7000.json','["前年送君空江上，張帆正值西風起。", "今日西風君未歸，茫茫只見空江水。"]'),
('8971f989-749e-4614-8de2-0c5e5404ea02','扇','釋智圓','宋','宋诗','song-poetry','','[]','霜縑裁製賴金刀，冷淡還宜畫海濤。',64,'全唐诗/poet.song.7000.json','["霜縑裁製賴金刀，冷淡還宜畫海濤。", "盛夏有功風自遠，涼秋無用架偏高。", "譚筵幾謝驅煩熱，征路長蒙解鬰陶。", "未得袁宏手中握，揚仁何處可施勞。"]'),
('078ffce1-9ef5-4ec7-90fa-b55422621aeb','新栽小松','釋智圓','宋','宋诗','song-poetry','','[]','新種孤松一尺餘，淡煙疏竹便相宜。',64,'全唐诗/poet.song.7000.json','["新種孤松一尺餘，淡煙疏竹便相宜。", "閑來且翫凌霜貌，身後誰觀合抱時。", "冷碧豈容塵染汙，貞心寧共草凋衰。", "夜深庭際清風起，細韻難教俗耳知。"]'),
('a3935ba0-e6dd-4299-b8ff-ede231d17c59','閑詠','釋智圓','宋','宋诗','song-poetry','','[]','造化無餘豈有私，如何庶物自參差。',64,'全唐诗/poet.song.7000.json','["造化無餘豈有私，如何庶物自參差。", "羣烏不涅身長黑，雙鷺無愁頂亦絲。", "巖桂翠濃深雪夜，井桐黄落暮秋時。", "虛空世界都如幻，莫把閑心逐境思。"]'),
('d08d4722-7662-4f90-b7c5-a543b0bc54c0','新栽竹','釋智圓','宋','宋诗','song-poetry','','[]','傍砌疏篁手自栽，數竿蒼翠勝花開。',32,'全唐诗/poet.song.7000.json','["傍砌疏篁手自栽，數竿蒼翠勝花開。", "今宵窗下更深睡，應送寒聲枕上來。"]'),
('75dd5254-3bf7-48f3-ab23-5d9121ac6d18','讀元結文','釋智圓','宋','宋诗','song-poetry','','[]','復古還淳元結文，可憐楊浚獨知君。',32,'全唐诗/poet.song.7000.json','["復古還淳元結文，可憐楊浚獨知君。", "當時自號爲聱叟，立事垂言信不羣。"]'),
('9ffff513-ffce-4cfd-b4d8-366efa2ae3b3','戲題夜合樹','釋智圓','宋','宋诗','song-poetry','','[]','明開暗合似知時，用舍行藏誡在茲。',32,'全唐诗/poet.song.7000.json','["明開暗合似知時，用舍行藏誡在茲。", "綠葉紅葩古牆畔，風光羞殺石楠枝。"]'),
('61105d79-fdf4-4f54-8074-ed1b6372b77d','病中感體元上人見訪','釋智圓','宋','宋诗','song-poetry','','[]','犬吠衡門宿霧消，草堂風冷竹蕭蕭。',32,'全唐诗/poet.song.7000.json','["犬吠衡門宿霧消，草堂風冷竹蕭蕭。", "若非故友憐衰病，誰肯凌晨訪寂寥。"]'),
('9b18741c-1540-4117-ab97-5f80e9ddb493','寄瑞應經疏及注陰符經與體元上人','釋智圓','宋','宋诗','song-poetry','','[]','瑞應陰符盡索看，封題欲寄意盤桓。',32,'全唐诗/poet.song.7000.json','["瑞應陰符盡索看，封題欲寄意盤桓。", "自慚才識非通敏，不得同歸得異端。"]'),
('299294b5-e0d1-4497-ac45-68375bb3417e','病起自嘲','釋智圓','宋','宋诗','song-poetry','','[]','林下羸羸一病軀，四旬欹枕減肌膚。',32,'全唐诗/poet.song.7000.json','["林下羸羸一病軀，四旬欹枕減肌膚。", "閑來試照秋泉看，金鍍形容雪染鬚。"]'),
('ad67f383-77d2-4f19-949d-8af7e38b05b6','戲題四絕句 鶴自矜','釋智圓','宋','宋诗','song-poetry','','[]','紫府青田任性游，一聲清唳萬山秋。',32,'全唐诗/poet.song.7000.json','["紫府青田任性游，一聲清唳萬山秋。", "仙材況有千年壽，鹿犬凡雞豈合儔。"]'),
('09f56225-b525-43c8-af50-212847f24fd9','戲題四絕句 鹿讓鶴','釋智圓','宋','宋诗','song-poetry','','[]','身有素斑文既備，頂峨雙角武仍全。',32,'全唐诗/poet.song.7000.json','["身有素斑文既備，頂峨雙角武仍全。", "我兼文武爲時瑞，汝但白身空有年。"]'),
('2a1ff490-acd3-4f3f-92d8-c60bcd873ccc','戲題四絕句 犬爭功','釋智圓','宋','宋诗','song-poetry','','[]','雪毳文毛虛有表，防姦禦御且無功。',32,'全唐诗/poet.song.7000.json','["雪毳文毛虛有表，防姦禦御且無功。", "中宵誰解頻頻吠，庭皎秋蟾樹褭風。"]'),
('e12b111a-e1bf-4a94-b654-1915eca948fb','戲題四絕句 雞怨言','釋智圓','宋','宋诗','song-poetry','','[]','三箇因何各自強，競誇己德掩他長。',32,'全唐诗/poet.song.7000.json','["三箇因何各自強，競誇己德掩他長。", "冥冥風雨茆堂閉，至竟誰先報曉光。"]'),
('694198b2-4f67-4c72-afad-443a20ab8628','經松江陸龜蒙舊居','釋智圓','宋','宋诗','song-poetry','','[]','甫里舊深隱，夫君道不行。',48,'全唐诗/poet.song.7000.json','["甫里舊深隱，夫君道不行。", "清名身後在，明月夜來生。", "寒水曾垂釣，春田久廢耕。", "空遺散人傳，千古見高情。"]'),
('b393254a-607f-430f-b82e-990321b35832','經照湖方干舊居','釋智圓','宋','宋诗','song-poetry','','[]','磻溪垂釣者，終得展其才。',48,'全唐诗/poet.song.7000.json','["磻溪垂釣者，終得展其才。", "何事先生隱，不逢明主來。", "泉聲秋雨歇，月色夜雲開。", "對此空惆悵，吟魂早晚迴。"]'),
('d52c9578-f0f9-4d49-8e58-d1eccd9abc56','翫月','釋智圓','宋','宋诗','song-poetry','','[]','去秋曾久翫，皓魄墜天涯。',48,'全唐诗/poet.song.7000.json','["去秋曾久翫，皓魄墜天涯。", "始恨經年別，還忻此夜期。", "鳴蛩沈古砌，驚鵲繞寒枝。", "莫厭憑欄久，冰輪覺漸移。"]'),
('92342863-b60a-4865-ae15-eecd31f05083','憶龍山院兼簡蟾上人','釋智圓','宋','宋诗','song-poetry','','[]','幽景遠囂俗，重來興未窮。',48,'全唐诗/poet.song.7000.json','["幽景遠囂俗，重來興未窮。", "鐘聲翠微裏，剎影碧溪中。", "地冷庭松瘦，門閑野徑通。", "幾因深夜話，密雪下寒空。"]'),
('65492746-38df-4cc6-8869-68abedcad682','閑居示友人','釋智圓','宋','宋诗','song-poetry','','[]','冷淡誰知趣，閑房枕水湄。',48,'全唐诗/poet.song.7000.json','["冷淡誰知趣，閑房枕水湄。", "秋窗開暮景，孤枕夢天涯。", "道直時流笑，心清夜月知。", "何當學支遁，共約買山期。"]'),
('85f79302-7bd9-4dd0-99d5-315cc8fcc1d4','孤山閑居次韻酬辯才大師','釋智圓','宋','宋诗','song-poetry','','[]','地僻人稀到，病來無話端。',48,'全唐诗/poet.song.7000.json','["地僻人稀到，病來無話端。", "遠山游未得，終日臥中看。", "藥篋經梅潤，松窗過雨寒。", "唯師知我趣，塵事絕相干。"]'),
('742d825e-0f9d-4a25-8502-bdcd708e262e','山中感友生見訪','釋智圓','宋','宋诗','song-poetry','','[]','講餘多滯疾，林下掩重扉。',48,'全唐诗/poet.song.7000.json','["講餘多滯疾，林下掩重扉。", "度日人稀到，殘陽鳥獨歸。", "山光來有勢，雲影去何依。", "世態那堪說，唯君念息機。"]'),
('90c8448d-f06a-46ee-b54a-bc8de0050958','舟次遊乾元寺','釋智圓','宋','宋诗','song-poetry','','[]','古樹垂清陰，維舟暫登陟。',48,'全唐诗/poet.song.7000.json','["古樹垂清陰，維舟暫登陟。", "閑吟塵想絕，久坐天籟息。", "幡影颺晴空，溪光澄暮色。", "掛帆尋去路，煙水查無極。"]'),
('55ba7aa6-caaf-4bb1-a751-5a33be1fe8ca','風','釋智圓','宋','宋诗','song-poetry','','[]','造化不可測，分明有所依。',48,'全唐诗/poet.song.7000.json','["造化不可測，分明有所依。", "冷和秋葉動，送客暮帆歸。", "掃霧離遙嶽，飄香出靜扉。", "西齋獨吟坐，蕭颯滿禪衣。"]'),
('dc8f772f-d770-4e43-b655-92b7efcba403','雨','釋智圓','宋','宋诗','song-poetry','','[]','潤物有深功，霏霏下半空。',48,'全唐诗/poet.song.7000.json','["潤物有深功，霏霏下半空。", "寒聲清入竹，斜勢急因風。", "苔片添秋碧，花枝損晚紅。", "山人獨欹枕，靜聽草堂中。"]'),
('5b3800af-8183-4e22-bf37-d4feef4b9a15','草','釋智圓','宋','宋诗','song-poetry','','[]','淺碧與深綠，萋萋古岸傍。',48,'全唐诗/poet.song.7000.json','["淺碧與深綠，萋萋古岸傍。", "旅愁生暮色，吟思發清光。", "過雨侵閑徑，披煙上壞牆。", "更堪思往事，金谷舊年荒。"]'),
('2687a157-9681-46db-8701-773f64221e38','寄湛上人','釋智圓','宋','宋诗','song-poetry','','[]','幾年辭輦寺，擁衲住雲林。',48,'全唐诗/poet.song.7000.json','["幾年辭輦寺，擁衲住雲林。", "上國歸心絕，千峰去夢深。", "殘經看雪卷，好句聽秋吟。", "曾有尋高迹，禪房古木陰。"]'),
('f302c151-7789-4107-ba88-5afd716f0c40','秋夕','釋智圓','宋','宋诗','song-poetry','','[]','滄江秋色暮，幽思起窮居。',48,'全唐诗/poet.song.7000.json','["滄江秋色暮，幽思起窮居。", "風葉寒侵夢，窗燈冷照書。", "砌深蟲韻咽，天淡雁行疏。", "終謝人羣去，孤峰待結廬。"]'),
('54a6d7ce-d7b7-49a5-b734-7a993dc01633','題湖上僧房','釋智圓','宋','宋诗','song-poetry','','[]','深隱遠城郭，平湖景色閑。',48,'全唐诗/poet.song.7000.json','["深隱遠城郭，平湖景色閑。", "苦吟終夜月，清夢徹寒山。", "徑冷秋苔合，庭幽嶽鳥還。", "紅塵趨競者，誰得扣松關。"]'),
('8cc7e675-6303-4d54-b9f6-aad351c57c48','送悅上人歸仙巖','釋智圓','宋','宋诗','song-poetry','','[]','道性輕爲別，荒城夕照陰。',48,'全唐诗/poet.song.7000.json','["道性輕爲別，荒城夕照陰。", "波濤歸路遠，雲木舊山深。", "夜定依霜島，中飡狎野禽。", "禪房清景在，飛瀑映疏林。"]'),
('f5657a94-dbcc-4cee-a472-e5908f59ebf1','聽琴','釋智圓','宋','宋诗','song-poetry','','[]','自得南風旨，虛堂此夕彈。',48,'全唐诗/poet.song.7000.json','["自得南風旨，虛堂此夕彈。", "正聲傳不易，俗耳聽終難。", "峭壁蟲音絕，喬枝鶴夢殘。", "坐來消萬慮，斜月上危欄。"]'),
('865d2df2-a138-42d1-85d5-51642aa00a27','寄咸潤上人','釋智圓','宋','宋诗','song-poetry','','[]','流俗不知處，深棲趣轉幽。',48,'全唐诗/poet.song.7000.json','["流俗不知處，深棲趣轉幽。", "閑房扃翠嶽，遠信司滄洲。", "定起花殘砌，詩成雪滿樓。", "相懷未能去，南北路悠悠。"]'),
('307cc0e0-c737-4185-b8b5-c19f9dfe78b6','寄葛溪爽上人','釋智圓','宋','宋诗','song-poetry','','[]','削盡浮華念，閑居道已成。',48,'全唐诗/poet.song.7000.json','["削盡浮華念，閑居道已成。", "夢幽關水石，門冷掩杉檉。", "百衲禪中弊，蒼髭病後生。", "何人問真理，笑指葛溪聲。"]'),
('a2bbcdf1-865f-496e-b010-db74b0ce9b9a','題靜慮院','釋智圓','宋','宋诗','song-poetry','','[]','下瞰諸峰頂，雲泉絕四鄰。',48,'全唐诗/poet.song.7000.json','["下瞰諸峰頂，雲泉絕四鄰。", "暫遊非俗客，深隱屬閑人。", "石磴秋苔滑，蘿龕夜月新。", "終期結幽侶，來此謝紅塵。"]'),
('bd684bbd-eede-4c91-864d-8cd3cbac7649','寄吳黔山人','釋智圓','宋','宋诗','song-poetry','','[]','鳥外自長往，人間過幾年。',48,'全唐诗/poet.song.7000.json','["鳥外自長往，人間過幾年。", "狂吟輕歲月，高趣狎神仙。", "醉臥雲蒸榻，漁歸雪滿船。", "想思未相識，終夜夢林泉。"]'),
('7858f20d-3ebf-4508-bc15-8b67af647315','懷友人','釋智圓','宋','宋诗','song-poetry','','[]','憶向荒原別，殘陽雪霽初。',48,'全唐诗/poet.song.7000.json','["憶向荒原別，殘陽雪霽初。", "幾宵成去夢，經閏絕來書。", "處世慵難減，眠雲癖未除。", "幽懷向誰說，昨夜對蟾蜍。"]'),
('14aebb42-4d96-43eb-b04e-64a44dffa61f','聞蟬','釋智圓','宋','宋诗','song-poetry','','[]','江天涼雨霽，嘒嘒出疏林。',48,'全唐诗/poet.song.7000.json','["江天涼雨霽，嘒嘒出疏林。", "清極殘陽裏，愁生遠客心。", "離亭秋草碧，荒塹暮煙深。", "不忍多時聽，吟髭雪暗侵。"]'),
('4b2d22ef-5050-463c-8828-6ac9b52bb34e','書友人壁','釋智圓','宋','宋诗','song-poetry','','[]','不問人間事，連年鳥外居。',48,'全唐诗/poet.song.7000.json','["不問人間事，連年鳥外居。", "白雲吟次見，青壁醉來書。", "掃石秋苔駮，開窗夜月虛。", "于時已無念，生計有樵漁。"]'),
('710fa21f-e360-42b7-ac56-6c37d3bb1a12','哭辯端上人','釋智圓','宋','宋诗','song-poetry','','[]','平昔於詩苦，精搜省未閑。',48,'全唐诗/poet.song.7000.json','["平昔於詩苦，精搜省未閑。", "壞房空鳥外，清句滿人間。", "瘦影懸鄰壁，孤墳接舊山。", "弔迴高樹下，寒水自潺潺。"]'),
('79c255a7-6a72-44d3-ab45-0775bc8b059c','遊石壁寺','釋智圓','宋','宋诗','song-poetry','','[]','寺幽稱絕境，荷策自登臨。',48,'全唐诗/poet.song.7000.json','["寺幽稱絕境，荷策自登臨。", "翠嶽千峰險，寒松一徑陰。", "清香秋殿冷，疏磬古廊深。", "靜立忘歸興，殘陽鳥忽吟。"]'),
('a409d79f-567a-479a-b95b-0694ab890a34','書林處士壁','釋智圓','宋','宋诗','song-poetry','','[]','高迹遠城市，湖山景色奇。',48,'全唐诗/poet.song.7000.json','["高迹遠城市，湖山景色奇。", "水聲喧睡榻，嵐氣逼書帷。", "鳥語垂軒竹，魚驚浸月池。", "蒲輪來有日，終負白雲期。"]'),
('0178ec90-2737-4347-93cc-7cb68cf60f02','幽居','釋智圓','宋','宋诗','song-poetry','','[]','塵迹不能到，衡門蘚色侵。',48,'全唐诗/poet.song.7000.json','["塵迹不能到，衡門蘚色侵。", "古杉秋韻冷，幽徑月華深。", "窗靜猿窺硯，軒閑鶴聽琴。", "東鄰有真隱，荷策夜相尋。"]'),
('e590f0c2-25be-492b-8124-5a4330d05254','寄湖西逸人','釋智圓','宋','宋诗','song-poetry','','[]','門掩翠層層，閑眠枕曲肱。',48,'全唐诗/poet.song.7000.json','["門掩翠層層，閑眠枕曲肱。", "破籬衝晚浪，古屋漏秋燈。", "月上招鄰叟，詩成寄嶽僧。", "滿朝簪組客，誰識醉騰騰。"]'),
('819918d3-4e31-40ff-a74e-d049932e2a02','贈邦上人','釋智圓','宋','宋诗','song-poetry','','[]','深居饒野興，門冷入杉松。',48,'全唐诗/poet.song.7000.json','["深居饒野興，門冷入杉松。", "鳥外閑頻往，人間事罕逢。", "水軒吟片月，秋榻夢千峰。", "憶得看新雪，相招靜話重。"]'),
('2ff28857-2d3e-4b51-b792-e34cb90615f8','送希中遊霅','釋智圓','宋','宋诗','song-poetry','','[]','日暮蟬鳴急，臨流動別吟。',48,'全唐诗/poet.song.7000.json','["日暮蟬鳴急，臨流動別吟。", "片帆衝晚照，歸鳥入遙林。", "月色寒溪靜，鐘聲嶽寺深。", "蘋洲逢舊識，應得話無心。"]'),
('4c23b470-1a51-4062-b362-752c24e5f724','鷺鷥','釋智圓','宋','宋诗','song-poetry','','[]','煙雨葦森森，飛翔豈易尋。',48,'全唐诗/poet.song.7000.json','["煙雨葦森森，飛翔豈易尋。", "印沙蹤自淺，傍水意還深。", "頂撼絲難斷，翎飄雪未沈。", "終宜鴛作侶，寧肯雜凡禽。"]'),
('c8737f33-3414-4b13-94e4-50ea40a18727','遠山','釋智圓','宋','宋诗','song-poetry','','[]','堆青纔數點，杳杳幾千程。',96,'全唐诗/poet.song.7000.json','["堆青纔數點，杳杳幾千程。", "幽檻葉初落，高空雨乍晴。", "崔嵬微有狀，窈窕莫知名。", "招隱誰長往，眠雲自動情。", "文君眉易似，摩詰畫難成。", "鳥去何曾到，泉流豈覺聲。", "經秋彌冷淡，向晚更分明。", "仁者由來好，閑觀意不輕。"]'),
('63bfd869-9b6d-4560-ac25-46730dd31f11','題方干舊隱','楊翱','宋','宋诗','song-poetry','','[]','雲山旦暮奇，築隱世希續。',48,'全唐诗/poet.song.7000.json','["雲山旦暮奇，築隱世希續。", "脫略浮官心，蟬聯先祖躅。", "門橫嚴子瀨，壁紀桐君籙。", "應笑泛輕舠，日爲官牒束。"]'),
('6ea7271f-34e2-4ffb-88ec-5aa4ce8d5642','遊梅山寺','釋仲休','宋','宋诗','song-poetry','','[]','世續香燈演聖言，再新華構稱憑軒。',64,'全唐诗/poet.song.7000.json','["世續香燈演聖言，再新華構稱憑軒。", "陰陰松色連僧閣，飋飋波聲入寺門。", "飛鷺銜魚離淺瀨，殘雲带雨渡遙邨。", "沃洲相較應相近，樹杪啼煙祇欠猿。"]'),
('103c8269-2b41-4590-b2ce-16c2e06ea285','雲門峰','釋仲休','宋','宋诗','song-poetry','','[]','鶴唳峰前路，行行世慮消。',48,'全唐诗/poet.song.7000.json','["鶴唳峰前路，行行世慮消。", "蘿交藏石竇，雲破露山椒。", "樹老形多怪，人閑色似驕。", "誰同訪諸謝，煙草滿溪橋。"]'),
('ba3b2678-f6cc-46fb-8c1a-9968d8d566f3','句','釋仲休','宋','宋诗','song-poetry','','[]','護塔雲偏重。',6,'全唐诗/poet.song.7000.json','["護塔雲偏重。"]'),
