('c40071ef-22df-4bbf-89df-8a635536a972','送張無夢歸天台','章得象','宋','宋诗','song-poetry','','[]','瓊臺東畔倚岧嶢，縹緲煙霞切絳霄。',64,'全唐诗/poet.song.7000.json','["瓊臺東畔倚岧嶢，縹緲煙霞切絳霄。", "門外杉松盡顛怪，雲中雞犬自逍遙。", "水流玉洞桃花出，風過星壇桂子飄。", "蕙帳已空三徑在，可憐猿鶴共無憀。"]'),
('da5cdfef-f284-42fa-bb01-66e0c1283b8c','送梵才大師歸天台','章得象','宋','宋诗','song-poetry','','[]','京寺棲禪久，霞城去路長。',48,'全唐诗/poet.song.7000.json','["京寺棲禪久，霞城去路長。", "江波收積潦，風信促歸航。", "坐榻新蒲穩，齋盂早稻香。", "遙知掩扉處，森斗萬峰傍。"]'),
('c46ea6dc-b412-49bb-b33a-7106e00967c7','送僧歸護國寺','章得象','宋','宋诗','song-poetry','','[]','京塵拂盡一囊輕，歸思飄然入杳冥。',64,'全唐诗/poet.song.7000.json','["京塵拂盡一囊輕，歸思飄然入杳冥。", "五兩風高飛榜急，八重山秀倚天青。", "供花林鳥窺禪熟，聞呪潭龍起蟄醒。", "他日可容攀社侶，籃輿終待叩松扃。"]'),
('e708329f-9f6e-4c87-b8f0-e179f871235b','題明慶塔院','章得象','宋','宋诗','song-poetry','','[]','步步雲梯徹上層，回頭自覺欲飛騰。',64,'全唐诗/poet.song.7000.json','["步步雲梯徹上層，回頭自覺欲飛騰。", "頻來不是塵中客，久住偏宜物外僧。", "下寺鐘聲沈地底，前峰塔影落階稜。", "憑闌未盡吟詩興，卻擬乘閑更一登。"]'),
('3a1699dd-7dd5-4041-a9aa-dfbd1d1f81ad','題山宮法安院  其一','章得象','宋','宋诗','song-poetry','','[]','路入青青數里松，上方樓閣一重重。',64,'全唐诗/poet.song.7000.json','["路入青青數里松，上方樓閣一重重。", "千尋練掛雙流瀑，六曲屏開四面峰。", "幽鷺獨翹藏翠竹，啼猿相對答疏鐘。", "留連不忍催歸騎，回首斜陽煙霧濃。"]'),
('b3b5bc64-75bf-4767-858e-17067882b245','題山宮法安院  其二','章得象','宋','宋诗','song-poetry','','[]','山家門徑鎖寒松，更向煙蘿第幾重。',64,'全唐诗/poet.song.7000.json','["山家門徑鎖寒松，更向煙蘿第幾重。", "幽鳥啼花歸舊谷，應龍飛雨過前峰。", "分持皂蓋歌千騎，入冠黄扉祿萬鍾。", "一見高吟重興感，清名長在木陰濃。"]'),
('47f09e80-7df5-44a5-aef1-6d3bcb745295','題靈康廟','章得象','宋','宋诗','song-poetry','','[]','白鶴何年入紫氛，空餘靈迹廟猶存。',64,'全唐诗/poet.song.7000.json','["白鶴何年入紫氛，空餘靈迹廟猶存。", "巖崖暗鎖雲根老，堂殿陰連海氣昏。", "潮上神烏鳴祭鼓，夜深鬼火照祠門。", "遼天歸嘆桑田事，應與麻姑子細論。"]'),
('c18dab9f-9287-4061-a287-60597d994d7a','題延慶院','章得象','宋','宋诗','song-poetry','','[]','碧澗連龍穴，層巒倚括蒼。',48,'全唐诗/poet.song.7000.json','["碧澗連龍穴，層巒倚括蒼。", "無時似風雨，繞院盡松篁。", "路僻人難到，僧閑日自長。", "勝游應不負，三度屆雲房。"]'),
('bfa742ae-5585-4ffe-adc8-0cc61fa90f29','題東掖山承山院','章得象','宋','宋诗','song-poetry','','[]','聞說新庵叫白蓮，五峰環繞布金田。',64,'全唐诗/poet.song.7000.json','["聞說新庵叫白蓮，五峰環繞布金田。", "虎溪社共何人繼，佛龕燈從幾代傳。", "嵐色排空長似畫，松枝偃蓋不知年。", "勞生已作歸休計，願解塵纓結凈緣。"]'),
('5908df8a-3eea-4300-b33e-087d1fd172c1','桐柏崇道觀','章得象','宋','宋诗','song-poetry','','[]','萬仞攀蘿上翠岑，豁然平地九峰心。',64,'全唐诗/poet.song.7000.json','["萬仞攀蘿上翠岑，豁然平地九峰心。", "參差珠樹和雲出，咫尺丹霄有路尋。", "洞口碧畦長種玉，壇邊古篆欲生金。", "桑田未變桃先熟，唯見蓬萊水淺深。"]'),
('8a367bd2-3d09-485d-937f-027775ed1c1b','國清寺','章得象','宋','宋诗','song-poetry','','[]','松韻蕭騷十里清，入門毛骨冷如冰。',64,'全唐诗/poet.song.7000.json','["松韻蕭騷十里清，入門毛骨冷如冰。", "題詩已有丹青筆，悟法應多黑白僧。", "風雨祇疑雙澗瀑，星辰長認上方燈。", "來游不是忘機客，誰到雲峰第一層。"]'),
('9366914e-2ac7-494f-8cf2-9b9a1770c095','玉光亭','章得象','宋','宋诗','song-poetry','','[]','千層懷玉對軒窗，池上新亭號玉光。',32,'全唐诗/poet.song.7000.json','["千層懷玉對軒窗，池上新亭號玉光。", "祇此便堪爲吏隱，神仙官職水雲鄉。"]'),
('b6fccf98-c3e6-4fb2-a4e0-a7edb07a8726','植萱亭','章得象','宋','宋诗','song-poetry','','[]','凌江清淺繞城流，庾嶺南邊第一州。',32,'全唐诗/poet.song.7000.json','["凌江清淺繞城流，庾嶺南邊第一州。", "惟有梅花傳遠信，祇憑萱草緩離憂。"]'),
('6ec49b91-1279-4b92-977c-8ca50059705a','媚漣亭','章得象','宋','宋诗','song-poetry','','[]','祇見萬山連瘴海，不知何處是長安。',32,'全唐诗/poet.song.7000.json','["祇見萬山連瘴海，不知何處是長安。", "百蠻梯盡來重譯，千古輪摧恨七盤。"]'),
('6f10582e-3e3c-485e-baab-9b59c5fceb2d','放鉢石','章得象','宋','宋诗','song-poetry','','[]','石上曾經轉鉢盂，石邊南北路崎嶇。',32,'全唐诗/poet.song.7000.json','["石上曾經轉鉢盂，石邊南北路崎嶇。", "行人見石空嗟嘆，還識西來意也無。"]'),
('b4dc3b5f-4927-4259-babd-b22f300debab','峽山飛來寺','章得象','宋','宋诗','song-poetry','','[]','澄江詰曲峽中天，遠使歸時駐畫船。',64,'全唐诗/poet.song.7000.json','["澄江詰曲峽中天，遠使歸時駐畫船。", "久別忽輕星一紀，暫來纔見月三弦。", "勞生草草真徒爾，陳迹依依亦愴然。", "回首越城何處是，山南渺莽祇雲煙。"]'),
('7f4b6ad2-58c8-4efc-a331-627fda1fcdc6','句  其一','章得象','宋','宋诗','song-poetry','','[]','萬頃波心露一拳，不知星落是何年。',16,'全唐诗/poet.song.7000.json','["萬頃波心露一拳，不知星落是何年。"]'),
('e384aa84-c952-4872-94bd-b8287979008d','句  其二','章得象','宋','宋诗','song-poetry','','[]','天面長虹一鑑痕，直通朝北兩山春。',16,'全唐诗/poet.song.7000.json','["天面長虹一鑑痕，直通朝北兩山春。"]'),
('1584a721-132b-4f00-afbf-598efce04633','句  其三','章得象','宋','宋诗','song-poetry','','[]','唯有梅花報春早，雪中傳信過江干。',16,'全唐诗/poet.song.7000.json','["唯有梅花報春早，雪中傳信過江干。"]'),
('3c4d7e7c-960c-423c-b174-d368e0c42ccc','句  其四','章得象','宋','宋诗','song-poetry','','[]','青草瘴深盧橘熟，黄梅雨歇荔枝紅。',16,'全唐诗/poet.song.7000.json','["青草瘴深盧橘熟，黄梅雨歇荔枝紅。"]'),
('14237092-6746-4eb7-803c-e1cbedb6c485','句  其五','章得象','宋','宋诗','song-poetry','','[]','一麾遠在百蠻中。',8,'全唐诗/poet.song.7000.json','["一麾遠在百蠻中。"]'),
('0d8b022f-11e0-460c-a7c9-9c8205eda551','句  其六','章得象','宋','宋诗','song-poetry','','[]','千尋練掛雙流瀑。',8,'全唐诗/poet.song.7000.json','["千尋練掛雙流瀑。"]'),
('1a87e320-8fc1-4891-a757-870dc9c34ead','咏蓮','杜衍','宋','宋诗','song-poetry','','[]','鑿破蒼苔漲作池，芰荷分得綠參差。',32,'全唐诗/poet.song.7000.json','["鑿破蒼苔漲作池，芰荷分得綠參差。", "曉開一朵煙波上，似畫真妃出浴時。"]'),
('3e4a7281-847b-4c4b-8859-505cccf7f13e','雨中荷花','杜衍','宋','宋诗','song-poetry','','[]','翠蓋佳人臨水立，檀粉不勻香汗濕。',32,'全唐诗/poet.song.7000.json','["翠蓋佳人臨水立，檀粉不勻香汗濕。", "一陣風來碧浪翻，珍珠零落難收拾。"]'),
('b070ed46-2a8a-4ffd-97d8-967d7aa16df1','睢陽五老圖','杜衍','宋','宋诗','song-poetry','','[]','五人四百有餘歲，俱稱分曹與掛冠。',64,'全唐诗/poet.song.7000.json','["五人四百有餘歲，俱稱分曹與掛冠。", "天地至仁難補報，林泉幽致許盤桓。", "花朝月夕隨時樂，雪鬢霜髯滿座寒。", "若也睢陽爲故事，何妨列向畫圖看。"]'),
('2c140351-2dfa-4c2c-9f97-14611f0a202f','鄉有好事者出君謨行草八分書數幅中有梅聖俞詩一首用成拙句以識二分','杜衍','宋','宋诗','song-poetry','','[]','莆田筆健與文豪，尤愛南山縣詠高。',64,'全唐诗/poet.song.7000.json','["莆田筆健與文豪，尤愛南山縣詠高。", "欲使英辭長潤石，毎逢佳句即揮毫。", "清如韶濩諧音律，逸似鸞皇振羽毛。", "羲獻有靈應悵望，當時不見此風騷。"]'),
('bf010b3d-8453-48ee-b27d-ce1997480a0e','寶林寺','杜衍','宋','宋诗','song-poetry','','[]','中懷無絆外緣閒，深掩禪扉客到難。',64,'全唐诗/poet.song.7000.json','["中懷無絆外緣閒，深掩禪扉客到難。", "勝景可曾飛錫去，好山多祇捲簾看。", "晝升講座天花落，夜步吟軒海月殘。", "今日逢師堪論道，歸心愁思一時寛。"]'),
('823579e6-2ecd-4682-a0b6-18af58438c7c','新居感詠','杜衍','宋','宋诗','song-poetry','','[]','無似老且病，惟恐歸田遲。',240,'全唐诗/poet.song.7000.json','["無似老且病，惟恐歸田遲。", "一旦得引年，九天還聽卑。", "尚霑二品禄，俾盡百年期。", "恩深淪骨髓，感極横涕洟。", "始營菟裘地，來向濉水湄。", "城隅最窮僻，匠者寧求奇。", "卜築悉由己，軒牖亦隨宜。", "外以蔽風雨，內以安妻兒。", "燕雀莫羣噪，鷦鷯才一枝。", "因念古聖賢，名爲千古垂。", "何嘗廣居室，儉爲後人師。", "亞聖樂簞食，寢丘無立錐。", "文終防勢奪，去病恥家爲。", "文園四壁立，鄭公小殿移。", "伊余具員者，適會承平時。", "無術毗萬務，無才撫四夷。", "爲郡亦齪齪，勞心徒孜孜。", "保身已天幸，拊己宜自知。", "開卷顔間厚，復懼來者嗤。", "朂哉知止足，清白猶可追。"]'),
('72c639d7-b13c-4fa1-abf0-742c7d126ebe','幽居即事','杜衍','宋','宋诗','song-poetry','','[]','寂寂復寂寂，告老閒居日。',48,'全唐诗/poet.song.7000.json','["寂寂復寂寂，告老閒居日。", "徑草高於人，林鳥熟如客。", "黄卷不釋手，清風常滿室。", "內顧平生心，無過此時適。"]'),
('95b6726c-cb16-4d70-978a-b773dec5fa2c','遠蒙運使度支以資政范公所寄黄素小字韓文公伯夷頌許昌文公淮西富公題詩於後才翁復綴雅什兼寄長安晏公公亦有作衍久兹休退人事僅廢不意雅故未遺悉以副本爲貺俾愚繼之對此怔忪既感且愧率成拙句奉呈敢言亦驥之乘聊爲續貂之比耳','杜衍','宋','宋诗','song-poetry','','[]','希文健筆鈔韓文，文爲首陽山下人。',64,'全唐诗/poet.song.7000.json','["希文健筆鈔韓文，文爲首陽山下人。", "寧止一言旌義士，欲教萬古勸忠臣。", "頌聲益與英聲遠，事跡還隨墨跡新。", "當世宗工復題咏，尤宜率土盡書紳。"]'),
('6d0a967e-2a5f-4eda-9a74-aca608131a64','林下書懷','杜衍','宋','宋诗','song-poetry','','[]','從政區區到白頭，一生寧肯顧恩仇。',64,'全唐诗/poet.song.7000.json','["從政區區到白頭，一生寧肯顧恩仇。", "雙鳬乘雁常深愧，野馬黄牛亦過憂。", "豈是林泉堪佚老，只緣蒲柳不禁秋。", "始終幸會承平日，樂聖唯能擊壤謳。"]'),
('0a5c0603-16a6-46f6-86ee-a0e8b449e427','和孫珪秘丞','杜衍','宋','宋诗','song-poetry','','[]','老來楷法不如初，試向閒齋習草書。',64,'全唐诗/poet.song.7000.json','["老來楷法不如初，試向閒齋習草書。", "落筆何曾見飛動，彫章早已過吹嘘。", "伯英比聖功難到，懷素稱狂力有餘。", "若謂伊余堪繼踵，只應緣木可求魚。"]'),
('8efc38cc-b7bf-4959-81f5-3066b088bf6e','聯句','杜衍','宋','宋诗','song-poetry','','[]','古木含清吹，池上增晚涼。',96,'全唐诗/poet.song.7000.json','["古木含清吹，池上增晚涼。", "余懷本達曠，聯此傲羲皇。", "孤鷗可與狎，幽岸足以觴。", "幸有彭澤酒，便同永嘉堂。", "潘生起爲壽，王子齊陳章。", "林端見新月，草際聞寒螿。", "照水螢影亂，拂筵蓼花香。", "徘徊戀嘉境，坐使歸興忘。"]'),
('27aa3e68-7045-49ea-b70e-95384979a3b4','聖俞詩名聞固久矣加有好事者時傳新什至此每一諷誦益使人忻慕故書五十六字以記','杜衍','宋','宋诗','song-poetry','','[]','李杜詩垂不朽名，君能刻意繼芳馨。',64,'全唐诗/poet.song.7000.json','["李杜詩垂不朽名，君能刻意繼芳馨。", "清才綽綽臻神妙，逸韻飄飄入杳冥。", "動與四方明得失，時教萬物被丹青。", "斯文期主宜推轂，無使沉吟向外庭。"]'),
('816e32ad-7a05-4093-9892-bf4d02b944a6','荷花','杜衍','宋','宋诗','song-poetry','','[]','芙蓉照水弄嬌斜，白白紅紅各一家。',32,'全唐诗/poet.song.7000.json','["芙蓉照水弄嬌斜，白白紅紅各一家。", "近日新花出新巧，一枝能著兩般花。"]'),
('e00287f0-4b37-463e-ac7b-e36ddffcd94e','蓮','杜衍','宋','宋诗','song-poetry','','[]','誰種幽花傍淺清，含紅怨綠影亭亭。',64,'全唐诗/poet.song.7000.json','["誰種幽花傍淺清，含紅怨綠影亭亭。", "雲歸巫女粧猶潤，浴出楊妃困未醒。", "好把芳楊臨晚岸，莫教飛片逐浮萍。", "相看最憶吳船路，萬里芙蓉水滿涇。"]'),
('6280a1a5-5f55-4ce2-8329-3c4e9209d6d9','贈應天寺昭凈法華','杜衍','宋','宋诗','song-poetry','','[]','出俗皆言爲息機，性靈凈僻似師稀。',64,'全唐诗/poet.song.7000.json','["出俗皆言爲息機，性靈凈僻似師稀。", "前山月落夜吟罷，深院菊荒秋講歸。", "谿霧鎖窗燈焰短，雪風敲竹磬聲微。", "會期雙闕重相見，應換當年舊衲衣。"]'),
('f01de13d-437a-42d4-942c-2d4b55b21509','送王周歸江陵','杜衍','宋','宋诗','song-poetry','','[]','早修天爵邀人爵，才近耆年便引年。',64,'全唐诗/poet.song.7000.json','["早修天爵邀人爵，才近耆年便引年。", "出處對揚多稱職，始終操履衆推賢。", "鑑湖賀老非陳迹，荆渚朱公合比肩。", "此去優游益吟詠，枝江集外別成編。"]'),
('77e091d2-e75c-4b0b-bf9e-2d643fc0acf8','聚星堂詠雪贈歐公','杜衍','宋','宋诗','song-poetry','','[]','嘗聞作者善評議，詠雪言白匪精思。',144,'全唐诗/poet.song.7000.json','["嘗聞作者善評議，詠雪言白匪精思。", "及窺古人今人詩，未能一一去其類。", "不將柳絮比輕揚，即把梅花作形似。", "或誇瓊樹鬬玲瓏，或取瑤臺造嘉致。", "散鹽舞鶴實有徒，吮墨含毫不能既。", "深悼無人可踐言，一旦見君何卓異。", "萬狀驅從物外來，終篇不涉題中意。", "宜乎衆目詩之豪，便合登壇推作帥。", "回頭且報郢中人，從此陽春不爲貴。"]'),
('e0007be2-9c2e-46dd-8f74-5fca57367268','簾','杜衍','宋','宋诗','song-poetry','','[]','編竹狀玲瓏，庭闈盡處中。',48,'全唐诗/poet.song.7000.json','["編竹狀玲瓏，庭闈盡處中。", "不由經緯力，安有卷舒功。", "春晝曾妨燕，寒宵豈隔風。", "都堂重獻賦，明處憶牢籠。"]'),
('3e9bdce0-c494-4948-a70c-8d8ede639a2f','贈孫沔','杜衍','宋','宋诗','song-poetry','','[]','四明山水饒靈粹，唐有希韓敻出倫。',32,'全唐诗/poet.song.7000.json','["四明山水饒靈粹，唐有希韓敻出倫。", "又見賢侯光乃祖，暫還仁里庇斯民。"]'),
('907c9b95-c28d-4902-aabb-a509708f1b3e','錢光祿兩張卿退居','杜衍','宋','宋诗','song-poetry','','[]','七十引年遵禮經，君家何事最爲榮。',64,'全唐诗/poet.song.7000.json','["七十引年遵禮經，君家何事最爲榮。", "清朝叔姪同辭祿，歸去田園盡列卿。", "遠近溪山資勝賞，往還舟楫稱閑行。", "誰知東路賢哉嘆，二阮方能繼此聲。"]'),
('12a2088c-fe57-42da-a153-545d95899a5b','過仇池','杜衍','宋','宋诗','song-poetry','','[]','仇池行館最清虛，按部由茲得柅車。',32,'全唐诗/poet.song.7000.json','["仇池行館最清虛，按部由茲得柅車。", "對竹祇宜思穴鳳，臨流不可見淵魚。"]'),
('bb164784-8713-4039-9bc0-067efcb90022','題懷素自序卷後','杜衍','宋','宋诗','song-poetry','','[]','狂僧草聖繼張顛，卷後兼題大曆年。',32,'全唐诗/poet.song.7000.json','["狂僧草聖繼張顛，卷後兼題大曆年。", "堪與儒門爲至寶，武功家世久相傳。"]'),
('3d60fd4e-e23a-4875-b49a-772a98740cbe','長平','杜衍','宋','宋诗','song-poetry','','[]','馮亭獻地豹言非，秦間廉頗又不疑。',32,'全唐诗/poet.song.7000.json','["馮亭獻地豹言非，秦間廉頗又不疑。", "四十萬兵降死後，渾輸括母一先知。"]'),
('82ed1b5c-6b10-4daa-8b34-1cf23872799f','霍嶽','杜衍','宋','宋诗','song-poetry','','[]','萬古神山入盛談，而今真得對晴嵐。',32,'全唐诗/poet.song.7000.json','["萬古神山入盛談，而今真得對晴嵐。", "禪門邂逅能留客，茶泛磁甌酒欲酣。"]'),
('1bd208ef-0048-4026-b654-3de694e666e0','句  其一','杜衍','宋','宋诗','song-poetry','','[]','獨無風雅可流傳。',8,'全唐诗/poet.song.7000.json','["獨無風雅可流傳。"]'),
('e9eb5699-b152-4d9d-b253-a586aa1d80a3','句  其二','杜衍','宋','宋诗','song-poetry','','[]','如何九老人猶少，應許東歸伴醉吟。',16,'全唐诗/poet.song.7000.json','["如何九老人猶少，應許東歸伴醉吟。"]'),
('4f205f38-0691-43c5-a99d-94fef70f3961','句  其三','杜衍','宋','宋诗','song-poetry','','[]','辨色爭朝咫尺顔。',8,'全唐诗/poet.song.7000.json','["辨色爭朝咫尺顔。"]'),
('5cd8d253-71da-467b-81fb-ee3a8f810a15','句','李绹','宋','宋诗','song-poetry','','[]','收得桑榆歸物外，種成桃李滿人間。',16,'全唐诗/poet.song.7000.json','["收得桑榆歸物外，種成桃李滿人間。"]'),
('b714da5e-9efc-4121-8325-3e7b3c31fb5a','臨水','黄亢','宋','宋诗','song-poetry','','[]','人生朝復暮，水波流不駐。',48,'全唐诗/poet.song.7000.json','["人生朝復暮，水波流不駐。", "去年昨日水，今日到何處。", "惆悵雨殘花，嫣紅隨水去。", "花落水東流，識盡人生事。"]'),
('879a8119-e6eb-4344-b778-6f24d07e3702','法身頌','端禪師','宋','宋诗','song-poetry','','[]','燈心刺著石人脚，火急去請周醫博。',32,'全唐诗/poet.song.7000.json','["燈心刺著石人脚，火急去請周醫博。", "路逢龐公相借問，六月日頭乾曬卻。"]'),
('e8846662-0c7a-44e9-b0d5-59f9974832b3','偈','釋齊岳','宋','宋诗','song-poetry','','[]','旋收黄葉燒青煙，竹榻和衣斗夜眠。',32,'全唐诗/poet.song.7000.json','["旋收黄葉燒青煙，竹榻和衣斗夜眠。", "粥後放參三下鼓，孰能更話祖師禪。"]'),
('a54a3e27-cd48-42e4-83ad-d04131ac65b4','獻南豐宰','彭齊','宋','宋诗','song-poetry','','[]','昨夜黄斑入縣來，分明蹤跡印蒼苔。',64,'全唐诗/poet.song.7000.json','["昨夜黄斑入縣來，分明蹤跡印蒼苔。", "幾多道德驅難去，些子豬羊引便來。", "令尹聲聲言有過，錄公口口道無災。", "思量也解開東閣，留取頭蹄設秀才。"]'),
('149aa790-3bdf-43f1-8077-1b61576bd5a8','寒食憶江南','彭齊','宋','宋诗','song-poetry','','[]','四度逢寒食，江南身未還。',48,'全唐诗/poet.song.7000.json','["四度逢寒食，江南身未還。", "二親青草冢，三月子規山。", "榆柳藏新火，松楸病故關。", "東風兩行淚，原上夕陽間。"]'),
('85ae3a23-a217-45ad-b9ce-97e6c13a2ce0','酒旗','彭齊','宋','宋诗','song-poetry','','[]','太平天子束戈矛，惟許青旗在酒樓。',32,'全唐诗/poet.song.7000.json','["太平天子束戈矛，惟許青旗在酒樓。", "我有百瓢元帥量，使君酣戰客中愁。"]'),
('4f2a6af3-e7e2-475f-ad9d-ea74383ed48a','句','陳詁','宋','宋诗','song-poetry','','[]','籠雞對窗語，鬬雀繞門飛。',12,'全唐诗/poet.song.7000.json','["籠雞對窗語，鬬雀繞門飛。"]'),
('765d469d-bf80-487a-bb3f-19ccf5110053','寒窗聽雪','陳宗道','宋','宋诗','song-poetry','','[]','水浸樓臺月，山圍花柳春。',48,'全唐诗/poet.song.7000.json','["水浸樓臺月，山圍花柳春。", "宸居一望近，風景四時新。", "畫舫斷橋聚，清簫夾岸聞。", "遊人歸去晚，車馬鬧紅塵。"]'),
('1848e52d-38dd-4ea5-8346-551feeab3e36','慧日寺','陳清','宋','宋诗','song-poetry','','[]','秋入西山爽氣生，煩襟滌盡漸神清。',32,'全唐诗/poet.song.7000.json','["秋入西山爽氣生，煩襟滌盡漸神清。", "塵埃不到窗扉靜，坐聽幽林一鳥鳴。"]'),
('d698ce93-1c61-4821-b0ba-ef1c8a27cf3a','浯溪','周世南','宋','宋诗','song-poetry','','[]','壁立石青蒼，鄰溪復枕江。',48,'全唐诗/poet.song.7000.json','["壁立石青蒼，鄰溪復枕江。", "刊銘傳不朽，文筆老無雙。", "怪樹森圓幄，□□寄□幢。", "奇蹤□異景，□□□□□。"]'),
('f2d2adef-27bf-4d52-98d3-42424f8369ad','詩一首','趙德□','宋','宋诗','song-poetry','','[]','鑱崖刻石成大像，誰道老僧多伎倆。',32,'全唐诗/poet.song.7000.json','["鑱崖刻石成大像，誰道老僧多伎倆。", "雖云百尺最高高，應有遊人到頭上。"]'),
('a406c1e4-dfed-45ca-87a7-0e6c1670dd99','江南寒食','穆脩','宋','宋诗','song-poetry','','[]','江南水國春光饒，清明上巳多招邀。',64,'全唐诗/poet.song.7000.json','["江南水國春光饒，清明上巳多招邀。", "花陰連絡青草岸，柳色掩映紅欄橋。", "歌調謳啞雜吳俗，髻鬟疏削傳南朝。", "誰憐北客歸未去，楚魄湘魂惟暗消。"]'),
('505866ca-2024-4a7f-ad3d-e650905a7d68','送毛得一秀才歸淮上  其一','穆脩','宋','宋诗','song-poetry','','[]','江天梅雨晝蕭蕭，送别愁吟白紵謠。',64,'全唐诗/poet.song.7000.json','["江天梅雨晝蕭蕭，送别愁吟白紵謠。", "處士才高融未薦，騷人魂斷玉方招。", "自傷櫪驥心千里，空羨冥鵬志九霄。", "酒罷征鞍迢遞去，不堪回首木蘭橈。"]'),
('0026f711-09a4-43e8-b8ea-9bb08fde4200','送毛得一秀才歸淮上  其二','穆脩','宋','宋诗','song-poetry','','[]','君歸迢遞淮西路，我客蕭條秋浦城。',64,'全唐诗/poet.song.7000.json','["君歸迢遞淮西路，我客蕭條秋浦城。", "惻惻相看復惻惻，行行送别重行行。", "途中猿鳥哀聲斷，馬上雲山遠碧橫。", "富貴窮通俱未決，直傾樽酒沃離情。"]'),
('70fcbd79-bcc4-4343-91f6-8a77f4da89a8','食魚','穆脩','宋','宋诗','song-poetry','','[]','南有嘉魚異，常趨四月期。',195,'全唐诗/poet.song.7000.json','["南有嘉魚異，常趨四月期。", "江天專伺至，烟網密爭垂。", "乍戲汀蘋末，初循水荇湄。", "競搖輕舴艋，寛罩碧漣漪。", "占浦搜深藻，空波出素髭。", "數頭餘赤質，二色類銀姿。", "貨鬻斯爲切，鮮腴敢暇知。", "青錢邀價值，華屋市新奇。", "珠沫緣條煦，霜鱗逐刃墮。", "扣顱瓊聚骨，剖腋錦分肌。", "味佐芳菘愜，香參苦筍宜。", "羮甌融膩玉，膾筯罥寒絲。", "湘鱓非吾偶，河魴孰與夷。", "薦新奚尚鮪，稔毒即殊{魚幾}。", "鱸訝休官易，鯖嫌醒酒遲。", "自當頻佐膳，所惜易過時。"]'),
('4212b24d-5a1a-45f8-9c6b-eb373650e677','魯從事清暉閣','穆脩','宋','宋诗','song-poetry','','[]','庾郎真好事，溪閣斬新開。',48,'全唐诗/poet.song.7000.json','["庾郎真好事，溪閣斬新開。", "水石精神出，江山氣色來。", "疏烟分鷺立，遠靄見帆迴。", "公退資清興，閒吟倚檻裁。"]'),
('831f3eb7-b8c0-438a-b31f-d8704f4f46ff','送葛源之太和主簿','穆脩','宋','宋诗','song-poetry','','[]','勿嘆從卑位，聊欣適去情。',48,'全唐诗/poet.song.7000.json','["勿嘆從卑位，聊欣適去情。", "秋風九月急，飛鳥一帆輕。", "鱠斫江鱗活，杯嘗楚釀清。", "歡華莫回首，寵辱正堪驚。"]'),
('81bfa84d-eace-4436-9685-13791e116756','送靈師歸吳','穆脩','宋','宋诗','song-poetry','','[]','靈師殊可尚，頗不類浮屠。',48,'全唐诗/poet.song.7000.json','["靈師殊可尚，頗不類浮屠。", "託迹雖依佛，留心獨喜儒。", "風塵倦京洛，水石隱句吳。", "破寺杉松老，南歸舊隱孤。"]'),
('04832df3-74b5-493b-ad82-69438413852e','江南春','穆脩','宋','宋诗','song-poetry','','[]','杜若谿邊待釣船，怨紅傷翠助鸝鵑。',64,'全唐诗/poet.song.7000.json','["杜若谿邊待釣船，怨紅傷翠助鸝鵑。", "戰回春事青蒲劍，買破韶光綠荇錢。", "千嶂遠圍芳草國，一江晴浸斷霞天。", "未知多感多愁客，何處偷尋甕底眠。"]'),
('5fbfd7dd-30d1-4a5b-9d9e-c7085e6c0bb9','寒食','穆脩','宋','宋诗','song-poetry','','[]','江邊又寒食，傖客奈離襟。',48,'全唐诗/poet.song.7000.json','["江邊又寒食，傖客奈離襟。", "恨滿王孫草，愁多望帝禽。", "鷄毬輕薄事，歌酒宴遊心。", "盡付吳兒輩，惟知屏跡深。"]'),
('0ad07028-f779-4754-919e-6e6cb6016b4b','江上送陳翹還無爲','穆脩','宋','宋诗','song-poetry','','[]','江上寂寥春雨晴，江邊冉冉春潮平。',64,'全唐诗/poet.song.7000.json','["江上寂寥春雨晴，江邊冉冉春潮平。", "相逢未盡斗酒醉，相送又速孤舟行。", "篁竹窮鎖秋浦郡，烟波渺隔無爲城。", "音塵兩地不千里，勿使負君金玉聲。"]'),
('52ca22d9-7f21-4925-a1bc-07420262f3e3','殘春病酲','穆脩','宋','宋诗','song-poetry','','[]','風簷窣窣燕哰哰，卧對殘芳起鬱陶。',64,'全唐诗/poet.song.7000.json','["風簷窣窣燕哰哰，卧對殘芳起鬱陶。", "乍困遊車春尚在，未扶醒枕日初高。", "煩腸屢沃痟難解，病髪慵簪癢更搔。", "欲爲風光輕賦别，正無憀賴染江毫。"]'),
('d93ff681-9799-4c7c-ab5d-e4cba8c1ce48','書事覺菴','穆脩','宋','宋诗','song-poetry','','[]','惠澤涵濡四海同，微生曾莫預昆蟲。',64,'全唐诗/poet.song.7000.json','["惠澤涵濡四海同，微生曾莫預昆蟲。", "不參品物陶鎔外，獨作窮人蓋載中。", "深穽已顛猶磷石，危苕將籜更推風。", "一家寄命嗟無地，何負明神與上穹。"]'),
('0e67c7aa-09ef-4171-be57-2755da369052','和毛秀才江墅幽居好十首  其一','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，當門看水田。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，當門看水田。", "鳧鷗閒夕照，秔稻秀原烟。", "野屐無完齒，山衣有敗肩。", "遙聞雙闕下，簫鼓樂豐年。"]'),
('dce86d98-410d-425b-a5b7-f738867d9805','和毛秀才江墅幽居好十首  其二','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，南塘枕野亭。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，南塘枕野亭。", "菰蒲顫風綠，菱荇蓋波青。", "繫葦一漁艇，翹烟雙雪翎。", "相攜二三叟，扶醉不曾醒。"]'),
('61364b36-1ce5-4868-a54b-aa5b923bc64e','和毛秀才江墅幽居好十首  其三','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，谿山數里長。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，谿山數里長。", "徑通茶塢綠，門枕橘園香。", "藉石還勝榻，聽松不讓簧。", "閒遊驚里巷，自作隱淪裝。"]'),
('4a0215b7-1988-43f9-a9a8-8cdfb04e47be','和毛秀才江墅幽居好十首  其四','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，老農時款扉。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，老農時款扉。", "濁醪時共醉，野話坦無機。", "山雨欲到檻，竹風先滿衣。", "谿南秋更樂，稻熟又魚肥。"]'),
('87d0134b-fad8-4891-a93e-f635757392ac','和毛秀才江墅幽居好十首  其五','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，賓來定不愁。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，賓來定不愁。", "酒醲新出榨，魚活旋離鈎。", "移席追松影，調琴和澗流。", "陶然方外樂，名教縶何由。"]'),
('8e53559f-c7cf-4281-8e04-9f5bc00d642a','和毛秀才江墅幽居好十首  其六','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，柴關带竹籬。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，柴關带竹籬。", "田頭餉耕後，樹裏灌園時。", "鄰靜鳴秋織，樵閒對野棋。", "扺巇非我事，大笑引蘇錐。"]'),
('340ee37d-1a77-440c-926f-9c438991bbe3','和毛秀才江墅幽居好十首  其七','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，名山對九華。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，名山對九華。", "疏篁十餘畝，古屋兩三家。", "碓下雞争黍，籬根虺逐蛙。", "水邊閒送目，獨鳥在秋槎。"]'),
('761132f7-c2d8-47f7-86ec-8335a4c7d89a','和毛秀才江墅幽居好十首  其八','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，何妨鄙事添。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，何妨鄙事添。", "神隨山父賽，筮學野人占。", "露草牛羊喜，秋霖黍豆嫌。", "短牆衰柳下，寒水半渠淹。"]'),
('5e1091ef-774e-4fa9-a8cc-fbfc95fb3294','和毛秀才江墅幽居好十首  其九','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，身如醉伯倫。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，身如醉伯倫。", "浮名抛可得，荒宴罷何因。", "酩酊乘籃輿，逍遙岸角巾。", "人間莫回首，容僞不容真。"]'),
('deae8acc-092f-43d2-a43f-927a56aea5fa','和毛秀才江墅幽居好十首  其一○','穆脩','宋','宋诗','song-poetry','','[]','江墅幽居好，人閒晚最孤。',48,'全唐诗/poet.song.7000.json','["江墅幽居好，人閒晚最孤。", "魚臨谿樹釣，鳥隔水烟呼。", "野竹掛薜荔，山花睡鷓鴣。", "畫工能狀出，羞殺輞川圖。"]'),
('35e178ab-dd62-40d9-8133-c7dea9017994','燭','穆脩','宋','宋诗','song-poetry','','[]','一箔珠簾掩映垂，房櫳清染麝香枝。',64,'全唐诗/poet.song.7000.json','["一箔珠簾掩映垂，房櫳清染麝香枝。", "佳人盼影横哀柱，狎客分光綴艷詩。", "禁鎖翠明初唱漏，宫窗紅短尚圍棋。", "長宵且秉歡遊去，無限風情見古辭。"]'),
('d33362dc-e279-44aa-98cc-7843a215108a','過西京','穆脩','宋','宋诗','song-poetry','','[]','西京千古帝王宫，無限名園水竹中。',32,'全唐诗/poet.song.7000.json','["西京千古帝王宫，無限名園水竹中。", "來恨不逢桃李日，滿城紅樹正秋風。"]'),
('6255a41e-9e0e-4cd2-b3a5-51dc29571a23','賦催粧','穆脩','宋','宋诗','song-poetry','','[]','嚴粧應在繡閨中，似鬭春芳拆曉風。',32,'全唐诗/poet.song.7000.json','["嚴粧應在繡閨中，似鬭春芳拆曉風。", "試問夭桃臨碧沼，何如艷質對青銅。"]'),
('3ee8605a-e38f-4298-831f-87c4d66a3237','送孫立東遊','穆脩','宋','宋诗','song-poetry','','[]','詩筆知名曾苦刻，文章多難久飄流。',32,'全唐诗/poet.song.7000.json','["詩筆知名曾苦刻，文章多難久飄流。", "睢陽縱酒黄金盡，提劍東方暫一遊。"]'),
('cf5894eb-c234-494f-b428-64a9b9b0d182','村郭寒食雨中作','穆脩','宋','宋诗','song-poetry','','[]','寂寥村郭見寒食，風光更着微雨遮。',64,'全唐诗/poet.song.7000.json','["寂寥村郭見寒食，風光更着微雨遮。", "鞦韆閑垂愁稚子，楊柳半濕眠春鴉。", "白社皆驚放狂客，青錢盡送沽酒家。", "眼前不得醉消遣，爭奈惱人紅杏花。"]'),
('e50b35bd-7958-497b-ab3b-bde21dfc1a22','清明連上巳','穆脩','宋','宋诗','song-poetry','','[]','改火清明度，湔衫上巳連。',48,'全唐诗/poet.song.7000.json','["改火清明度，湔衫上巳連。", "芳辰來屬續，遊事困聯翩。", "酒帳經旬直，花司併日權。", "俠兒狂不足，猶恨促春妍。"]'),
('7964a7df-8f96-4250-b5ee-9f0716a6eceb','合歡芍藥','穆脩','宋','宋诗','song-poetry','','[]','薰風對拆香心破，浩露雙滋粉面新。',64,'全唐诗/poet.song.7000.json','["薰風對拆香心破，浩露雙滋粉面新。", "油碧車中同載女，菱花鑑裏並粧人。", "皇英帝子鍾遺艷，琬琰宫姬託後身。", "誰道獨呈芳瑞晚，也勝常調牡丹春。"]'),
('91f7aa66-1403-470e-8efe-08aa5cb6bafc','故侯園','穆脩','宋','宋诗','song-poetry','','[]','池館早來瓦礫存，路傍看取故侯園。',32,'全唐诗/poet.song.7000.json','["池館早來瓦礫存，路傍看取故侯園。", "身前便作荒凉計，祗樹芳菲不樹恩。"]'),
('183167cb-11da-4f8b-af67-0829e37fd6f0','送定師南遊','穆脩','宋','宋诗','song-poetry','','[]','營營學佛徒，皆喜訾吾道。',96,'全唐诗/poet.song.7000.json','["營營學佛徒，皆喜訾吾道。", "憐師獨異羣，儒藝知探討。", "誦詩三四章，往往見詞藻。", "玉璞在琢磨，不難成至寶。", "知予本好古，身服仁義老。", "勤請送行詩，安足慰枯槁。", "别時汝潁路，凉葉經秋早。", "南遊何當還，江潭無限好。"]'),
('0f06c4ad-f4fe-4193-a3c3-803d8aeac472','送人至邊寨','穆脩','宋','宋诗','song-poetry','','[]','豈憚河湟遠，男兒效主恩。',48,'全唐诗/poet.song.7000.json','["豈憚河湟遠，男兒效主恩。", "窮邊人不到，孤戍自分屯。", "馬放胡沙暖，烽傳塞日昏。", "軍前初謁帥，戎服走轅門。"]'),
('49bab338-8147-420b-9585-77b1fa05c745','巨盜','穆脩','宋','宋诗','song-poetry','','[]','嗣皇登位始凝旒，巨盜尋并相印收。',64,'全唐诗/poet.song.7000.json','["嗣皇登位始凝旒，巨盜尋并相印收。", "漢室有靈誅賊冀，舜廷無患放凶兜。", "猨狙豈稱周公任，豺虎猶寛巷伯投。", "願斬都衡謝天下，不然何用正王猷。"]'),
('7a299500-e98e-4eac-a6d7-be7083d9108a','汝陰偶書呈一二知己','穆脩','宋','宋诗','song-poetry','','[]','汝陰窮掾計何疏，四十無成坐諷書。',64,'全唐诗/poet.song.7000.json','["汝陰窮掾計何疏，四十無成坐諷書。", "不務功名師捭闔，獨將仁義守蘧廬。", "敢同賈傅希前席，况異鄒生託後車。", "除泥諸公時一醉，等閒猶且忘歸歟。"]'),
('cddda2ed-dc26-427f-8aea-49b4144f2430','除夜','穆脩','宋','宋诗','song-poetry','','[]','燈前清淚落衣間，守歲分爲客是閒。',32,'全唐诗/poet.song.7000.json','["燈前清淚落衣間，守歲分爲客是閒。", "老母今春年七十，壽觴争忍對慈顔。"]'),
('1b59f283-6cef-4438-911c-8065b458da81','城南五題 郊步','穆脩','宋','宋诗','song-poetry','','[]','野水岸邊逢草歇，平林烟畔逐花行。',32,'全唐诗/poet.song.7000.json','["野水岸邊逢草歇，平林烟畔逐花行。", "雨晴南陌塵埃洗，倍覺風光奪眼明。"]'),
('ecfef6b5-8a32-4fa2-a6c3-6476b68df173','城南五題 獨游','穆脩','宋','宋诗','song-poetry','','[]','水曲臨幽獨杖藜，郫筒香入亂花攜。',32,'全唐诗/poet.song.7000.json','["水曲臨幽獨杖藜，郫筒香入亂花攜。", "輕肥不得尋春意，動要笙歌逐馬蹄。"]'),
('c8b04df4-a29f-4d10-9687-5cd553379e89','城南五題 貴侯園','穆脩','宋','宋诗','song-poetry','','[]','名園雖是屬侯家，任客閒遊到日斜。',32,'全唐诗/poet.song.7000.json','["名園雖是屬侯家，任客閒遊到日斜。", "富貴位高無暇出，生人空看折來花。"]'),
('11c25bb3-9cbd-4636-9380-bc9780a2b682','城南五題 朱亥墓','穆脩','宋','宋诗','song-poetry','','[]','閒登朱亥遊俠墓，却望梁王歌吹臺。',32,'全唐诗/poet.song.7000.json','["閒登朱亥遊俠墓，却望梁王歌吹臺。", "臺上墓邊芳草綠，遊人心事立徘徊。"]'),
('089b644c-c6c8-417d-be98-5e1d2db72828','城南五題 玉津園','穆脩','宋','宋诗','song-poetry','','[]','君王未到玉津遊，萬樹紅芳相倚愁。',32,'全唐诗/poet.song.7000.json','["君王未到玉津遊，萬樹紅芳相倚愁。", "金鎖不開春寂寂，落花飛出粉牆頭。"]'),
('80ef182b-e526-4d47-aceb-9fceb51ba468','燈','穆脩','宋','宋诗','song-poetry','','[]','杳杳有時當永恨，依依何處照閒眠。',64,'全唐诗/poet.song.7000.json','["杳杳有時當永恨，依依何處照閒眠。", "靜臨客枕愁寒雨，遠逐魚篷秋暝烟。", "纖影乍欹還復立，冷花時結不成圓。", "銷魂猶憶江樓夜，曾對離觴賦短篇。"]'),
('0999a86f-55c6-4d95-ae16-96aa1ff572d2','登莒子臺','穆脩','宋','宋诗','song-poetry','','[]','莒國丘壟在，莒臺荆棘深。',48,'全唐诗/poet.song.7000.json','["莒國丘壟在，莒臺荆棘深。", "憑高一極目，懷古重傷心。", "平楚蒼烟暝，遇風白日沈。", "誰論客懷抱，灌木自悲吟。"]'),
('a34c4eee-7da7-4821-9233-d87e9abd8903','希言官舍種花','穆脩','宋','宋诗','song-poetry','','[]','纔初看君栽小園，已報新花着桃李。',160,'全唐诗/poet.song.7000.json','["纔初看君栽小園，已報新花着桃李。", "感時睠物情何多，發咏長篇託興比。", "爲言桃李富花實，君子盛德尤所似。", "蒨蒨相倚臨芳辰，輔導春功如宰揆。", "旁有百卉爭妍舒，特煩花匠施劂剞。", "誇紅鬭紫亦可憐，各事繁華一時爾。", "繁盛寧將此花同，令人慕翫狂不已。", "羲和奔御催春歸，祗得銜杯且歡喜。", "君看灼灼枝上英，半雜泥塵成落蕊。", "盛衰不獨草木然，人事悠悠盡如此。"]'),
('d295e2b9-080f-4053-8fcb-d835ff233913','登女郎臺  其一','穆脩','宋','宋诗','song-poetry','','[]','臺前流水眼波明，臺上閒雲鬢葉輕。',32,'全唐诗/poet.song.7000.json','["臺前流水眼波明，臺上閒雲鬢葉輕。", "莫把姑蘇遠相比，不曾亡國只傾城。"]'),
('4c75ea33-9e6f-4b60-9c80-88968c38f755','登女郎臺  其二','穆脩','宋','宋诗','song-poetry','','[]','女郎名字本風流，好與州人作勝遊。',32,'全唐诗/poet.song.7000.json','["女郎名字本風流，好與州人作勝遊。", "倘使此臺呼醜女，汝陰城裏一荒丘。"]'),
('92d2cb0d-218f-4aee-885c-de50daf1f1c7','友人燒筍之約未赴','穆脩','宋','宋诗','song-poetry','','[]','久約燒林筍，何時會勝園。',48,'全唐诗/poet.song.7000.json','["久約燒林筍，何時會勝園。", "未嘗清氣味，每厭俗盤飱。", "漸痛烟犀老，方憐露錦繁。", "如何玉川子，苦惜籜龍冤。"]'),
('7eff325b-3002-44c9-ab37-0180e0648b3c','别穀熟尉李七同年','穆脩','宋','宋诗','song-poetry','','[]','騎驢登縣門，屑屑復何言。',48,'全唐诗/poet.song.7000.json','["騎驢登縣門，屑屑復何言。", "留館竺乾舍，屢攜梅福尊。", "凶荒岐路梗，冰雪歲時昏。", "明日别君去，依然蓬跡奔。"]'),
('a75cc0bd-5584-4e55-b55d-fd8acd9e6642','樊博士化州監鹽','穆脩','宋','宋诗','song-poetry','','[]','監鹺已非職，况復極南之。',48,'全唐诗/poet.song.7000.json','["監鹺已非職，况復極南之。", "莫識州名化，徒聞水涉灕。", "樹驚人面果，俗駭鳥言夷。", "去去唯強飯，歲還歲可期。"]'),
('46a8d212-68fe-401b-9742-cd2ed0719ff9','丙寅春雨','穆脩','宋','宋诗','song-poetry','','[]','天地開春暉，羣陰争閉之。',240,'全唐诗/poet.song.7000.json','["天地開春暉，羣陰争閉之。", "行行二月路，寒威切人肌。", "淫雨恣凌虐，淹旬下無時。", "頑雲掃復合，直向平地垂。", "蒸人共愁嘆，萬物皆瘡痍。", "衆木有芳華，摧沮不得施。", "青苞斂絳萼，同向枝上萎。", "民麥悲已病，泥中聊參差。", "嘉穀失播種，雖晴諒胡爲。", "蠢彼田中氓，豈惟念身饑。", "州縣責常賦，嗷嗷訴之誰。", "幸不爲盜起，多應盡流離。", "吁嗟致此異，其咎安所尸。", "悒悒窮巷士，屏身伏茅茨。", "讀書抗前古，得失心頗窺。", "天理不難究，可以人事知。", "且欲上其說，懼非己所宜。", "有職彼尚默，未當僭汝卑。", "勉汝無妄言，言出禍汝隨。", "誰識此懷抱，獨自空嗟嘻。"]'),
('03e27f0f-c226-451b-9f40-cfc56b746c09','贈適公上人','穆脩','宋','宋诗','song-poetry','','[]','喜得師消耗，從僧問不休。',120,'全唐诗/poet.song.7000.json','["喜得師消耗，從僧問不休。", "苦吟成白髪，多病寄滄洲。", "道氣閒尤勝，書鋒晚更遒。", "相思二千里，阻别十三秋。", "六合勞生耳，休追萬事不。", "雲蘿荒舊隱，知友落新丘。", "想嘆歐生逝，應聞李氏憂。", "尋思祗如此，必竟欲何求。", "未即無言問，方期勿藥瘳。", "終爲嵩少約，築室共夷猶。"]'),
('e0b7fe3b-6701-4f40-8099-2e925b34229e','一百五日同周越陳永錫遊吉祥僧舍','穆脩','宋','宋诗','song-poetry','','[]','痛飲方期數百杯，尋芳何事又空回。',32,'全唐诗/poet.song.7000.json','["痛飲方期數百杯，尋芳何事又空回。", "花愁酒困春無著，却訝野僧蕭寺來。"]'),
('97c81936-5a97-462a-80a7-7e1d4006e505','題李士言秀才别貯帕','穆脩','宋','宋诗','song-poetry','','[]','蘭薫麝浥輕綃帕，略許攜持又索還。',32,'全唐诗/poet.song.7000.json','["蘭薫麝浥輕綃帕，略許攜持又索還。", "題破白雲深有意，要傳消息到巫山。"]'),
('c99a5a30-4f84-4315-9022-0d10798077d1','南陌','穆脩','宋','宋诗','song-poetry','','[]','南陌一雨後，東風三月天。',48,'全唐诗/poet.song.7000.json','["南陌一雨後，東風三月天。", "殘花亂芳草，輕絮散春烟。", "景色真愁絕，歡悰重棄捐。", "倀倀有餘恨，醽醁詎能蠲。"]'),
('8242ec0f-e5f1-412d-ba49-8e8cf2435a35','雨中牡丹','穆脩','宋','宋诗','song-poetry','','[]','萬金期勝賞，三月破穠芳。',48,'全唐诗/poet.song.7000.json','["萬金期勝賞，三月破穠芳。", "妬忌巫娥雨，摧殘洛苑香。", "怨啼甄后玉，寒出貴妃湯。", "掩斂無聊極，誰來替斷腸。"]'),
('2e2035b8-e6a5-4c94-a5ce-b11617b2915b','思邊','穆脩','宋','宋诗','song-poetry','','[]','去年何時君别妾，南園綠草飛蝴蝶。',48,'全唐诗/poet.song.7000.json','["去年何時君别妾，南園綠草飛蝴蝶。", "今歲何時妾憶君，西山白雪暗秦雲。", "玉關此去三千里，欲寄音書那可聞。"]'),
('62615ee0-93f1-4af3-b849-d96acbb3175f','聞報自崖徙雷成一章','穆脩','宋','宋诗','song-poetry','','[]','從來崖貶斷還期，聞徙警雷衆共疑。',32,'全唐诗/poet.song.7000.json','["從來崖貶斷還期，聞徙警雷衆共疑。", "却訝有虞刑政錯，四兇何事不量移。"]'),
('d96918e8-2c74-4e0f-b15f-02aa14c857a4','秋浦會遇','穆脩','宋','宋诗','song-poetry','','[]','齪齪幽遐地，栖栖會遇人。',288,'全唐诗/poet.song.7000.json','["齪齪幽遐地，栖栖會遇人。", "窮愁艱理勝，羈旅易情親。", "豈意當漂謫，兹諧卜並鄰。", "温温窺表粹，晏晏奉嬉嚬。", "直道談端闢，橫流語下堙。", "綺文何斐疊，瑰行亦璘玢。", "敦分初投漆，交言乍飲醇。", "操心忠義合，開口肺肝陳。", "共昧隨時理，俱成迷患因。", "禍來非造次，語及自酸辛。", "衆奮漂山舌，孤縻坐獄身。", "詆誣惟腷臆，鍛鍊正逡巡。", "囚任桐棺躍，冤寧斗劍伸。", "君牽成狠翟，我患構奸秦。", "巧縱銛刀筆，幽争誷鬼神。", "精誠懷皎日，悲憤貫高旻。", "素誓端清檢，期無取玷淪。", "斬芻嘗鼓篋，卧藁先書紳。", "側璧疑曾辨，鈎金法所循。", "得情奚示喜，伏念不忘旬。", "粗評三章直，何辭一馬貧。", "決曹誠自任，司舉仰誰論。", "膺破藏奸柱，綱埋翦暴輪。", "存心固慨慕，有位敢希遵。"]'),
('0173ebba-d75d-4158-9ab2-b2c22b2a3591','夜讌','錢惟濟','宋','宋诗','song-poetry','','[]','清讌夜何其，南亭露欲晞。',48,'全唐诗/poet.song.7000.json','["清讌夜何其，南亭露欲晞。", "蹁躚霞袖舞，瀲灧羽觴飛。", "鏤楶搖花落，金璫照月輝。", "瑤光未西落，休賦醉言歸。"]'),
('3322aea6-013a-4559-8052-9cb10dd69e03','苦熱','錢惟濟','宋','宋诗','song-poetry','','[]','蘋末風休飛閣深，亭亭日御漸流金。',64,'全唐诗/poet.song.7000.json','["蘋末風休飛閣深，亭亭日御漸流金。", "火雲接影橫銀漢，水鳥無聲下翠陰。", "渴想孤山同飲露，煩思楚殿獨披襟。", "柘漿粔籹都無味，衛玠清羸欲不任。"]'),
('03fc018d-4c8f-4cc7-8797-39b0d97014ed','護國寺','錢惟濟','宋','宋诗','song-poetry','','[]','穹窿臺嶽壓重溟，中起青鴛接福庭。',64,'全唐诗/poet.song.7000.json','["穹窿臺嶽壓重溟，中起青鴛接福庭。", "新好天花對雨墜，清涼甘露隔宵零。", "金繩界道連飛布，碧樹周阿繞翠屏。", "異日功成解纓去，佇期同擷五芝馨。"]'),
('dac73fb8-f103-4028-89e2-b08c7d280d5d','送從進長老歸天台','錢惟濟','宋','宋诗','song-poetry','','[]','樞府多年識相毫，又飛鐶錫出神臯。',64,'全唐诗/poet.song.7000.json','["樞府多年識相毫，又飛鐶錫出神臯。", "霞標起處瞻鴛剎，風信平時過鷺濤。", "月露空濛迷檜檝，天香芬郁濕蘭袍。", "道猷法窟從茲始，應嘆吾生空二毛。"]'),
('d9c4fdc9-fbca-4461-997b-81be701f96f8','燈夕寄獻內翰虢略公','錢惟濟','宋','宋诗','song-poetry','','[]','嶢闕翬飛河漢傍，勾陳遙認赭袍光。',64,'全唐诗/poet.song.7000.json','["嶢闕翬飛河漢傍，勾陳遙認赭袍光。", "九枝火樹連金狄，萬里霜輪上碧璫。", "匝地行車珠網細，照光晨燎紫沈香。", "祇開鼇嶺神仙客，再拜雲邊捧壽觴。"]'),
('154afabc-09c7-492b-aac6-7cdba3f7ff5b','句  其一','錢惟濟','宋','宋诗','song-poetry','','[]','鳳簫通碧落，星石辨靈源。',12,'全唐诗/poet.song.7000.json','["鳳簫通碧落，星石辨靈源。"]'),
('c0ba988c-6dca-4bc4-907b-a85288c24169','句  其二','錢惟濟','宋','宋诗','song-poetry','','[]','庭下焚香連宿霧，林間鳴佩起棲鸞。',16,'全唐诗/poet.song.7000.json','["庭下焚香連宿霧，林間鳴佩起棲鸞。"]'),
('bee63fd4-8b86-4520-a755-8d94827d9597','句  其三','錢惟濟','宋','宋诗','song-poetry','','[]','曉陌壺漿滿，春風騎吹長。',12,'全唐诗/poet.song.7000.json','["曉陌壺漿滿，春風騎吹長。"]'),
('567f8a3f-5fcd-4a91-8bb9-ee28824384f3','天花寺','呂夷簡','宋','宋诗','song-poetry','','[]','賀家湖上天花寺，一一軒窗向水開。',32,'全唐诗/poet.song.7000.json','["賀家湖上天花寺，一一軒窗向水開。", "不用閉門防俗客，愛閑能有幾人來。"]'),
('49c7fe08-4f24-424b-a6fc-2fc705c9b340','憶越州  其一','呂夷簡','宋','宋诗','song-poetry','','[]','賀監湖邊山斗高，水軒水塢頻抽毫。',32,'全唐诗/poet.song.7000.json','["賀監湖邊山斗高，水軒水塢頻抽毫。", "吟餘清興杳無際，揭蓬聽雨登漁舠。"]'),
('a6f03d45-0a2f-47a4-b36f-3ed49f631084','憶越州  其二','呂夷簡','宋','宋诗','song-poetry','','[]','雲門雪竇阻清賞，怳然目想心如遺。',32,'全唐诗/poet.song.7000.json','["雲門雪竇阻清賞，怳然目想心如遺。", "前溪後溪月上處，千山萬山花發時。"]'),
('741613fa-841c-4d17-822c-0443d4763e61','江南立春','呂夷簡','宋','宋诗','song-poetry','','[]','灰律何時應，江春昨夜來。',48,'全唐诗/poet.song.7000.json','["灰律何時應，江春昨夜來。", "細風先動柳，殘雪不藏梅。", "餘冷迷清管，微和發凍醅。", "閉門無客到，樽俎爲誰開。"]'),
('9e2d23a2-524c-4ff4-9e36-a091fa6e257f','詠天寧院','呂夷簡','宋','宋诗','song-poetry','','[]','飄然吟魄到鰲山，好句空疏水石間。',32,'全唐诗/poet.song.7000.json','["飄然吟魄到鰲山，好句空疏水石間。", "眼界清虛心不息，浮生能有幾人閑。"]'),
('5ac69d20-dabb-4e88-9743-f8a57c7e8224','送僧歸護國寺','呂夷簡','宋','宋诗','song-poetry','','[]','赤城千仞聳霞標，聞說精藍近石橋。',64,'全唐诗/poet.song.7000.json','["赤城千仞聳霞標，聞說精藍近石橋。", "久向天廚分凈供，忽游人落赴嘉招。", "逾年華館留禪榻，幾宿輕航兀夜潮。", "深愧山陰許都講，肯隨支遁出塵囂。"]'),
('9ca69d26-9672-4695-a32b-4c4ce3234dbc','西溪看牡丹','呂夷簡','宋','宋诗','song-poetry','','[]','異香穠艷厭羣葩，何事栽培近海涯。',32,'全唐诗/poet.song.7000.json','["異香穠艷厭羣葩，何事栽培近海涯。", "開向東風應有恨，凭誰移入五侯家。"]'),
('d89564ab-1f77-4653-a635-96a364a1e407','無題','呂夷簡','宋','宋诗','song-poetry','','[]','老讀文書興易闌，須知養病不如閑。',32,'全唐诗/poet.song.7000.json','["老讀文書興易闌，須知養病不如閑。", "竹床瓦枕虛堂上，臥見江南雨後山。"]'),
('46c536cf-cf86-480d-b922-b7f45ccacdfd','重遊雁山','呂夷簡','宋','宋诗','song-poetry','','[]','往年遊海嶠，上徹最高層。',48,'全唐诗/poet.song.7000.json','["往年遊海嶠，上徹最高層。", "雲外疑無路，山中忽見僧。", "虎蹲臨澗石，猿掛半巖藤。", "何日拋龜紐，孤峰上再登。"]'),
('54792c46-fad9-4c61-b2e8-643c1f967c20','過靈巖寺','呂夷簡','宋','宋诗','song-poetry','','[]','凈名菴下靈巖路，峻壁層崖倚半空。',32,'全唐诗/poet.song.7000.json','["凈名菴下靈巖路，峻壁層崖倚半空。", "我愛老僧年八十，一生長住翠微中。"]'),
('9ad795a3-e82e-4705-bb34-e701a35ea538','鄭州浮波亭','呂夷簡','宋','宋诗','song-poetry','','[]','清波環繞地無塵，榜署嘉名得意新。',32,'全唐诗/poet.song.7000.json','["清波環繞地無塵，榜署嘉名得意新。", "若問經綸康濟術，亭中兼有釣璜人。"]'),
('38efdbde-2a2e-4d4c-a268-77bc4df55474','句  其一','呂夷簡','宋','宋诗','song-poetry','','[]','自恨捲簾人已老。',8,'全唐诗/poet.song.7000.json','["自恨捲簾人已老。"]'),
('54999f0a-1e99-4889-8b53-f03f2f6865df','句  其二','呂夷簡','宋','宋诗','song-poetry','','[]','梅無驛使飄零盡，草怨王孫取次生。',16,'全唐诗/poet.song.7000.json','["梅無驛使飄零盡，草怨王孫取次生。"]'),
('a012fb46-0660-4cc7-b8a3-54c41fd8790f','句  其三','呂夷簡','宋','宋诗','song-poetry','','[]','人歸北闕知何日，菊映東籬似去年。',16,'全唐诗/poet.song.7000.json','["人歸北闕知何日，菊映東籬似去年。"]'),
('8f6887f7-c0b9-4ee0-afd6-4512795853a6','句  其四','呂夷簡','宋','宋诗','song-poetry','','[]','人爲子推初禁火，花愁青女再飛霜。',16,'全唐诗/poet.song.7000.json','["人爲子推初禁火，花愁青女再飛霜。"]'),
('00b2f502-07be-4a33-a34e-8d0655fa9f6e','句  其五','呂夷簡','宋','宋诗','song-poetry','','[]','江涵帝子翬飛閣，山際真君鶴馭天。',16,'全唐诗/poet.song.7000.json','["江涵帝子翬飛閣，山際真君鶴馭天。"]'),
('81f5326c-fda9-49dd-9b53-10770c13e40b','贈仁曉禪師竹簟','曹修睦','宋','宋诗','song-poetry','','[]','翠筠織簟寄禪齋，半夜秋從枕底來。',32,'全唐诗/poet.song.7000.json','["翠筠織簟寄禪齋，半夜秋從枕底來。", "若也此時人問道，涼天捲卻暑天開。"]'),
('7d03c514-004e-4ce5-aced-1cf974fc6ce8','峴山','韋不伐','宋','宋诗','song-poetry','','[]','羊公民愛深，原叔復善政。',24,'全唐诗/poet.song.7000.json','["羊公民愛深，原叔復善政。", "緝祠流聲詩，才德交輝映。"]'),
('5ce537c2-51e9-4482-943f-7cb65b1471d0','句  其一','徐陟','宋','宋诗','song-poetry','','[]','君因山嶽重，汝命鴻毛輕。',12,'全唐诗/poet.song.7000.json','["君因山嶽重，汝命鴻毛輕。"]'),
('f67e8de1-5e77-47d1-b416-0fde4ef0caba','句  其二','徐陟','宋','宋诗','song-poetry','','[]','止渴當擇水，暫憩須芳陰。',12,'全唐诗/poet.song.7000.json','["止渴當擇水，暫憩須芳陰。"]'),
('751d3fb3-964f-4f00-bafa-244b4d372f83','湖州作','蘇爲','宋','宋诗','song-poetry','','[]','野艇閑撐處，湖天景亦微。',48,'全唐诗/poet.song.7000.json','["野艇閑撐處，湖天景亦微。", "春波無限綠，白鳥自由飛。", "柳色濃垂岸，山光冷照衣。", "時攜一壺酒，戀到晚涼歸。"]'),
('71634968-0f98-44c8-b9d6-52b9a3cffc88','宣城花','蘇爲','宋','宋诗','song-poetry','','[]','宣城花疊嶂，樓前簇綺霞。',28,'全唐诗/poet.song.7000.json','["宣城花疊嶂，樓前簇綺霞。", "若非翠露陶潛柳，即是紅藏小謝家。"]'),
('129aded2-2872-47a7-be5c-8ee905cd525d','邵武作','蘇爲','宋','宋诗','song-poetry','','[]','愛重八九月，登高上下樓。',24,'全唐诗/poet.song.7000.json','["愛重八九月，登高上下樓。", "林紅雲白處，寒瀨泊漁舟。"]'),
('31ed3bd3-4675-4172-8805-4f7bdea2cdb8','送張無夢歸天台','蘇爲','宋','宋诗','song-poetry','','[]','彤庭留不住，歸憶舊山頻。',48,'全唐诗/poet.song.7000.json','["彤庭留不住，歸憶舊山頻。", "世路都無念，心源養得真。", "瓊臺棲樹石，碧落應星辰。", "幾話蟠桃熟，罇前醉過春。"]'),
('e80b0ec0-423c-4f92-a10c-ad4c372d0952','東池詩','蘇爲','宋','宋诗','song-poetry','','[]','謝塘疏鑿時，滄洲聊可擬。',96,'全唐诗/poet.song.7000.json','["謝塘疏鑿時，滄洲聊可擬。", "高有智者情，淡如君子旨。", "秋光夜初永，漁唱幽宜起。", "白鷺閑不驚，圓荷翠相倚。", "宛然江上色，孰爲囂塵裏。", "待月泛潺湲，觀魚戲清泚。", "樓陰仰窗岫，閣影明霞綺。", "預想及瓜時，戀戀誠無已。"]'),
('d80cb12f-f70d-4fde-af4e-54dad3cffe3b','昭亭山','蘇爲','宋','宋诗','song-poetry','','[]','昭亭載嚴祠，休祐穰穰布。',84,'全唐诗/poet.song.7000.json','["昭亭載嚴祠，休祐穰穰布。", "森羅絕澗松，盤屈中阿路。", "凝眸盼平野，彷彿披寒霧。", "水遠露微陽，山明照紅樹。", "數尺漁艇歸，幾點秋鴻度。", "唯思圜室靜，更禱餘糧富。", "天末望白雲，帝鄉深所慕。"]'),
('52489f89-0003-43f2-bdb5-35878eb2ceab','宛溪','蘇爲','宋','宋诗','song-poetry','','[]','源分春穀邊，來此自溪徼。',72,'全唐诗/poet.song.7000.json','["源分春穀邊，來此自溪徼。", "雪凍汎其流，潄玉鳴于沼。", "晴光盪霞影，白浪浮天杪。", "水木助清翠，景物隨昏曉。", "汀沙翠荇長，酒市青旗小。", "憑檻立津亭，歸心逐飛鳥。"]'),
('7eb6abad-6e11-4ac8-9612-fbd0017acd60','化成圩','蘇爲','宋','宋诗','song-poetry','','[]','下田憐沮澤，環堤圪成雉。',48,'全唐诗/poet.song.7000.json','["下田憐沮澤，環堤圪成雉。", "堯湯水旱時，蓄洩得專利。", "泥資數斗沃，場謝千金貴。", "何物代天工，嘉此老農智。"]'),
('8effa3f3-f31e-4b62-89ec-dc236b187bcc','泛宛溪至敬亭','蘇爲','宋','宋诗','song-poetry','','[]','南國初寒候，扁舟遠客心。',48,'全唐诗/poet.song.7000.json','["南國初寒候，扁舟遠客心。", "歸人出斷岸，晚翼會疏林。", "漁市臨官道，叢祠蔽木陰。", "長年多感慨，況此對分襟。"]'),
('a34ba4cd-a067-40a9-8e5a-a5e7fee34c7a','句','蘇爲','宋','宋诗','song-poetry','','[]','夜浪珠還浦，春泥象印蹤。',12,'全唐诗/poet.song.7000.json','["夜浪珠還浦，春泥象印蹤。"]'),
('682540d6-8ac7-4282-aa1a-ca98c964a02b','南山十詠 鳴絃峰','劉仲堪','宋','宋诗','song-poetry','','[]','奇峰枕高岸，迴合藏雲煙。',48,'全唐诗/poet.song.7000.json','["奇峰枕高岸，迴合藏雲煙。", "直上數百仞，倒影浮清漣。", "民傳舜南狩，向此鳴朱絃。", "至今萬籟寂，雅韻猶泠然。"]'),
('f765052e-01e0-4ced-8686-fde750ee9288','南山十詠 薰風亭','劉仲堪','宋','宋诗','song-poetry','','[]','茲亭最高時，勢與羣峰仵。',48,'全唐诗/poet.song.7000.json','["茲亭最高時，勢與羣峰仵。", "層軒一以臨，萬物皆下顧。", "賡歌音久絕，締構意何古。", "猿鳥豈有知，騰翔如率舞。"]'),
('d2c73e11-0f90-4dd6-a482-853f5a16d45e','南山十詠 涵暉谷','劉仲堪','宋','宋诗','song-poetry','','[]','嵌空在山半，天設茲閑敞。',48,'全唐诗/poet.song.7000.json','["嵌空在山半，天設茲閑敞。", "清虛生晝白，高迴傳遙響。", "窮應到真境，憩暫祛煩想。", "巖石如可耕，此地堪長往。"]'),
('4afcd70f-861e-4a7e-8e40-42d851d3ed99','南山十詠 凌煙嶂','劉仲堪','宋','宋诗','song-poetry','','[]','嶔崟纔數仞，邐迤極幽致。',48,'全唐诗/poet.song.7000.json','["嶔崟纔數仞，邐迤極幽致。", "藤蘿與苔蘚，蔓延相□□。", "青天鍊可補，滄海鞭難至。", "運物者何爲，並此儕魑魅。"]'),
('edb9ed45-c248-4cc4-a5ab-687955619b30','南山十詠 宣聖廟','劉仲堪','宋','宋诗','song-poetry','','[]','翼翼素王宮，誇倚高峰右。',48,'全唐诗/poet.song.7000.json','["翼翼素王宮，誇倚高峰右。", "煙雲覆幽邃，樹石叢奇秀。", "丹青古冕服，赭堊新締構。", "率土被儒風，九夷信何陋。"]'),
('5625fd40-1a54-4aac-ad15-da96d5ee92c3','南山十詠 沂風亭','劉仲堪','宋','宋诗','song-poetry','','[]','四楹倚巖壁，一徑臨臨煙塢。',49,'全唐诗/poet.song.7000.json','["四楹倚巖壁，一徑臨臨煙塢。", "詵詵講習罷，濟濟生徒□。", "振衣嘉樹陰，浴德青江滸。", "舞詠自忘歸，何須在鄒魯。"]'),
('148a5ef4-fd2a-458a-a3e6-4c6b8a22e3a6','南山十詠 來學亭','劉仲堪','宋','宋诗','song-poetry','','[]','□雲忽上征，簷廡如翬翅。',48,'全唐诗/poet.song.7000.json','["□雲忽上征，簷廡如翬翅。", "橫經就一隅，負笈來千里。", "止同矍相圃，□類公□市。", "靜聽絃誦聲，杳在層巒裏。"]'),
('46f8c53d-6f18-4f87-ab0b-21220a6d2ddf','南山十詠 集儒閣','劉仲堪','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','飛閣敞東軒，俯瞰長江瀉。',48,'全唐诗/poet.song.7000.json','["飛閣敞東軒，俯瞰長江瀉。", "晨霞晃梁際，晴虹隱波下。", "諸生肄業餘，羣吏時享罷。", "清風四座來，茲焉縱嘉話。"]'),
('e57fad41-2895-431d-ae79-43ec2489ead2','南山十詠 讀易堂','劉仲堪','宋','宋诗','song-poetry','','[]','八卦既成列，幽贊天地功。',48,'全唐诗/poet.song.7000.json','["八卦既成列，幽贊天地功。", "邈哉九聖意，究此□堂中。", "□機□嚴□，華□□澗松。", "□□理儻析，欲遊學□蹤。"]'),
('b2627752-211d-4acf-9bd8-b45bbde9ecbf','南山十詠 □書院','劉仲堪','宋','宋诗','song-poetry','','[]','鑿石導行徑，刊木羅居室。',48,'全唐诗/poet.song.7000.json','["鑿石導行徑，刊木羅居室。", "微雲□總戶，青嵐照緗帙。", "潔士□□堵，志人輕尺璧。", "況近□山水，勉旃此游息。"]'),
('993ca32e-8a02-4794-9d7b-e2f2790cffac','行色','司馬池','宋','宋诗','song-poetry','','[]','冷於陂水淡於秋，遠陌初窮見渡頭。',32,'全唐诗/poet.song.7000.json','["冷於陂水淡於秋，遠陌初窮見渡頭。", "猶賴丹青無處畫，畫成應遣一生愁。"]'),
('bd8377e2-a79b-4d7d-a156-7538542d1850','郡舍偶書','楊偕','宋','宋诗','song-poetry','','[]','偃息鈴齋度歲華，著書人聖笑聱牙。',64,'全唐诗/poet.song.7000.json','["偃息鈴齋度歲華，著書人聖笑聱牙。", "斯文自信驚天地，吾道誰知繫國家。", "獨愛杉篁寒不變，更憐江海闊無涯。", "因思朝市爭名地，何似優游刺史衙。"]'),
('ddbcaadd-c3db-4db3-acb0-9b3d568ceea8','送寶相長老','釋重顯','宋','宋诗','song-poetry','','[]','奥域靈區存物外，獨標台嶺爲絕槩。',160,'全唐诗/poet.song.7000.json','["奥域靈區存物外，獨標台嶺爲絕槩。", "掩勝潛奇列作屏，堆青寫碧深如黛。", "彤霞暖影生巖壁，香桂茂陰籠蘚石。", "赤松子也浪虚閑，白道猷兮太輕擲。", "曹溪有叟歸其中，風從虎兮雲從龍。", "乘興正值二三月，坐斷還依千萬峰。", "花飛飛，日遲遲，清飈𩖼𩖼吹無時。", "玲瓏八面自回合，峭峻一方誰敢窺。", "窺來須得乾坤眼，照古騰今謂非間。", "若能此去副全提，開發人天有何限。"]'),
('546a14c2-b579-4d56-a8fd-f0f3b0d53669','送法海長老','釋重顯','宋','宋诗','song-poetry','','[]','常愛裴相國，式芳塵，斷際高風慕要倫。',250,'全唐诗/poet.song.7000.json','["常愛裴相國，式芳塵，斷際高風慕要倫。", "擬欲事師爲弟子，不知將法付何人。", "常愛李相國，垂列星，藥嶠深源宅性靈。", "我來問道無餘說，雲在清霄水在瓶。", "緬想當時二台輔，出鎮藩維訪諸祖。", "寥寥浮幻輕百年，落落宏規照千古。", "今聞仙都賢太守，入政褰帷聲浩浩。", "英佐一一分化條，文經武緯亦難討。", "遠遠牋函飛乳峰，選開士兮恢吾宗。", "覿夜光非震滄海，聆正音豈玩焦桐。", "徒誇麟龍，自西自東。", "應排罔象得象，必須覺雄讓雄。", "今既塞請，還也奇别。", "茫茫普熱，紛紛下雪。", "倒流四河，載發枯枿。", "卷舒立方外乾坤，蹤横挂域中日月。", "黄頭碧眼知未知，去去憑誰繼清絕。"]'),
('a6938c3d-18b7-483e-b456-1b173aebe168','送文政禪者','釋重顯','宋','宋诗','song-poetry','','[]','古有焦桐音，聽寡不在彈。',128,'全唐诗/poet.song.7000.json','["古有焦桐音，聽寡不在彈。", "古有陽春曲，和寡不在言。", "言兮牙齒寒，未極離微根。", "彈兮歲月闌，未盡昇沉源。", "少休幾坐花木落，庾嶺獨行天地寛。", "因笑仲尼温伯雪，傾蓋同途不同轍。", "麟兮鳳兮安可論，許兮巢兮復何說。", "秋光澄澄蟾印水，秋風蕭蕭葉初墜。", "送君高蹈誰不知，如曰不知則爲貴。"]'),
('3cfcfe5f-9dcc-4953-abb5-7e5c7066d2da','送昭敏首座','釋重顯','宋','宋诗','song-poetry','','[]','君不見，鷲峰勝集，百萬茫茫等閑過，壞衲之外皆清墮。',147,'全唐诗/poet.song.7000.json','["君不見，鷲峰勝集，百萬茫茫等閑過，壞衲之外皆清墮。", "君又不見，熊嶺孤運，歲月索索艱難生，深雪之中有一箇。", "宛轉流落千餘年，危分嶮布空平闐。", "弁龍蛇兮眼何正，擒虎兕兮機不全。", "石窗四顧滄溟窄，寥寥不許白雲白。", "掣斷金鎖天麒麟，高舉鐵鞭擊三百。", "猶輕舍，争知也，别有七星光鬭射。", "風前把欲贈行人，將報不平遶天下。"]'),
('0d39c835-d021-462c-9aa5-87ca289dfcd6','送知白禪者','釋重顯','宋','宋诗','song-poetry','','[]','松不直，棘不曲，誰笑卞和三獻玉。',66,'全唐诗/poet.song.7000.json','["松不直，棘不曲，誰笑卞和三獻玉。", "經天緯地太無端，邁古超今亦輕觸。", "靡羈束，何必云，素範還還，真規復復。", "栴檀葉落香風清，千里萬里長相逐。"]'),
('b04c7226-d39e-44fa-96ee-e684728a44f4','送勝因長老','釋重顯','宋','宋诗','song-poetry','','[]','黄梅散席三百載，續焰聯芳事空在。',160,'全唐诗/poet.song.7000.json','["黄梅散席三百載，續焰聯芳事空在。", "宗兮派分生異端，花兮葉兮太煩碎。", "韶陽間出多慷慨，權要雄雄曾絕待。", "曲木據位知幾何，利刀翦却令人愛。", "近還有箇披老衲，楚甸横身風颯颯。", "鐡作一尋非等閑，壁立千仞須摧蹋。", "報君知，江南江北徒纍纍。", "鼇轉海運兮纖鱗片甲，雷奔電驅兮寸毫尺氂。", "斯言勿謂存規矩，平不留兮險非取。", "周行獨立如便休，誰振宏綱照千古。"]'),
('c7ba191e-b770-4146-935c-1926c5bcc9a9','送重郜禪者','釋重顯','宋','宋诗','song-poetry','','[]','春雨如膏，春雲如鶴。',69,'全唐诗/poet.song.7000.json','["春雨如膏，春雲如鶴。", "忽此忽彼，乍休乍作。", "枯荄離離，維風太遲。", "幽石片片，遼空亦危。", "一花五葉兮不相似，獨孤明兮還自知。", "還自知，歷魏游梁徒爾爲。"]'),
('413aeeb2-cb33-48ef-bca0-f4c70f6354ec','送僧歸靈隱','釋重顯','宋','宋诗','song-poetry','','[]','白雲無羈，泠淡清奇。',68,'全唐诗/poet.song.7000.json','["白雲無羈，泠淡清奇。", "雪格未可，鶴態還卑。", "垂天沃日兮似結不結，爲雨從龍兮後期必期。", "噫，悠悠忽爾春風吹，南北東西唯我知，誰知菡萏峰前布影時。"]'),
('ab624a24-a96f-4180-ab4c-5e0dd63fb0db','送僧之石梁','釋重顯','宋','宋诗','song-poetry','','[]','萬卉流芳，不知春力。',87,'全唐诗/poet.song.7000.json','["萬卉流芳，不知春力。", "巖畔澗下，蹙紅皺碧。", "乘興復誰同，孤蹤遠讎敵。", "君不見五百聖者導雄機，靈峰晦育深無極。", "寒山老，寒山老，隨沈跡，迢迢此去須尋覓。", "花落花開獨望時，記取白雲抱幽石。"]'),
('d1281ba5-d19e-4776-ae7b-42f34cdcdbd1','送師旻禪者','釋重顯','宋','宋诗','song-poetry','','[]','深巖寂寂披蘭芷，碧霧紅霞映流水。',124,'全唐诗/poet.song.7000.json','["深巖寂寂披蘭芷，碧霧紅霞映流水。", "空生别我期未期，絕域殊方擬輕擬。", "堪笑歸嶺南，奔馳何鄙彼。", "危急亂抛下，盡云提不起。", "伊予本自不將來，相送奚憑挂唇齒。", "旻禪客，旻禪客，師子子，應須落落存終始。", "君不見古人有言兮，撲碎驪龍明月珠。", "大丈夫到如此，行行不用頻彈指。"]'),
('06085629-ded5-4feb-a3d1-e31891605dd0','寄白雲長老','釋重顯','宋','宋诗','song-poetry','','[]','八紘雲靜明寥泬，夜永松堂對寒月。',128,'全唐诗/poet.song.7000.json','["八紘雲靜明寥泬，夜永松堂對寒月。", "凋殘片葉墜虛庭，泠寂何人立深雪。", "因憶錢唐郜禪者，十載巖栖曾未下。", "分飛誰謂絕相同，遠念冥冥欲奚寫。", "忽聞赴請之仙都，聲光藹藹登清途。", "孰云天驥驟方外，自笑大鵬離海隅。", "乾坤窄，乾坤窄，湛盧潛射斗牛白。", "茫茫無限未歸人，到必爲時除點額。"]'),
('ce9dbc77-e466-47c3-9dcb-e1e346ed88b2','送智遷首座','釋重顯','宋','宋诗','song-poetry','','[]','雲蘿杳杳藏巖曲，碧疊清飛冷相促。',96,'全唐诗/poet.song.7000.json','["雲蘿杳杳藏巖曲，碧疊清飛冷相促。", "瘦藤輕衲休便休，短焰殘芳續何續。", "禪家本自冥羈絆，洲渚園林曾不憚。", "十影神駒立海涯，五色祥麟步天岸。", "君看取，君看取，匝地茫茫有誰舉。", "瓴甋頻磨如未回，爲吾深憶盧公語。"]'),
('8711f868-39e5-4dfc-914c-82445b79594d','送善暹首座','釋重顯','宋','宋诗','song-poetry','','[]','名之基，實之蒂，深兮固兮宛相繼。',170,'全唐诗/poet.song.7000.json','["名之基，實之蒂，深兮固兮宛相繼。", "古之名也在希聲，今之實也同浮瞖。", "子州善卷之流也，堯驅舜馳讓無暇。", "歸兮歸兮歸不歸，到頭未出冥冥者。", "吾徒孰謂標奇絕，動靜憑君試甄别。", "葉零零兮秋暮半凋，花片片兮春暖齊發。", "暹禪老，暹禪老，意曾高。", "曠排沽待，忽致譏褒。", "天人列請兮屢輕笑，祖佛位卑兮還擬逃。", "我恐逃之逃不得，大方無外皆充塞。", "茫茫擾擾知何極，八面香風惹衣裓。"]'),
('d99e9ddd-6602-4937-9a19-e12c7870df4f','送僧','釋重顯','宋','宋诗','song-poetry','','[]','吴山碧，楚江碧，吴楚悠悠興何極。',96,'全唐诗/poet.song.7000.json','["吴山碧，楚江碧，吴楚悠悠興何極。", "一尋寒木自爲鄰，三事秋雲更誰識。", "乾坤不是無知已，玉石休云辨真僞。", "待時沽譽漫淪生，晦跡韜光亦何意。", "春風急，春風急，八駿奔馳追不及。", "南北東西把定時，爲君直上孤峰立。"]'),
('0e91d840-9cea-45e0-b1ec-da43b8f6e933','頌藥山師子話送僧','釋重顯','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','厇訴金毛師子子，栴檀林下青莎裏。',64,'全唐诗/poet.song.7000.json','["厇訴金毛師子子，栴檀林下青莎裏。", "置也置也威自全，一出六出眉剔起。", "非擬擬，知幾幾，星流不問三千里。", "天外風清哮吼時，爲君吸盡西江水。"]'),
('2d6cd36b-5f50-43e2-b5d4-601035c7264b','送秀大師','釋重顯','宋','宋诗','song-poetry','','[]','巖竇宵寒擁山帔，月高古木霜禽睡。',95,'全唐诗/poet.song.7000.json','["巖竇宵寒擁山帔，月高古木霜禽睡。", "西庵禪者來扣門，别我凌晨下層翠。", "欲留不可留，寫意不及意。", "屈眴迢迢安足云，花偈聯聯太容易。", "君不見劉陽叟，絕希冀，送人只道無他事。", "行行會有知音知，何必清風動天地。"]'),
('77cd8e9a-a626-4d64-a913-359e9f16bb77','送廣華嚴歸鷲峰','釋重顯','宋','宋诗','song-poetry','','[]','海山孤僻非蓬島，霧泠雲深松桂老。',96,'全唐诗/poet.song.7000.json','["海山孤僻非蓬島，霧泠雲深松桂老。", "有客凝冬何太高，巨野宵征苦相討。", "巖房杳杳凌寒空，冰霜落落分譚叢。", "誰云百城沉古月，自笑八面生清風。", "俄然别我還歸去，惠理之徒望回馭。", "重重無盡樓閣門，到必爲時略輕據。"]'),
('f1666101-94e4-4ee1-87d7-d91376880fba','送遠塵禪者','釋重顯','宋','宋诗','song-poetry','','[]','衲卷殘雲，風高絕鄰。',56,'全唐诗/poet.song.7000.json','["衲卷殘雲，風高絕鄰。", "倚天照雪，堪抗要津。", "八紘極目兮春山若黛，九野縱步兮汀草如茵。", "三十四老未輕識，澟然方外奚相親。"]'),
('e392c3e1-e6b6-47c3-8e0f-b0d47016a1dc','送德隆山主','釋重顯','宋','宋诗','song-poetry','','[]','霜葉凋殘，巖風凜寒。',74,'全唐诗/poet.song.7000.json','["霜葉凋殘，巖風凜寒。", "彼之禪老，忽下崇巒。", "衲有雲兮曾卷未卷，琴無絃兮解彈不彈。", "迢迢既行，宜聼斯語。", "明暗路岐，生死洲渚。", "而今而後知不知，頺綱委地憑誰舉。"]'),
('0cfdcb09-260a-4018-9e0a-2fb807b4dad2','送澄禪者','釋重顯','宋','宋诗','song-poetry','','[]','春色依依，襲爾原草。',93,'全唐诗/poet.song.7000.json','["春色依依，襲爾原草。", "春風浩浩，拂我窗牖。", "念此分飛，贈無瓊玖。", "片片亂飄巖上梅，條條縱舞溪邊柳。", "澄禪澄禪聽斯言，古也今也行路難。", "知之者石火星流未急，不知者龍驥步驟曾寛。", "看看，孰云平地起波瀾。"]'),
('8dac617f-27af-4ce8-b9b2-a8dfac1b87fb','送惠儔禪者','釋重顯','宋','宋诗','song-poetry','','[]','少林風規，何太蕭灑。',60,'全唐诗/poet.song.7000.json','["少林風規，何太蕭灑。", "籠古罩今，睥真睨假。", "誰云發機射虎，自笑品類觀馬。", "劍客茫茫不要呈，甑人往往須擒下。", "儔禪儔禫，崢嶸象駕。"]'),
('bb15d719-4b8c-48bd-8bcb-ba3046476fa8','送惠文禪者','釋重顯','宋','宋诗','song-poetry','','[]','正法眼，絕塵沙。',71,'全唐诗/poet.song.7000.json','["正法眼，絕塵沙。", "二三四七，水月空花。", "千燈續焰曾間，五葉分披未葩。", "君不見卷蓆百丈，掩耳丹霞。", "龍行虎步爭孤立，盡同雲雨去無涯。", "文禪文禪，騰煥吾家。"]'),
('e8bb611c-82b6-440b-9ed0-1315e18aba1e','送道成禪者','釋重顯','宋','宋诗','song-poetry','','[]','曹溪流，非止水。',61,'全唐诗/poet.song.7000.json','["曹溪流，非止水。", "一點忽來，千波自起。", "直須釣鼇釣鯨，莫問得皮得髓。", "君不見石頭有言兮，聖不慕他，靈不在己。", "成禪成禪，誰家之子。"]'),
('58801ac7-002f-4f76-a9b1-eb6b23ae0476','送清演禪者','釋重顯','宋','宋诗','song-poetry','','[]','我年老大，心力衰微。',64,'全唐诗/poet.song.7000.json','["我年老大，心力衰微。", "贈别無語，冥同振飛。", "因思古之送人有言，吾不知其殊途同歸。", "獨愛新豐，曲騰清輝。", "寸草不生千萬里，出門春色共依依。"]'),
('f19cca9c-74ee-47d3-8913-1683b3f1019d','送繼寶禪者','釋重顯','宋','宋诗','song-poetry','','[]','寶非寶，日杲杲。',48,'全唐诗/poet.song.7000.json','["寶非寶，日杲杲。", "上上機，無處討。", "赤水求來何太狂，荆山覓得苦相惱。", "不惱不狂排夜光，險惡道中爲津梁。"]'),
('39d427b7-ecac-4205-9948-a074bc301edf','送小師元楚','釋重顯','宋','宋诗','song-poetry','','[]','道之冥機，一何相守。',54,'全唐诗/poet.song.7000.json','["道之冥機，一何相守。", "汝競光陰，我親蒲柳。", "毋厚弁之奪席，毋薄愚之誦箒。", "深思彼伐木丁丁之聲，照古照今兮宜善求友。"]'),
('a15bb3b3-d7f6-4a71-9d90-3def9de340ee','送清杲禪者','釋重顯','宋','宋诗','song-poetry','','[]','春雨濛濛，春風𩖼𩖼。',96,'全唐诗/poet.song.7000.json','["春雨濛濛，春風𩖼𩖼。", "動兮靜兮，匪待時出。", "雲霞閑澹作性，金鐡冷落爲骨。", "知我者謂我高蹈世表，不知我者謂我下視塵窟。", "道恣隨方，情融羈鎖。", "紫栗一尋，青山萬朵。", "行行思古人之言，無可不可，南北東西但唯我。"]'),
('2f39bc0a-65f8-4711-8090-b7c26f5a23d2','酬行奯長老','釋重顯','宋','宋诗','song-poetry','','[]','黄金爲骨松爲姿，道高曾鄙天人師。',36,'全唐诗/poet.song.7000.json','["黄金爲骨松爲姿，道高曾鄙天人師。", "有言遺我千古奇，無人知，石虎吞却木羊兒。"]'),
('bf24769f-318c-4878-9d52-62914ebbe769','至人不器','釋重顯','宋','宋诗','song-poetry','','[]','誰當機，舉不賺，亦還稀。',64,'全唐诗/poet.song.7000.json','["誰當機，舉不賺，亦還稀。", "摧殘峭峻，銷爍玄微。", "重關曾巨闢，作者未同歸。", "玉兔乍圓乍缺，金烏似飛不飛。", "盧老不知何處去，白雲流水共依依。"]'),
('70985f8f-495b-4e20-8d0f-6f5dd5334398','因事示衆','釋重顯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','石本落落，玉自碌碌。',53,'全唐诗/poet.song.7000.json','["石本落落，玉自碌碌。", "古之今之，一何𧬊速。", "師子不咬麒麟，猛虎不食伏肉。", "君不見洞庭孤島煙浪深，木馬追風有人識。"]'),
('a9fa8bb9-8cd5-4526-b061-092bad60d06c','日暮游東澗  其一','釋重顯','宋','宋诗','song-poetry','','[]','極目生晚照，溪雲偶成朵。',24,'全唐诗/poet.song.7000.json','["極目生晚照，溪雲偶成朵。", "大樸曾未分，青山自唯我。"]'),
('6b4c9298-f20a-4f82-8702-67a1f006964b','日暮游東澗  其二','釋重顯','宋','宋诗','song-poetry','','[]','極目生晚照，遠樹籠微陰。',24,'全唐诗/poet.song.7000.json','["極目生晚照，遠樹籠微陰。", "誰知清淺流，别有滄海深。"]'),
('31a18836-28ff-4666-b743-4d665d175cd5','日暮游東澗  其三','釋重顯','宋','宋诗','song-poetry','','[]','極目生晚照，幽情眷蘭芷。',24,'全唐诗/poet.song.7000.json','["極目生晚照，幽情眷蘭芷。", "白蘋葉裏風，不在秋江起。"]'),
('67a5f966-4a56-4d6f-9c29-81a5316c0ba7','日暮游東澗  其四','釋重顯','宋','宋诗','song-poetry','','[]','極目生晚照，步影何遲遲。',24,'全唐诗/poet.song.7000.json','["極目生晚照，步影何遲遲。", "歸禽古木中，相對頻相窺。"]'),
('53950f2b-7f50-4028-ba4d-7a82b0c3714f','日暮游東澗  其五','釋重顯','宋','宋诗','song-poetry','','[]','極目生晚照，蓬萊匪仙境。',24,'全唐诗/poet.song.7000.json','["極目生晚照，蓬萊匪仙境。", "釣得十二鼇，重來謝孤影。"]'),
('10ce1382-e72f-4c67-921b-ce8b247b07d9','思歸引  其一','釋重顯','宋','宋诗','song-poetry','','[]','一住翠峰頂，兩見溪草綠。',48,'全唐诗/poet.song.7000.json','["一住翠峰頂，兩見溪草綠。", "不知朝市間，幾番生榮辱。", "蕭條巖上雲，冷淡水邊竹。", "報誰歸去來，向此空踟躅。"]'),
('13af8803-41b9-484c-8b11-40fa9c681858','思歸引  其二','釋重顯','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','常憶在廬山，隨時寄瓶錫。',48,'全唐诗/poet.song.7000.json','["常憶在廬山，隨時寄瓶錫。", "五百與一千，聚頭同遣日。", "猿攀影未回，鶴望情還失。", "教他王老師，癡鈍無處覓。"]'),
('57aaea2c-69b1-47e0-9c75-007a48be7ee3','思歸引  其三','釋重顯','宋','宋诗','song-poetry','','[]','時雨灑如膏，萬卉皆滋益。',48,'全唐诗/poet.song.7000.json','["時雨灑如膏，萬卉皆滋益。", "枯根甘自休，也似春無力。", "耕夫曉尚眠，蠶婦夜多息。", "從兹家業荒，共落風塵跡。"]'),
('472eb3d9-ac99-4ac2-889f-a0a04b4c4655','送藴懽禪者西上','釋重顯','宋','宋诗','song-poetry','','[]','金闕路曾遙，行行直開泰。',48,'全唐诗/poet.song.7000.json','["金闕路曾遙，行行直開泰。", "石房雲未閑，杳杳若相待。", "高蹤逾履冰，何人不傾蓋。", "早晚承帝恩，再卜林泉會。"]'),
('700e7783-c323-4673-b3dc-8944b41ad43f','送僧','釋重顯','宋','宋诗','song-poetry','','[]','春雲情既高，片段飛虛碧。',48,'全唐诗/poet.song.7000.json','["春雲情既高，片段飛虛碧。", "去留機未消，今古望還積。", "澄澄天影回，杳杳地形直。", "别夜共相思，誰栖此泉石。"]'),
('a1bdb2a0-90a2-45c5-a828-c0619394175a','法爾不爾','釋重顯','宋','宋诗','song-poetry','','[]','夏雲多奇峰，乾城冷相映。',48,'全唐诗/poet.song.7000.json','["夏雲多奇峰，乾城冷相映。", "借問諸禪僧，那箇堪憑定。", "乾城高鎖月，夏雲欲爲雨。", "若謂非全功，子細看規矩。"]'),
('2719d129-6879-4088-a67d-f3c674ee8727','送諸方化主','釋重顯','宋','宋诗','song-poetry','','[]','空巖暖律回，極目望還普。',48,'全唐诗/poet.song.7000.json','["空巖暖律回，極目望還普。", "數點方外雲，幾處人間雨。", "寥寥滄海月，依依少林祖。", "去必示勞生，清風立千古。"]'),
('1eea670c-5423-42a1-9046-a0753fb3deb0','劉禹端公問雲居雨從何來東平問官人風作何色  其一','釋重顯','宋','宋诗','song-poetry','','[]','雨從何來，風作何色。',30,'全唐诗/poet.song.7000.json','["雨從何來，風作何色。", "龍門萬仞，曾留宿客。", "進退相將，誰遭點額。"]'),
('3b43deb6-840d-4848-89fe-ef25f2a37084','劉禹端公問雲居雨從何來東平問官人風作何色  其二','釋重顯','宋','宋诗','song-poetry','','[]','風作何色，雨從何來。',30,'全唐诗/poet.song.7000.json','["風作何色，雨從何來。", "不用彈指，樓閣門開。", "波波稜稜，南方未回。"]'),
('b21813fa-e45a-42f9-9ca8-110a4f3b4af1','送僧','釋重顯','宋','宋诗','song-poetry','','[]','松風清未休，水月淡相對。',24,'全唐诗/poet.song.7000.json','["松風清未休，水月淡相對。", "去來非等閑，必許孤雲會。"]'),
('2e17984a-2982-4ea9-aa0b-9915a4d94168','頌雲門九九八十一  其一','釋重顯','宋','宋诗','song-poetry','','[]','三三九九八十一，一一觀風隨召出。',32,'全唐诗/poet.song.7000.json','["三三九九八十一，一一觀風隨召出。", "千古有誰同共知，一毛師子衆毛畢。"]'),
('bd25b6ac-db57-4e71-a1bc-02f497919ffe','頌雲門九九八十一  其二','釋重顯','宋','宋诗','song-poetry','','[]','九九八十一，大勳不豎賞。',24,'全唐诗/poet.song.7000.json','["九九八十一，大勳不豎賞。", "若謂無詨訛，金剛曾合掌。"]'),
('8992575c-fb0a-42ca-835d-52c31d4349ef','烏龍和尚','釋重顯','宋','宋诗','song-poetry','','[]','空巖清夜坐，蘚徑積深雪。',48,'全唐诗/poet.song.7000.json','["空巖清夜坐，蘚徑積深雪。", "瞑目思古人，徹曙落殘月。", "童敲石磬寒，猿挂枯枝折。", "杳杳無限情，分明向誰說。"]'),
('c72c03ec-3d96-4826-8fcb-936f8a22966d','秋日送僧','釋重顯','宋','宋诗','song-poetry','','[]','邊雁影邪，寒蟬聲速。',58,'全唐诗/poet.song.7000.json','["邊雁影邪，寒蟬聲速。", "乘時毳流，遠别巖谷。", "林驚一葉兮微風觸袖，水肅百川兮片月在目。", "因憶象骨老師曾送人，行行不謂抽金鏃。"]'),
('1ff6842e-b7bc-4dc2-b5ff-6f4edcc31e2a','早參示衆','釋重顯','宋','宋诗','song-poetry','','[]','曉天雲靜濃霜白，千峰萬峰鎖寒色。',32,'全唐诗/poet.song.7000.json','["曉天雲靜濃霜白，千峰萬峰鎖寒色。", "驪龍失珠知不知，無限平人遭點額。"]'),
('0478f535-1056-4c1d-afaf-a9a070bf1180','春風辭寄武威石秘校','釋重顯','宋','宋诗','song-poetry','','[]','春風何蕭蕭，和雨復兼雪。',192,'全唐诗/poet.song.7000.json','["春風何蕭蕭，和雨復兼雪。", "坼花功未深，偃草勢曾烈。", "毗城癡愛老，怯寒對清拙。", "襄巖影響士，難御同孤劣。", "鼇峰人不來，柴門亦休閉。", "松頭栗鼠下，時把藤牀囓。", "庭際霜禽歸，屢啄雪錢缺。", "一旦春風息，暖日生林樾。", "幽徑磐百上，拄筇行且歇。", "無絃兮莫彈，有語兮存舌。", "冷落流水聲，古之若爲說。", "凋殘早梅樹，今之若爲别。", "俯仰身力輕，翻憶春風切。", "爲吾吹却塵，欲革分岐轍。", "爲吾吹却雲，欲問遼空月。", "不知天地間，堪爲誰交結。"]'),
('68226ee6-6d2b-4f9a-949b-76758e28d08b','送百丈專使','釋重顯','宋','宋诗','song-poetry','','[]','大雄孤頂曾遐舉，偏索諸方誰敢拒。',32,'全唐诗/poet.song.7000.json','["大雄孤頂曾遐舉，偏索諸方誰敢拒。", "乳竇峰前捋虎鬚，再得完全又歸去。"]'),
('99e49ef9-0dc8-4b65-983b-50ba900278f3','送清素禪者之金華','釋重顯','宋','宋诗','song-poetry','','[]','古策風高瓶浪闊，春雲片段分清絕。',32,'全唐诗/poet.song.7000.json','["古策風高瓶浪闊，春雲片段分清絕。", "金盆后夜孤頂寒，去去誰同落殘月。"]'),
('4cdfc805-9e26-4a3b-9261-b667c340481e','擬寒山送僧','釋重顯','宋','宋诗','song-poetry','','[]','擇木有靈禽，寒空寄羽翼。',24,'全唐诗/poet.song.7000.json','["擇木有靈禽，寒空寄羽翼。", "不止蓬萊山，冥冥去何極。"]'),
('56d02a5b-0564-420e-8765-43396e5b854e','送如香大師','釋重顯','宋','宋诗','song-poetry','','[]','栴檀葉落雨初歇，天外風清亦何别。',32,'全唐诗/poet.song.7000.json','["栴檀葉落雨初歇，天外風清亦何别。", "後夜蓮城溪月寒，孤光誰共倚寥泬。"]'),
('1d9f5afd-b11f-4d5f-95ba-3d0041774441','寄于秘丞  其一','釋重顯','宋','宋诗','song-poetry','','[]','石徑通巖竇，引步藏欹側。',24,'全唐诗/poet.song.7000.json','["石徑通巖竇，引步藏欹側。", "蓬萊人不來，掃盡蒼苔色。"]'),
('d61f723f-1a24-4c8d-9739-37032ec59453','寄于秘丞  其二','釋重顯','宋','宋诗','song-poetry','','[]','飛瀑千萬層，五月狀冰雪。',24,'全唐诗/poet.song.7000.json','["飛瀑千萬層，五月狀冰雪。", "將期雲霧開，永夜對孤月。"]'),
('6ec3bc9e-5f1a-4aba-bf33-04a7d6a99d6e','再成古詩','釋重顯','宋','宋诗','song-poetry','','[]','霜花一鑷中，玉童摘未摘。',36,'全唐诗/poet.song.7000.json','["霜花一鑷中，玉童摘未摘。", "斯言如不聞，千古動愁色。", "因憶商山吟，在烏如在白。"]'),
('2b02af34-a433-4d82-87fa-cad4a098f65b','答當生不生','釋重顯','宋','宋诗','song-poetry','','[]','咄咄休强名，芻狗亦爲累。',24,'全唐诗/poet.song.7000.json','["咄咄休强名，芻狗亦爲累。", "寂寥金粟身，曾未求諸己。"]'),
('bf0e377a-fd6a-465f-b35f-d88ebb2ad346','戲靠安巖呈雙溪大師','釋重顯','宋','宋诗','song-poetry','','[]','陜府鐡牛却知有，春秋幾幾成過咎。',32,'全唐诗/poet.song.7000.json','["陜府鐡牛却知有，春秋幾幾成過咎。", "一身還作二如來，黑白不分辨香臭。"]'),
('3bc01a8f-c5db-4b26-9138-dcf0ef9ec2fd','疏黑白無從','釋重顯','宋','宋诗','song-poetry','','[]','天地不仁，萬化蠢蠢。',30,'全唐诗/poet.song.7000.json','["天地不仁，萬化蠢蠢。", "若謂非緣，竹何從笋。", "髮兮髪兮，黑白是凖。"]'),
('6ea0f69f-9a29-4790-9261-a21eb2fa42ed','暮冬感懷寄瑞巖禪師','釋重顯','宋','宋诗','song-poetry','','[]','雪水遶松檻，遲遲結清淺。',48,'全唐诗/poet.song.7000.json','["雪水遶松檻，遲遲結清淺。", "病眼時懶開，幽情況難遣。", "故人久相别，飛文屢慚靦。", "仰謝十二峰，分照月如翦。"]'),
('faed7614-b471-4bb4-b4b6-50f602dfa1e5','送知久禪者','釋重顯','宋','宋诗','song-poetry','','[]','霜竹凝寒攜九節，銅瓶浪鎖千溪月。',32,'全唐诗/poet.song.7000.json','["霜竹凝寒攜九節，銅瓶浪鎖千溪月。", "天上人間不自知，行行誰共分清絕。"]'),
('ee2416ff-ce39-4144-9b92-efc54cfde119','送慶顔禪者','釋重顯','宋','宋诗','song-poetry','','[]','巖桂風清香露滴，定起高秋映虛碧。',32,'全唐诗/poet.song.7000.json','["巖桂風清香露滴，定起高秋映虛碧。", "斷雲不是歸帝鄉，飛落人間有誰識。"]'),
('b3c6aa7f-c41d-461a-afce-6b3c3e774bae','春日懷古  其一','釋重顯','宋','宋诗','song-poetry','','[]','門外春將半，巖冰暖有聲。',24,'全唐诗/poet.song.7000.json','["門外春將半，巖冰暖有聲。", "玄沙曾未到，虛得偃溪名。"]'),
('8ee2c949-7251-4452-a2a9-c497d7215e51','春日懷古  其二','釋重顯','宋','宋诗','song-poetry','','[]','門外春將半，青青野色分。',24,'全唐诗/poet.song.7000.json','["門外春將半，青青野色分。", "桃花開欲盡，無處覓靈雲。"]'),
('4e8ed404-ac74-45a0-beeb-2eced77d13f5','春日懷古  其三','釋重顯','宋','宋诗','song-poetry','','[]','門外春將半，羣芳鬭盛時。',24,'全唐诗/poet.song.7000.json','["門外春將半，羣芳鬭盛時。", "鄰家有庭柏，諸祖共相知。"]'),
('813eed78-0003-4a37-8987-927bb4188079','春日懷古  其四','釋重顯','宋','宋诗','song-poetry','','[]','門外春將半，幽禽語共新。',24,'全唐诗/poet.song.7000.json','["門外春將半，幽禽語共新。", "寶陀巖上客，應笑未歸人。"]'),
('59a16122-12ad-4a97-b154-40b5f5c0d4f6','送僧之金陵','釋重顯','宋','宋诗','song-poetry','','[]','勝游生末跡，杳自狎時羣。',48,'全唐诗/poet.song.7000.json','["勝游生末跡，杳自狎時羣。", "卷衲消寒木，揚帆寄斷雲。", "曙瓶花外汲，午磬浪邊聞。", "别後石城月，依依遠共分。"]'),
('bc7178c1-cab8-4ee3-a928-9df6d526f13c','送僧','釋重顯','宋','宋诗','song-poetry','','[]','知方流古意，雲樹别諸鄰。',48,'全唐诗/poet.song.7000.json','["知方流古意，雲樹别諸鄰。", "月不澄微水，山應立是塵。", "靜空孤鶚遠，高柳一蟬新。", "欲究勞生問，歸思莫厭頻。"]'),
('452b8786-1cf5-48ca-9d87-c23b98a54007','千里不來','釋重顯','宋','宋诗','song-poetry','','[]','不見古君子，因循又隔秋。',48,'全唐诗/poet.song.7000.json','["不見古君子，因循又隔秋。", "浮生多自擲，好事更誰留。", "碧巘高沉月，寒雲靜鎖樓。", "宗雷何處是，白鳥下汀洲。"]'),
('bf5735d8-756b-4f05-b778-6a0463c72e52','僧歸霅上','釋重顯','宋','宋诗','song-poetry','','[]','海國浮輕檝，悠悠興未闌。',48,'全唐诗/poet.song.7000.json','["海國浮輕檝，悠悠興未闌。", "草隨春岸綠，風倚夜濤寒。", "沙鷺宜相狎，霜蟾望更寛。", "河聲西聼日，誰得共雲端。"]'),
('2441039d-976e-4412-9c97-044c4a12e0ed','春晴野步','釋重顯','宋','宋诗','song-poetry','','[]','乘興攜多士，遲遲傍水濆。',48,'全唐诗/poet.song.7000.json','["乘興攜多士，遲遲傍水濆。", "春山不在目，啼鳥共誰聞。", "片石寒籠蘚，殘花冷襯雲。", "只應融老輩，庵際境猶分。"]'),
('aa2bf01b-8718-4686-8434-c6a3576766ac','賦瑞雪送穆大師','釋重顯','宋','宋诗','song-poetry','','[]','五六皆名出，飄花獨見稀。',48,'全唐诗/poet.song.7000.json','["五六皆名出，飄花獨見稀。", "若教同一色，還似負羣機。", "玉馬猶空說，銅駝轉更非。", "爭如千萬里，相對共依依。"]'),
('2b0f4608-2b12-4d46-a689-f30edf190e2c','送鐡佛專使','釋重顯','宋','宋诗','song-poetry','','[]','荷策來尋我，泛舟思舊山。',48,'全唐诗/poet.song.7000.json','["荷策來尋我，泛舟思舊山。", "不知何處月，相照在深灣。", "風助秋濤急，雲兼野樹閑。", "到時如請益，先憶趙州關。"]'),
('f56dfdd8-2b8c-4471-8723-56db7ccad3f3','同于秘丞賦瀑泉','釋重顯','宋','宋诗','song-poetry','','[]','大禹不知鑿，來源亦自成。',48,'全唐诗/poet.song.7000.json','["大禹不知鑿，來源亦自成。", "色應鄰衆白，聲合讓孤清。", "遠勢曾吞海，飛流未噴鯨。", "靈槎如可泛，天派問歸程。"]'),
('28e43611-5f5a-4349-8e43-525cbfe42ce9','送簡能禪者歸仙都','釋重顯','宋','宋诗','song-poetry','','[]','荷策下丹嶂，紛紛雪正飛。',48,'全唐诗/poet.song.7000.json','["荷策下丹嶂，紛紛雪正飛。", "浮生誰未到，舊國自重歸。", "雲背猿聲斷，天遙鶚影微。", "蓮城古風月，又得振清機。"]'),
('c498178c-f98e-4943-bb86-8f1174671645','天竺送僧','釋重顯','宋','宋诗','song-poetry','','[]','雪霽蓮峰頂，孤禪起石牀。',48,'全唐诗/poet.song.7000.json','["雪霽蓮峰頂，孤禪起石牀。", "向時機自絕，異域路空長。", "啼狖衝寒影，歸鴻見斷行。", "後期無定跡，煙水共茫茫。"]'),
('ab50af43-9a79-40ee-af8d-c88bed39fbd0','寄石秘校','釋重顯','宋','宋诗','song-poetry','','[]','重林冥坐久，引望復遲遲。',48,'全唐诗/poet.song.7000.json','["重林冥坐久，引望復遲遲。", "煩暑未消日，涼風來幾時。", "天雲飛積火，巖溜散垂絲。", "欲擬相尋去，浮生已共知。"]'),
('a50a1e44-bde9-463b-81b8-6f343da63361','因事示衆','釋重顯','宋','宋诗','song-poetry','','[]','客從遠方來，遺我徑寸璧。',48,'全唐诗/poet.song.7000.json','["客從遠方來，遺我徑寸璧。", "中有四箇字，字字無人識。", "清涵鯨海寛，冷射蟾輪窄。", "今朝呈似看，請道末後句。"]'),
('3eabd745-69ed-4edd-aee1-36decf400c0c','靜而善應  其一','釋重顯','宋','宋诗','song-poetry','','[]','覿面相見，不在多端。',40,'全唐诗/poet.song.7000.json','["覿面相見，不在多端。", "龍蛇易辨，衲子難瞞。", "金槌影動，寶劍光寒。", "直下來也，急著眼看。"]'),
('e260982c-4559-45d4-bcdc-3f1933ffa550','靜而善應  其二','釋重顯','宋','宋诗','song-poetry','','[]','對揚殊特本同參，誰自遼空强指南。',32,'全唐诗/poet.song.7000.json','["對揚殊特本同參，誰自遼空强指南。", "今古不存師弟子，一輪秋月印寒潭。"]'),
('f67b7a66-2c21-4bff-a950-49d5d5054e4c','自誨','釋重顯','宋','宋诗','song-poetry','','[]','麟龍不爲瑞，草木生光輝。',36,'全唐诗/poet.song.7000.json','["麟龍不爲瑞，草木生光輝。", "三尺一丈六，且同攜手歸。", "慚爾懲世師，巍巍何巍巍。"]'),
('eb8ee956-024a-4f41-a5aa-5846fc461e90','宗門三印  其一','釋重顯','宋','宋诗','song-poetry','','[]','印空印水印泥，炳然字義還迷。',28,'全唐诗/poet.song.7000.json','["印空印水印泥，炳然字義還迷。", "黄頭大士不識，敢問誰得親提。"]'),
('e97b4dc8-822e-4d76-93b3-d8d1924eed1f','宗門三印  其二','釋重顯','宋','宋诗','song-poetry','','[]','印泥印空印水，匝地寒濤競起。',28,'全唐诗/poet.song.7000.json','["印泥印空印水，匝地寒濤競起。", "其中無限麟龍，幾處爭求出嘴。"]'),
('d0c9ffd8-2151-41f5-b7b8-e20495bbacc3','宗門三印  其三','釋重顯','宋','宋诗','song-poetry','','[]','印水印泥印空，衲子不辨西東。',28,'全唐诗/poet.song.7000.json','["印水印泥印空，衲子不辨西東。", "撥開向上一竅，千聖齊立下風。"]'),
('d9057e3a-40b3-4e73-8750-b2587f808627','革轍二門  其一','釋重顯','宋','宋诗','song-poetry','','[]','劫火曾洞然，木人淚先落。',24,'全唐诗/poet.song.7000.json','["劫火曾洞然，木人淚先落。", "可憐傅大士，處處失樓閣。"]'),
('ae5db0d7-3b4b-4ace-9fe2-407001aae23f','革轍二門  其二','釋重顯','宋','宋诗','song-poetry','','[]','德雲閑古錐，幾下妙峰頂。',24,'全唐诗/poet.song.7000.json','["德雲閑古錐，幾下妙峰頂。", "喚他癡聖人，擔雪共填井。"]'),
('93cf27ae-166a-4a89-a685-071b1f60a3f0','革轍二門  其三','釋重顯','宋','宋诗','song-poetry','','[]','祖佛未生前，已震塗毒鼓。',24,'全唐诗/poet.song.7000.json','["祖佛未生前，已震塗毒鼓。", "如今誰樂聞，請試分回互。"]'),
('e1c37e08-fea8-4b13-99fa-4b919e99394c','革轍二門  其四','釋重顯','宋','宋诗','song-poetry','','[]','宛轉復宛轉，真金休百鍊。',24,'全唐诗/poet.song.7000.json','["宛轉復宛轉，真金休百鍊。", "喪却毗耶離，無人解看箭。"]'),
