('a81fcc9f-4d1c-4e57-83b7-141c4168625b','送僧','釋重顯','宋','宋诗','song-poetry','','[]','巖泉高鎖黄金宅，衲卷秋雲古標格。',92,'全唐诗/poet.song.7000.json','["巖泉高鎖黄金宅，衲卷秋雲古標格。", "離歌誰贈欲行人，偏界同爲一宿客。", "春色依依日杲杲，南北東西好看好。", "閙市拶笑嬌尸迦，草頭青點俱胝老。", "呵呵呵，人間天上不知他。", "糲竭節有頂門眼，歸去清風拂薜蘿。"]'),
('c7a361c2-8e77-427c-a8ca-332dd5e026cb','寄李都尉','釋重顯','宋','宋诗','song-poetry','','[]','水月拈來作者殊，東西南北謾區區。',34,'全唐诗/poet.song.7000.json','["水月拈來作者殊，東西南北謾區區。", "也知金粟李居士，端坐重城笑老盧。", "咄。"]'),
('2fdb38bc-65f4-431d-ab05-e88e572bdf11','寄池陽曾學士','釋重顯','宋','宋诗','song-poetry','','[]','山萬重兮水萬枝，堆青流碧冷便宜。',32,'全唐诗/poet.song.7000.json','["山萬重兮水萬枝，堆青流碧冷便宜。", "筭來免得生遙恨，不在詩情在祖師。"]'),
('eb7d493c-2d81-45c1-bc0c-0e2164bf439f','寄四明使君沈祠部  其一','釋重顯','宋','宋诗','song-poetry','','[]','露冕民謠物物成，江山千里古風清。',32,'全唐诗/poet.song.7000.json','["露冕民謠物物成，江山千里古風清。", "曹溪客是無機者，日在深雲聽頌聲。"]'),
('682d5823-a41f-4b96-a741-fe04a59520fb','寄四明使君沈祠部  其二','釋重顯','宋','宋诗','song-poetry','','[]','蒼蒼德也亦如斯，政化全歸副倚毗。',32,'全唐诗/poet.song.7000.json','["蒼蒼德也亦如斯，政化全歸副倚毗。", "十萬人家寫春色，不知誰解立生祠。"]'),
('fea5b67f-7932-4664-a10e-2d5a4f16bf59','寄內侍太保  其一','釋重顯','宋','宋诗','song-poetry','','[]','千尺巖泉噴冷聲，草堂雲淡竹風清。',32,'全唐诗/poet.song.7000.json','["千尺巖泉噴冷聲，草堂雲淡竹風清。", "蒲團時倚無他事，永日寥寥謝太平。"]'),
('c7e8003e-dc9a-4f47-873b-8ac70db27183','寄內侍太保  其二','釋重顯','宋','宋诗','song-poetry','','[]','蘿龕蘚室狎猿猱，忽捧綸言挂紫袍。',32,'全唐诗/poet.song.7000.json','["蘿龕蘚室狎猿猱，忽捧綸言挂紫袍。", "恩大不知何以報，五雲天上望空勞。"]'),
('2455656d-ecbc-4e86-9bb1-801cfcbc53a2','寄曹都護','釋重顯','宋','宋诗','song-poetry','','[]','故國休言萬里程，爲官爲釋且分明。',32,'全唐诗/poet.song.7000.json','["故國休言萬里程，爲官爲釋且分明。", "道存不必曾傾蓋，俱有清風匝地生。"]'),
('833c8384-95c4-4c66-add7-9ab74cd52972','送僧','釋重顯','宋','宋诗','song-poetry','','[]','虎角深藏不待時，全機曾許雪林知。',32,'全唐诗/poet.song.7000.json','["虎角深藏不待時，全機曾許雪林知。", "如今百越拈來也，草偃風行是信旗。"]'),
('7a47a691-a34c-47fa-91cd-7287b237352c','寄靈隱惠明禪師  其一','釋重顯','宋','宋诗','song-poetry','','[]','千峰影裏葉初凋，極望還將慰寂寥。',32,'全唐诗/poet.song.7000.json','["千峰影裏葉初凋，極望還將慰寂寥。", "也謂毫端不相隔，秋雲秋水奈遙遙。"]'),
('5f2296fc-769b-4258-8a0a-756d0c857bd7','寄靈隱惠明禪師  其二','釋重顯','宋','宋诗','song-poetry','','[]','海嶠生片雲，有時忽如蓋。',24,'全唐诗/poet.song.7000.json','["海嶠生片雲，有時忽如蓋。", "不挂飛來峰，悠悠擬何待。"]'),
('748f8c90-27ff-49a4-ac3d-a0ed41dbc7f5','送益書記之霅水','釋重顯','宋','宋诗','song-poetry','','[]','白蘋汀是舊家鄉，歸興蘭舟泛渺茫。',32,'全唐诗/poet.song.7000.json','["白蘋汀是舊家鄉，歸興蘭舟泛渺茫。", "日暮沙禽啼欲斷，不知誰在碧雲房。"]'),
('a37383d0-5faa-4e6e-974a-f4673c17212b','三寶讚 佛寶','釋重顯','宋','宋诗','song-poetry','','[]','甘蔗流苗應刹塵，覺場高發利生因。',160,'全唐诗/poet.song.7000.json','["甘蔗流苗應刹塵，覺場高發利生因。", "紫金蓮捧千輪足，白玉毫飛萬德身。", "孤立大方資定惠，等觀含類捨怨親。", "挨星相好中天主，匝地名聞出世人。", "螺髪右旋仙島碧，月眉斜印海門新。", "鸞翔鳳舞非殊品，象轉龍蟠絕比倫。", "瓔絡聚中騰瑞色，花鬘影裏奪芳春。", "慈儀戀望知何極，梵德言辭莫可陳。", "胸字杳分無量義，頂珠常照百由旬。", "雙林孰謂歸圓寂，坐斷乾坤日見真。"]'),
('0abe8fbe-f6fc-4600-ba25-ee14b1ab5478','三寶讚 法寶','釋重顯','宋','宋诗','song-poetry','','[]','後得智生功德聚，大悲留演潤禽魚。',160,'全唐诗/poet.song.7000.json','["後得智生功德聚，大悲留演潤禽魚。", "貫花雖自科千品，標月還歸理一如。", "過量劫應期廣布，刹那心合未忘書。", "四衢道內抛紅焰，五欲波中綻白蕖。", "排斥衆魔登壽域，引攜諸子下安車。", "義天星象熒熒也，辭海波瀾浩浩歟。", "違背此恩難拯拔，遭逢末世豈躊躇。", "聞來半偈須相斆，惜去全身莫共居。", "飛辯恨曾虧激問，頤幽欣且免長噓。", "生生頂奉輝心鏡，廓照塵勞信有餘。"]'),
('34518734-d707-4e65-8f47-b7cd6256b966','三寶讚 僧寶','釋重顯','宋','宋诗','song-poetry','','[]','方袍圓頂義何宣，續焰千燈豈小緣。',160,'全唐诗/poet.song.7000.json','["方袍圓頂義何宣，續焰千燈豈小緣。", "花雨座前猶滯相，虎馴庵畔尚稽詮。", "巖栖塚宿難依望，鶴貌雲心迥灑然。", "寶杖夜鳴寒嶠月，銅瓶秋潄碧潭煙。", "名標練若澄諠猾，迹念昏衢警睡眠。", "林下雅爲方外客，人間堪作火中蓮。", "情高不是超三際，道在非同入四禪。", "浮世勉誰知逝水，深峰甘自聼飛泉。", "苾蒭草馥僧祇後，玳瑁盂傳古佛先。", "珍重覺皇有真子，坤維高步列金田。"]'),
('752c02d4-2d34-45ec-a5a0-9e0b8442361d','夏寄辯禪者山房','釋重顯','宋','宋诗','song-poetry','','[]','枕簟雲作屏，必固黄金宅。',48,'全唐诗/poet.song.7000.json','["枕簟雲作屏，必固黄金宅。", "軒窗月爲晝，豈止虛生白。", "麟龍愧頭角，鵰鶚慚羽翮。", "庶擬羣類心，在寛如在窄。"]'),
('6cb7ab02-d6a9-4c7a-aa72-5dbce5336632','和錢太博見寄覓山藥  其一','釋重顯','宋','宋诗','song-poetry','','[]','文柄誰持合自持，憂民風槩乍清羸。',32,'全唐诗/poet.song.7000.json','["文柄誰持合自持，憂民風槩乍清羸。", "禪林草藥如爲效，願見皇家急詔時。"]'),
('73b5cc2f-ad23-48d1-b6b5-58cbbbde5265','和錢太博見寄覓山藥  其二','釋重顯','宋','宋诗','song-poetry','','[]','聖君鴻業在扶持，日角龍章固不羸。',32,'全唐诗/poet.song.7000.json','["聖君鴻業在扶持，日角龍章固不羸。", "摛藻玉堂歸未晚，百花開赴御筵時。"]'),
('ffdf0109-b68b-411b-aef1-474cabd171b6','送錢太博應賢良選','釋重顯','宋','宋诗','song-poetry','','[]','賢才當召試，彪炳對吾君。',48,'全唐诗/poet.song.7000.json','["賢才當召試，彪炳對吾君。", "千古不遺恨，八元應主文。", "岸花明列斾，天籟拂微雲。", "後夜觀垂象，中台位已分。"]'),
('119464c6-df90-45db-9477-a4ece338952e','答天童新和尚','釋重顯','宋','宋诗','song-poetry','','[]','中峰深且寒，欹接海邊島。',120,'全唐诗/poet.song.7000.json','["中峰深且寒，欹接海邊島。", "松凋不死枝，花坼未萌草。", "飛瀑吼蛟宮，幽徑分鳥道。", "伊余空寂徒，浮光寄枯槁。", "冥遊天地間，誰兮可尋討。", "孤立雲霞外，誰兮可長保。", "兹來仁者來，還稱太白老。", "荷策扣巖扃，重席展懷抱。", "示我商頌清，休誇郢歌好。", "報投慚抒辭，難以論嘉藻。"]'),
('0b04080e-3673-4afd-b714-5e46ad27beb1','和頌','釋重顯','宋','宋诗','song-poetry','','[]','玲瓏巖古寺，冠乎明越境。',120,'全唐诗/poet.song.7000.json','["玲瓏巖古寺，冠乎明越境。", "海眼通洌泉，天心聳危嶺。", "嘗游興未闌，遐想神忽凝。", "彼士真覺雄，相鄰不孤迥。", "吾愛濟横流，孰云煩慮屏。", "吾愛整頺綱，豈止浮根靜。", "棲梧瑞九包，追風駿十影。", "顧我不爭衡，與誰閑鬭茗。", "乘時既磊落，照世非昏暝。", "佇爲王者師，三千統摩頂。"]'),
('8bbb92c8-39dd-410b-8dbe-30dd661b678d','贈别太臻禪者','釋重顯','宋','宋诗','song-poetry','','[]','武陵山水何秘邃，元化功兮不容易。',133,'全唐诗/poet.song.7000.json','["武陵山水何秘邃，元化功兮不容易。", "壇曾善卷韜龍光，洞亦桃花副麟趾。", "仍思昔日吾祖浩浩提綱宗，消息曠斷寰宇空。", "又聞高大舜讓公器，祥瑞却生蘆葦叢。", "人由境兮冥道德，境有人兮分玉石。", "臻禪本自偃殊方，忽向其中誕孤跡。", "迢迢海甸來尋我，一十二年同冷坐。", "羽翼摶風今是時，拂盡天雲乃飛過。"]'),
('a1e31a31-60c7-42a1-8b81-205f168668d3','雲門俱字','釋重顯','宋','宋诗','song-poetry','','[]','百草頭，何太極，重與禪徒下錐刺。',84,'全唐诗/poet.song.7000.json','["百草頭，何太極，重與禪徒下錐刺。", "雲門俱字好參詳，雪峰輥毬亦端的。", "黛非青兮藍一色，辰錦砂兮敢言赤。", "紫羅帳裏有真珠，曹溪路上生荆棘。", "還會麽，此時若不究根源，直向當來問彌勒。"]'),
('d0e83166-1ff9-4e69-9dec-5456f75d39c0','僧問四賓主因而有頌頌之  其一','釋重顯','宋','宋诗','song-poetry','','[]','如何是賓中賓。',17,'全唐诗/poet.song.7000.json','["如何是賓中賓。", "云滿面埃塵，又曰噫。"]'),
('a5756b1a-3179-473b-9d20-5e3efc1fc153','僧問四賓主因而有頌頌之  其二','釋重顯','宋','宋诗','song-poetry','','[]','賓中之賓，少喜多瞑。',20,'全唐诗/poet.song.7000.json','["賓中之賓，少喜多瞑。", "丈夫壯志，當付何人。"]'),
('7fd0fb1a-2ef6-4cba-a45f-66768648474d','僧問四賓主因而有頌頌之  其三','釋重顯','宋','宋诗','song-poetry','','[]','如何是賓中主。',17,'全唐诗/poet.song.7000.json','["如何是賓中主。", "云兆分其五，又曰引。"]'),
('91a94171-e9a3-41ca-be64-5b9d5295be68','僧問四賓主因而有頌頌之  其四','釋重顯','宋','宋诗','song-poetry','','[]','賓中之主，玄沙猛虎。',20,'全唐诗/poet.song.7000.json','["賓中之主，玄沙猛虎。", "半合半開，唯自相許。"]'),
('f87708b2-b086-42bd-8b02-edf15f2beb8a','僧問四賓主因而有頌頌之  其五','釋重顯','宋','宋诗','song-poetry','','[]','如何是主中賓。',17,'全唐诗/poet.song.7000.json','["如何是主中賓。", "云月带重輪，又曰收。"]'),
('fc3e8f7d-55b0-4058-91ee-9764dfc0dad0','僧問四賓主因而有頌頌之  其六','釋重顯','宋','宋诗','song-poetry','','[]','主中之賓，温故知新。',20,'全唐诗/poet.song.7000.json','["主中之賓，温故知新。", "互換相照，師子嚬呻。"]'),
('7fb52a7f-6f7d-4345-8859-62216fbdaee5','僧問四賓主因而有頌頌之  其七','釋重顯','宋','宋诗','song-poetry','','[]','如何是主中主。',17,'全唐诗/poet.song.7000.json','["如何是主中主。", "云大千捏聚，又曰掲。"]'),
('9fa614b7-ec07-4163-8a04-eeec2a8dd563','僧問四賓主因而有頌頌之  其八','釋重顯','宋','宋诗','song-poetry','','[]','主中之主，正令齊舉。',20,'全唐诗/poet.song.7000.json','["主中之主，正令齊舉。", "長劍倚天，誰敢當禦。"]'),
('792b0e25-f3a5-4d5e-b288-ba3ca6c3bbab','僧問四賓主因而有頌頌之  其九','釋重顯','宋','宋诗','song-poetry','','[]','賓主分不分，顢頇絕異聞。',24,'全唐诗/poet.song.7000.json','["賓主分不分，顢頇絕異聞。", "解布勞生手，寄言來白雲。"]'),
('30f82b0d-c980-4eb8-a6bc-3c48a6f7c57e','令僧把衲','釋重顯','宋','宋诗','song-poetry','','[]','七八既難，直須教透。',46,'全唐诗/poet.song.7000.json','["七八既難，直須教透。", "來不在前，去不在後。", "麤細自看，緊緩相就。", "一日圓成呈似君，想得諸方未知有。"]'),
('8ece2ad4-78fd-4053-b858-4ed20c00bd94','送知一入京兼簡清河從事','釋重顯','宋','宋诗','song-poetry','','[]','六月干江水似秋，片帆高挂岸雲收。',32,'全唐诗/poet.song.7000.json','["六月干江水似秋，片帆高挂岸雲收。", "行行莫謂朝天闕，況倚文星在巨舟。"]'),
('f803ca3c-9512-4829-9dc3-379eebc8e1de','送德珉山主','釋重顯','宋','宋诗','song-poetry','','[]','溪山春色映雲袍，愛住隍城意轉高。',32,'全唐诗/poet.song.7000.json','["溪山春色映雲袍，愛住隍城意轉高。", "翻笑忘機自安者，不能垂手入塵勞。"]'),
('79bb8c70-7741-4c2e-9f70-1515944aa57b','送僧  其一','釋重顯','宋','宋诗','song-poetry','','[]','紅芍藥邊方舞蝶，碧梧桐裏正啼鶯。',32,'全唐诗/poet.song.7000.json','["紅芍藥邊方舞蝶，碧梧桐裏正啼鶯。", "離亭不折依依柳，況有春山送又迎。"]'),
('32c894e2-b940-4a01-9cb6-c871aa5eb3a5','送僧  其二','釋重顯','宋','宋诗','song-poetry','','[]','祖域高親日未央，家林歸去意何長。',32,'全唐诗/poet.song.7000.json','["祖域高親日未央，家林歸去意何長。", "舊交不識初相見，曾振滄溟奪夜光。"]'),
('386cc0d7-761f-456c-862c-f6e01ff88d06','送崇己闍黎歸天台','釋重顯','宋','宋诗','song-poetry','','[]','石橋雲瀑冷相侵，蘚徑蘿龕入更深。',32,'全唐诗/poet.song.7000.json','["石橋雲瀑冷相侵，蘚徑蘿龕入更深。", "却羨搘筇遠歸去，半千尊者是知音。"]'),
('1628f786-42c2-45c2-b13f-12d5f6763ef5','送邃悟上人之會稽','釋重顯','宋','宋诗','song-poetry','','[]','百越江山冠九州，如屏還愧謾相褒。',32,'全唐诗/poet.song.7000.json','["百越江山冠九州，如屏還愧謾相褒。", "惠休此去多吟賞，嬴得清風價轉高。"]'),
