('f6624b56-8828-43fc-9fb7-6ab4bf71f105','喜禪人迴山','釋重顯','宋','宋诗','song-poetry','','[]','别我遊方意未論，瓶盂還喜到雲根。',32,'全唐诗/poet.song.7000.json','["别我遊方意未論，瓶盂還喜到雲根。", "舊巖房有安禪石，再折松枝拂蘚痕。"]'),
('895833ad-c1eb-4742-a7f1-c61649822100','送僧','釋重顯','宋','宋诗','song-poetry','','[]','七尺巖藤握便行，舊山歸去幾多程。',32,'全唐诗/poet.song.7000.json','["七尺巖藤握便行，舊山歸去幾多程。", "相逢忽問迢迢意，應發春雷動地聲。"]'),
('ad06c42e-bc82-42be-b1b6-caf7176ca091','送僧歸天童','釋重顯','宋','宋诗','song-poetry','','[]','峨峨太白峰，倚翠列霄岸。',24,'全唐诗/poet.song.7000.json','["峨峨太白峰，倚翠列霄岸。", "羨君乘興歸，凭欄與誰看。"]'),
('c6f77c15-ed65-4b69-85c2-e3fa0ce80238','和曾推官示嘉遁之什','釋重顯','宋','宋诗','song-poetry','','[]','少微星出古風還，匝地聲光不掩關。',64,'全唐诗/poet.song.7000.json','["少微星出古風還，匝地聲光不掩關。", "三館峻遷同陌路，九華高卧是蓬山。", "巖莎步入祥麟稳，海樹飛求白鳳閑。", "祗恐致君休未得，蒲輪重到薜蘿間。"]'),
('80452579-23d4-42dd-9d0e-df6909c37ed0','經古堰偶作','釋重顯','宋','宋诗','song-poetry','','[]','出城四十里，古堰若天外。',24,'全唐诗/poet.song.7000.json','["出城四十里，古堰若天外。", "飛棹清淺中，孤影自相對。"]'),
('e838dae9-5605-4af1-8507-b76c6f0bc933','謝張太保見訪','釋重顯','宋','宋诗','song-poetry','','[]','老病還同葉半凋，經旬門掩夜蕭蕭。',32,'全唐诗/poet.song.7000.json','["老病還同葉半凋，經旬門掩夜蕭蕭。", "海城都護曾垂訪，一片清風慰寂寥。"]'),
('f528c564-8cdb-4900-a4bf-195d6d9927f8','送宗朴禪者','釋重顯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭乳竇皆泉石，抱疾何緣寄幽跡。',96,'全唐诗/poet.song.7000.json','["洞庭乳竇皆泉石，抱疾何緣寄幽跡。", "曾列狂機一二三，東山西嶺非相識。", "屈指嚬眉不可尋，雲飛雨散空沈沈。", "如今轉覺流年隔，强把冥悰苦搜索。", "縱止言欺白雪辭，寧忘笑與黄梅客。", "朴禪者，朴禪者，珠月有光慚照夜。"]'),
('634c6acd-1831-4e4b-a936-3acb93189f38','送尚辭','釋重顯','宋','宋诗','song-poetry','','[]','浮圖之子，履道爲貴。',40,'全唐诗/poet.song.7000.json','["浮圖之子，履道爲貴。", "天兮地兮，何泰何否。", "動無飾非，靜還雕僞。", "辭也云行，後生可畏。"]'),
('fb3525ee-b66f-40ca-9dd4-e58d2b351134','歌寄留英禪德','釋重顯','宋','宋诗','song-poetry','','[]','當時臨際辭黄蘗，或指河南或河北。',80,'全唐诗/poet.song.7000.json','["當時臨際辭黄蘗，或指河南或河北。", "英禪此日下中峰，機案曾焚笑仍則。", "九包一角慚稱瑞，導月觀星亦非意。", "爭以韶陽振古風，半途未肯還希冀。", "歸去來，歸去來，飛泉浩浩聲如雷。"]'),
('d53c8ddd-d67c-4189-8cd9-60c3c4425fae','送小師元賁','釋重顯','宋','宋诗','song-poetry','','[]','愧爾求師，爲吾弟子。',48,'全唐诗/poet.song.7000.json','["愧爾求師，爲吾弟子。", "學雖無聞，道亦可擬。", "平飛辯月，照復流水。", "斯意斯言兮如不忘，行行𩖼𩖼兮步蘭芷。"]'),
('8fddb1e3-bd96-4941-b13a-be8737052e71','送文佶歸廬岳','釋重顯','宋','宋诗','song-poetry','','[]','春色未深，興無遲早。',36,'全唐诗/poet.song.7000.json','["春色未深，興無遲早。", "瓶謝九江，峰尋五老。", "到日攀蘿獨上時，依依莫忘海山腦。"]'),
('067d5529-a52a-46a8-a3f7-282650c8319b','送侃禪者之丹丘','釋重顯','宋','宋诗','song-poetry','','[]','石橋多古跡，路嶮少人過。',36,'全唐诗/poet.song.7000.json','["石橋多古跡，路嶮少人過。", "如同白日閑，冷拂青苔坐。", "寒老若相逢，爲吾略嘲破。"]'),
('db6591c8-8b28-49d5-ab52-0ff9b454178e','送實山主','釋重顯','宋','宋诗','song-poetry','','[]','野水春山，風光極目。',58,'全唐诗/poet.song.7000.json','["野水春山，風光極目。", "千里萬里，太遲太速。", "絕域澄澄兮非犀炬可照，希聲杳杳兮非鳳膠可續。", "葉落花開知不知，人天景行爲高躅。"]'),
('b139b5a0-35a7-482a-ac5d-d72c319e4691','示衆','釋重顯','宋','宋诗','song-poetry','','[]','丫角女子白頭絲，報你諸方作者知。',48,'全唐诗/poet.song.7000.json','["丫角女子白頭絲，報你諸方作者知。", "借問住山何境界，春風𩖼𩖼，春鳥喧喧。", "翠峰不能助發，心印却是他傳。"]'),
('75633a96-4c13-46b1-9028-48616447b1be','和范監簿  其一','釋重顯','宋','宋诗','song-poetry','','[]','吏散簾垂思莫窮，山光溪影恣相容。',64,'全唐诗/poet.song.7000.json','["吏散簾垂思莫窮，山光溪影恣相容。", "誰誇靖節偏栽柳，自笑隱居高聽松。", "丹闕尚遙芝檢密，訟庭閑列蘚花重。", "巖間野客雖多病，終再攜筇謁士龍。"]'),
