('f23a68bd-7d1e-4eb8-b25a-35179212362b','酬李校書','釋重顯','宋','宋诗','song-poetry','','[]','一回辭我一回吟，睠戀巖叢意轉深。',32,'全唐诗/poet.song.7000.json','["一回辭我一回吟，睠戀巖叢意轉深。", "翻謝霜松不凋落，與君同有歲寒心。"]'),
('17665623-bef3-42b4-a62d-2df9a1029509','苦熱中懷寄永固山主','釋重顯','宋','宋诗','song-poetry','','[]','火雲高下影相連，幾欲披尋恨不前。',32,'全唐诗/poet.song.7000.json','["火雲高下影相連，幾欲披尋恨不前。", "無限清風無處問，只應遲步遶林泉。"]'),
('7d8dd296-0c29-42ab-8e64-5a846e1de258','送元安禪者','釋重顯','宋','宋诗','song-poetry','','[]','羣峰杳藹留不住，遠道依依祇藤屨。',32,'全唐诗/poet.song.7000.json','["羣峰杳藹留不住，遠道依依祇藤屨。", "舊隱蘿龕付與誰，寒猿後夜啼高樹。"]'),
('183bed4e-73eb-45ba-93b3-943db7337255','賦病鶴送奉倫禪者','釋重顯','宋','宋诗','song-poetry','','[]','欲飛飛未得，冷泊杉松枝。',24,'全唐诗/poet.song.7000.json','["欲飛飛未得，冷泊杉松枝。", "如何垂天雲，遠遠同一涯。"]'),
('35c76578-6e3e-4e70-8485-bbd75d7eb594','偶作','釋重顯','宋','宋诗','song-poetry','','[]','列岫霽新雨，凭欄秪澹交。',48,'全唐诗/poet.song.7000.json','["列岫霽新雨，凭欄秪澹交。", "夕陽明遠水，秋葉露空巢。", "思極曾無玷，神清未動爻。", "祇應千古意，誰得共雲坳。"]'),
('b2a2cc21-d0ad-480f-ad5c-5941fdd88d9e','謝鮑學士惠臘茶','釋重顯','宋','宋诗','song-poetry','','[]','叢卉乘春獨讓靈，建溪從此振家聲。',32,'全唐诗/poet.song.7000.json','["叢卉乘春獨讓靈，建溪從此振家聲。", "使君分賜深深意，曾滌禪曹萬慮清。"]'),
('fc64bb7f-5f3c-4f99-b87d-154d89dfb136','因遊育王亭寄收主郎給事','釋重顯','宋','宋诗','song-poetry','','[]','冷翠千萬峰，當軒列如黛。',48,'全唐诗/poet.song.7000.json','["冷翠千萬峰，當軒列如黛。", "蒲團及禪板，永日澹相對。", "彤雲曾無機，燒松亦成蓋。", "遠謝幽隱情，難與台星會。"]'),
('17c0135f-cb76-4625-b380-1720abef1f60','送遇能禪者','釋重顯','宋','宋诗','song-poetry','','[]','湖遶巖城列象寛，萬家臺榭水光寒。',32,'全唐诗/poet.song.7000.json','["湖遶巖城列象寛，萬家臺榭水光寒。", "片帆隱隱生遙極，誰問曹溪意轉難。"]'),
('f49fbc24-b73a-406b-8b11-c6c2f028bddd','送覺海大師','釋重顯','宋','宋诗','song-poetry','','[]','秋雲巖葉兩悠悠，半逐風馳半水流。',32,'全唐诗/poet.song.7000.json','["秋雲巖葉兩悠悠，半逐風馳半水流。", "憑問禪家有何意，不知方外若爲酬。"]'),
('b3c0aca8-e6e5-462c-befb-12f161705ddb','送曾侍禁','釋重顯','宋','宋诗','song-poetry','','[]','冷匣秋波射斗星，鐡衣隨從古霜清。',32,'全唐诗/poet.song.7000.json','["冷匣秋波射斗星，鐡衣隨從古霜清。", "宣池莫問當年事，一片威風動地生。"]'),
('83fa1531-b0dc-4eed-b7ea-ea4be54e7f1b','病起酬如禪德','釋重顯','宋','宋诗','song-poetry','','[]','大明一寸光，腐草一何假。',48,'全唐诗/poet.song.7000.json','["大明一寸光，腐草一何假。", "人命呼吸間，誠哉是言也。", "呼之曾已休，吸之尚未舍。", "寄問諸苦源，來者不來者。"]'),
('9411ba27-c6c2-435a-8490-5958d82c9c54','送雲禪德','釋重顯','宋','宋诗','song-poetry','','[]','古之送人，言作懷寶。',56,'全唐诗/poet.song.7000.json','["古之送人，言作懷寶。", "我慚老病，困乏辭藻。", "熊嶺迢迢兮曾立夜雪，謝池依依兮笑生春草。", "頭角麟龍安可論，清風步步應相討。"]'),
('131edd0e-e255-4990-80df-d244c7aad1a1','送久禪德歸蘭亭','釋重顯','宋','宋诗','song-poetry','','[]','右軍墨池月，照我復照誰。',24,'全唐诗/poet.song.7000.json','["右軍墨池月，照我復照誰。", "千里忽相到，中峰多病師。"]'),
('aab5d9bc-7183-4010-899d-4e4fe9616ac5','送羲大師','釋重顯','宋','宋诗','song-poetry','','[]','巖房抱病經一月，門有諸生阻來謁。',98,'全唐诗/poet.song.7000.json','["巖房抱病經一月，門有諸生阻來謁。", "長往之期猶未能，七十之年更何說。", "若耶溪老忽留語，溪上舊遊且歸去。", "春風𩖼𩖼兮兼斷雲，弱柳依依兮带輕絮。", "古今離恨雖如此，動靜於吾亦多意。", "高握霜筇獨步時，音書莫忘遠飛寄。"]'),
('e482fdfe-341a-4cb2-a0d7-c04e3ef77f6b','酬海宗二侍者  其一','釋重顯','宋','宋诗','song-poetry','','[]','蓀之得蘭，其道匪難。',30,'全唐诗/poet.song.7000.json','["蓀之得蘭，其道匪難。", "扶吾病起，如珠在盤。", "一兮二兮，自看誰看。"]'),
('53cd5a29-6090-4c92-9a2e-c35254f0c4eb','酬海宗二侍者  其二','釋重顯','宋','宋诗','song-poetry','','[]','蘭之得蓀，其道必存。',30,'全唐诗/poet.song.7000.json','["蘭之得蓀，其道必存。", "扶吾病起，古風入門。", "二兮一兮，且論勿論。"]'),
('afbe0b97-5b63-4d35-b3ff-bf1d75e71491','謝郎給事送建茗','釋重顯','宋','宋诗','song-poetry','','[]','陸羽仙經不易誇，詩家珍重寄禪家。',32,'全唐诗/poet.song.7000.json','["陸羽仙經不易誇，詩家珍重寄禪家。", "松根石上春光裏，瀑水烹來鬭百花。"]'),
('a596b17b-c4e3-4057-ba57-7ecad59a2786','送山茶上知府郎給事','釋重顯','宋','宋诗','song-poetry','','[]','穀雨前收獻至公，不爭春力避芳叢。',32,'全唐诗/poet.song.7000.json','["穀雨前收獻至公，不爭春力避芳叢。", "煙開曾入深深搗，百萬槍旗在下風。"]'),
('a42df169-a905-4157-ac44-4943b2c0418d','送郎侍郎致政歸錢塘','釋重顯','宋','宋诗','song-poetry','','[]','帆挂西風别海城，二疏千古道相應。',64,'全唐诗/poet.song.7000.json','["帆挂西風别海城，二疏千古道相應。", "誰誇富貴沽時譽，自笑經綸作技能。", "殘葉賦題紅片片，遠山供望碧層層。", "武林到日符嘉遁，高訪巖扃祇許僧。"]'),
('5580dc24-3b88-451b-89cd-c58657c63843','山行逢懃禪德','釋重顯','宋','宋诗','song-poetry','','[]','乳巖秋日無他作，策杖層層止寥廓。',78,'全唐诗/poet.song.7000.json','["乳巖秋日無他作，策杖層層止寥廓。", "四顧有語分野情，一點彤雲起深壑。", "蘚石遲遲略輕踞，逢箇衲僧忽驟步。", "頻喚回頭不肯回，及至回兮眉卓竪。", "阿喇喇，千里萬里横該抹。", "咄。"]'),
('bce09d5e-c29c-46c5-b453-7120744ff26b','送小師元哲','釋重顯','宋','宋诗','song-poetry','','[]','老盧之子，四三二一。',44,'全唐诗/poet.song.7000.json','["老盧之子，四三二一。", "將欲振飛，卷比叢室。", "松凌霜兮運青，水带巖兮流急。", "南北東西，雲開見日。"]'),
('98e5fd22-cd41-4947-9c45-655dadf12c66','永豐莊新植徑松忽二本鄰偃抒辭紀之','釋重顯','宋','宋诗','song-poetry','','[]','雙偃松何似，螺文結數遭。',48,'全唐诗/poet.song.7000.json','["雙偃松何似，螺文結數遭。", "清聲雖競發，寒影不相高。", "對客圓分蓋，孤禪翠滴袍。", "若教圖畫得，爭奈有蕭搔。"]'),
('c6ce5a47-eaa0-43bd-a1d2-17053b532d44','送白雲宣長老','釋重顯','宋','宋诗','song-poetry','','[]','鄞江秋晚忽成春，況有台星作主人。',32,'全唐诗/poet.song.7000.json','["鄞江秋晚忽成春，況有台星作主人。", "去去高攜古刀尺，二千年運續芳塵。"]'),
('6c8623f4-013c-4071-916a-b8282a38772d','送親禪者','釋重顯','宋','宋诗','song-poetry','','[]','萬木带秋聲，古今念暌别。',48,'全唐诗/poet.song.7000.json','["萬木带秋聲，古今念暌别。", "我有贈行意，臨行爲君說。", "重巖休滯雲，遠水且觀月。", "生生知不知，天風助清徹。"]'),
('5f0b3494-e23f-4c25-b1da-664ffd0d2174','送顯冲禪者','釋重顯','宋','宋诗','song-poetry','','[]','聚散非常凖，古今亦標格。',60,'全唐诗/poet.song.7000.json','["聚散非常凖，古今亦標格。", "如何無事人，還似未歸客。", "秋風生羣林，野水資寒色。", "誰兮謝寸陰，觀彼青山白。", "冲禪行復行，五葉待時折。"]'),
('8b258b22-2d90-47fa-9e50-cac13ada34dc','送天童普和尚','釋重顯','宋','宋诗','song-poetry','','[]','迢迢别海涯，帆挂杪秋時。',48,'全唐诗/poet.song.7000.json','["迢迢别海涯，帆挂杪秋時。", "島樹落寒葉，人誰訪祖師。", "浪開遊象急，天闊過鴻遲。", "早晚歸林下，千徒不共知。"]'),
('8ae6bf3d-5896-4e35-b213-be5809620bb6','張秀才下第','釋重顯','宋','宋诗','song-poetry','','[]','得第何人愧不平，道存顔巷亦爲榮。',32,'全唐诗/poet.song.7000.json','["得第何人愧不平，道存顔巷亦爲榮。", "應知未喪斯文也，且把新詩樂性情。"]'),
('894b001c-140e-41c4-8b57-d1ed45daf66b','寄久監收','釋重顯','宋','宋诗','song-poetry','','[]','田中稻熟及時收，顆立圓成免外求。',32,'全唐诗/poet.song.7000.json','["田中稻熟及時收，顆立圓成免外求。", "一日歸來古巖上，白雲紅樹共悠悠。"]'),
('cbe8a63c-3c90-4785-828e-7bc949620d16','暮冬夜坐寄岫禪者','釋重顯','宋','宋诗','song-poetry','','[]','碧落無片雲，虚庭積深雪。',60,'全唐诗/poet.song.7000.json','["碧落無片雲，虚庭積深雪。", "負春還有誰，徹曙對孤月。", "巖松影拂翠不斷，瀑水聲來聽忽絕。", "岫禪岫禪知也如未知，八面清風遠遠待時說。"]'),
('1456959c-977c-4d4e-a24b-e4a412b3f6f1','寄崇壽懷長老歌','釋重顯','宋','宋诗','song-poetry','','[]','寂住峰兮觸星斗，寂住師兮古爲道。',128,'全唐诗/poet.song.7000.json','["寂住峰兮觸星斗，寂住師兮古爲道。", "死中得活未輕酬，不許夜行投曉到。", "藹藹聲光一百年，吾其後兮吾其先。", "振領提綱笑多事，掩扉塞路空依然。", "龍朔老盧同兀兀，土爲貌兮金作骨。", "萬國爭求肯便行，我要重新敲鐡佛。", "東西南北休云識，枯槁冥冥頗相憶。", "天外清風結陣來，狂歌遠寄從抛擲。"]'),
('db10b7ce-cff1-47d1-8e9b-629641543df6','送廷利禪者','釋重顯','宋','宋诗','song-poetry','','[]','雷峰孤頂誰家路，上兮下兮復何故。',96,'全唐诗/poet.song.7000.json','["雷峰孤頂誰家路，上兮下兮復何故。", "曾列三千一半徒，我今獨滿當時數。", "鯨麟麟，龍鱗鱗，坤維高步生清塵。", "休云裴相慕黄蘗，額有圓珠七尺身。", "利禪者，利禪者，倚天長劍應牢把。", "或謂風雲不再來，誰爲蒼蒼分晝夜。"]'),
('9cd93628-3e13-4449-a662-4d71812a079d','送倧禪者','釋重顯','宋','宋诗','song-poetry','','[]','涪江怒激鯨鼇宅，岌岌三山大傾側。',136,'全唐诗/poet.song.7000.json','["涪江怒激鯨鼇宅，岌岌三山大傾側。", "冥數俄然一箇來，步武羣方作禪客。", "振聲謂我分綱宗，今兮古兮何忩忩。", "令吾强爲抉辭句，句句字字凜凜生狂風。", "拂散四七單傳之落葉，掃蕩二三直指之流蓬。", "似带微芒，敢未勦絕。", "寒木在握兮全機可笑，秋水横按兮半提可滅。", "使八極頂目者不自爭衡，見斯人兮駕御昂枿。"]'),
('6257a6c8-876a-454f-bb0c-7ca0c31cf742','送鼎禪者','釋重顯','宋','宋诗','song-poetry','','[]','落落禪家流，攜筇卷雲毳。',60,'全唐诗/poet.song.7000.json','["落落禪家流，攜筇卷雲毳。", "别我振辭鋒，夜堂消祖偈。", "霜天飛一鶚，目對彈其滯。", "春岸立千峰，指也乎其勢。", "行行復行行，清飇起蘭蕙。"]'),
('0fb33ac3-130e-49a1-9b96-2721f12c9180','觀泉送演禪者','釋重顯','宋','宋诗','song-poetry','','[]','雲根漱野泉，照空復照月。',52,'全唐诗/poet.song.7000.json','["雲根漱野泉，照空復照月。", "冷聲曾未消，飛瀾似相别。", "巖近生風雷，天遙新冰雪。", "演禪乘與知不知，源流依依共澄潔。"]'),
('f18532bc-bbc4-419b-a6aa-930bf01a056c','答忠禪者','釋重顯','宋','宋诗','song-poetry','','[]','一字七字三五字，萬象窮來不爲據。',32,'全唐诗/poet.song.7000.json','["一字七字三五字，萬象窮來不爲據。", "夜深月白下滄溟，搜得驪珠有多許。"]'),
('af231642-9e2b-468a-bc3f-5b08091544cf','和陸學士夏日見寄','釋重顯','宋','宋诗','song-poetry','','[]','良牧歸詩匠，雅風消鬱蒸。',48,'全唐诗/poet.song.7000.json','["良牧歸詩匠，雅風消鬱蒸。", "官清難滯爵，吏散遠同僧。", "棠樹非煙合，仙槎碧浪乘。", "因思窮萬化，千古更無能。"]'),
('c4c91b8f-aff0-4f24-a02f-c14a9ae0904d','送化主','釋重顯','宋','宋诗','song-poetry','','[]','春色依依籠遠樹，卷衲搘藤墀輕屨。',32,'全唐诗/poet.song.7000.json','["春色依依籠遠樹，卷衲搘藤墀輕屨。", "塵世茫茫無限人，不知誰問曹溪路。"]'),
('07e5dbe4-b111-4044-9746-13d2fec2e86c','送通判劉國博','釋重顯','宋','宋诗','song-poetry','','[]','爲星當貳職，權化不相饒。',48,'全唐诗/poet.song.7000.json','["爲星當貳職，權化不相饒。", "白屋如多恨，清風何處消。", "岸鷗窺列斾，天辟看陞朝。", "别有生靈意，寒枝未變條。"]'),
('7ddcd52f-0516-4c86-8c58-5fd402361faa','送别陳秘丞古意','釋重顯','宋','宋诗','song-poetry','','[]','悠悠層山雲，斷兮仍復續。',72,'全唐诗/poet.song.7000.json','["悠悠層山雲，斷兮仍復續。", "離離雙岸草，變兮且兼綠。", "如何苦雪霜，後凋蠧松竹。", "松竹有節操，雪霜無伎倆。", "敢折歲寒枝，贈君作嘉賞。", "行行天地間，清風在誰掌。"]'),
('2e01544f-7c47-49d7-b483-8dc3ecb97ddc','送通判學士歸南國','釋重顯','宋','宋诗','song-poetry','','[]','斾擁帆開照德星，天風高興國風清。',32,'全唐诗/poet.song.7000.json','["斾擁帆開照德星，天風高興國風清。", "武夷仙仗知回也，各下祥雲到地迎。"]'),
('5390b2b9-07f9-4cbc-86c3-8df35845adfb','和酬郎簽判殿丞','釋重顯','宋','宋诗','song-poetry','','[]','向國心存了了身，大方無外且同塵。',32,'全唐诗/poet.song.7000.json','["向國心存了了身，大方無外且同塵。", "江城早晚重相見，解笑宗雷十八人。"]'),
('6deec5cb-7724-40c9-adec-c01742978ec9','歌送范陽盧君','釋重顯','宋','宋诗','song-poetry','','[]','范陽居士來鄞水，動地仙飇向人起。',128,'全唐诗/poet.song.7000.json','["范陽居士來鄞水，動地仙飇向人起。", "乳峰直上雲霞開，步驟大衢到如此。", "茫茫塵世誰知交，當場問我非相饒。", "禪家畢竟無他事，古雪巖前曾未消。", "俄然悵望辭叢室，荷負難兮淚深溢。", "遠幸流方且莫論，再得從容又何日。", "迢迢故國殊存想，冷碧柯山分指掌。", "況有覺雄華藏師，歸去百城共游賞。"]'),
('56249180-0e58-41f7-b0a0-3f6ac26a2ad9','送廣教專使','釋重顯','宋','宋诗','song-poetry','','[]','峨峨石頭，使乎讓祖。',49,'全唐诗/poet.song.7000.json','["峨峨石頭，使乎讓祖。", "已之匪存，聖之奚慕。", "或妄以山，或索云斧。", "音耗不通兮清源派分，吾斯語兮詎可論古。"]'),
('0cbdb692-79b7-4dd1-9b54-22325eb2936d','送微文章','釋重顯','宋','宋诗','song-poetry','','[]','雙蓮亭上送行客，菡萏清香散秋色。',151,'全唐诗/poet.song.7000.json','["雙蓮亭上送行客，菡萏清香散秋色。", "野興斷山雲片高，孤影澄江月華白。", "希聲險絕堪誰知，大道機存曾未可。", "縱闢天常立下風，安教類變叢流火。", "君不見梁兮闔國難滯留，千古遺恨空悠悠。", "君又不見魏兮小桂生寒翠，一花對雪開無休。", "微禪亦並聯芳駕，德星文星仰蕭灑。", "物外情深不等閑，環中趣别非輕捨。", "相訪從容爲我言，屈指多求更何者。"]'),
('e133bc5b-dcce-4b6b-ade2-d838913d9d3d','送懷秀禪者','釋重顯','宋','宋诗','song-poetry','','[]','麻衣草座思靈徹，一食安閑更無别。',144,'全唐诗/poet.song.7000.json','["麻衣草座思靈徹，一食安閑更無别。", "儵忽遷流數百年，杳杳誰來繼其絕。", "吾兮亦是疏慵輩，冷淡身心存慷愷。", "偶續靈峰照夜燈，邃泛鐡船下滄海。", "深嗟知困不知休，奔馳駭浪空淹留。", "縱得長鼇擬何待，堪白頭時好白頭。", "因觀壞衲秀禪客，清苦如冰復如蘗。", "别我攜筇步大方，爲葉爲花恣披折。", "伏枕寥寥情意闌，率寫狂歌贈行色。"]'),
('2330dd14-bd4a-44f9-acdc-005927232be4','孤運銘','釋重顯','宋','宋诗','song-poetry','','[]','雲根石壙，容身待老。',38,'全唐诗/poet.song.7000.json','["雲根石壙，容身待老。", "南來北來，閑且尋討。", "五葉一花兮堪對誰，寥寥萬古兮空知有。"]'),
('705eed6e-6d0a-4512-ab78-d525de6624df','寄海會之長老','釋重顯','宋','宋诗','song-poetry','','[]','百花開後一花開，風遞清香遠遠來。',32,'全唐诗/poet.song.7000.json','["百花開後一花開，風遞清香遠遠來。", "誰問黄梅不平事，照中依舊惹塵埃。"]'),
('d923ecc9-0c9d-4f0a-90e5-5f6f8bebb8ff','雜言送賢專使','釋重顯','宋','宋诗','song-poetry','','[]','使乎誰，老作者，百戰場中飛鐡馬。',44,'全唐诗/poet.song.7000.json','["使乎誰，老作者，百戰場中飛鐡馬。", "秋水藏來人不知，笑李將軍被擒下。", "阿呵呵，却歸湖山唱凱歌。"]'),
('cc6eb335-d6b7-4e0e-9d3e-aaec2d04a540','歌紀四明汪君信士','釋重顯','宋','宋诗','song-poetry','','[]','古君子兮道諸己，道器用兮合天理。',128,'全唐诗/poet.song.7000.json','["古君子兮道諸己，道器用兮合天理。", "同塵還若待時生，觀象不知何處起。", "荆叢叢襲莪叢叢，孝兮悌兮非沚中。", "聚應落落滴仙露，散或泠泠揚士風。", "風之上兮風之下，近一指兮遠一馬。", "秋水澹交無限情，夜光照乘胡爲者。", "伊予匪謂存餘力，詠高義兮困胸臆。", "巴歌百字巖葉書，飛寄汪門舊知識。"]'),
('e819e8bb-d2a9-4435-b121-aab34f8576d8','送仲卿禪德','釋重顯','宋','宋诗','song-poetry','','[]','高兮竺卿，秋水虛明。',30,'全唐诗/poet.song.7000.json','["高兮竺卿，秋水虛明。", "夫何之象，堪云指程。", "知吾不知，笑伽耶城。"]'),
('fb9bea09-ab06-46ac-935a-4871d78273d6','九日','鄒浩','宋','宋诗','song-poetry','','[]','歸田日日望恩光，今日尤思返故鄉。',32,'全唐诗/poet.song.70000.json','["歸田日日望恩光，今日尤思返故鄉。", "淡飯三盃菊花酒，何妨隨俗且重陽。"]'),
('11e2c5e9-af0c-4656-998a-0506d757e8e4','送擇老赴桂州龍華會','鄒浩','宋','宋诗','song-poetry','','[]','罪大投身瘴癘鄉，親年老矣重難忘。',32,'全唐诗/poet.song.70000.json','["罪大投身瘴癘鄉，親年老矣重難忘。", "龍華會上俱賢聖，爲爇精誠一炷香。"]'),
('553d6486-8285-4543-8444-c6786a0199ed','觀牡丹','鄒浩','宋','宋诗','song-poetry','','[]','去年寒食已爲客，今年寒食未還家。',32,'全唐诗/poet.song.70000.json','["去年寒食已爲客，今年寒食未還家。", "春前莫負一杯酒，山後聊觀三朵花。"]'),
('2c55416f-37f3-4c87-870d-7234ce4ffbc5','送希古','鄒浩','宋','宋诗','song-poetry','','[]','清都不敢夢中遊，何况通明侍冕旒。',64,'全唐诗/poet.song.70000.json','["清都不敢夢中遊，何况通明侍冕旒。", "分手知從天上去，望雲深感嶺邊留。", "三年瘴癘精神在，一日功名謦欬收。", "驥足風生誰絆得，綠楊芳草謾高樓。"]'),
('1965ed9d-f15e-408c-aab2-67e93c54273d','攬秀軒','鄒浩','宋','宋诗','song-poetry','','[]','觀書已若觀山水，今更開軒山水來。',64,'全唐诗/poet.song.70000.json','["觀書已若觀山水，今更開軒山水來。", "岌岌雲收騰日月，滔滔魚躍起風雷。", "二儀歘向胸中集，萬象都從筆下回。", "只恐高深亦欣覽，秀才尤秀出塵埃。"]'),
('7d98f120-9819-4466-89b4-a8ca3e3438ba','簡君瑞覓竹葉清','鄒浩','宋','宋诗','song-poetry','','[]','通道三盃如李白，解酲五斗似劉伶。',32,'全唐诗/poet.song.70000.json','["通道三盃如李白，解酲五斗似劉伶。", "爾來心渇鴨頭綠，應許唇霑竹葉青。"]'),
('41b0ab65-6953-4a68-92e0-bcf52c02dcea','君瑞酒來用前韻','鄒浩','宋','宋诗','song-poetry','','[]','蟾影舞花真窈窕，江風吹竹是倫伶。',32,'全唐诗/poet.song.70000.json','["蟾影舞花真窈窕，江風吹竹是倫伶。", "開壺日月欣浮白，放眼乾坤得倍青。"]'),
('6db59101-eced-4d28-8cfb-6321b9b0d882','聞正夫遷門下','鄒浩','宋','宋诗','song-poetry','','[]','促膝論心十二年，有時忠憤淚澘然。',64,'全唐诗/poet.song.70000.json','["促膝論心十二年，有時忠憤淚澘然。", "不聞一事拳拳救，但見三臺每每遷。", "天地豈容將計免，國家能報乃身全。", "它時會有相逢日，解說何由復自賢。"]'),
('8c99ab30-9a4d-4aa5-a28f-a24cea86e318','開窗','鄒浩','宋','宋诗','song-poetry','','[]','雨師風伯倐回車，今日春工得自如。',32,'全唐诗/poet.song.70000.json','["雨師風伯倐回車，今日春工得自如。", "窗牖洞開除障礙，盡教風景到吾廬。"]'),
('09bb0c39-c42b-457a-8065-3677b2e924b1','對牡丹','鄒浩','宋','宋诗','song-poetry','','[]','輕雲籠日雨收塵，天作奇花照眼明。',32,'全唐诗/poet.song.70000.json','["輕雲籠日雨收塵，天作奇花照眼明。", "莫道嶺邊無好況，吾今春在洛陽城。"]'),
('76a9eb6e-3b4b-4ddb-9e4f-df542aea9bc5','聞鷓鴣','鄒浩','宋','宋诗','song-poetry','','[]','默默炎荒已歲餘，音書那復阻三吳。',32,'全唐诗/poet.song.70000.json','["默默炎荒已歲餘，音書那復阻三吳。", "晚來何限青天出，獨倚欄杆聞鷓鴣。"]'),
('421b6cd0-68c1-406d-93f4-f9bc6e37b135','觀插田','鄒浩','宋','宋诗','song-poetry','','[]','幾片空田白水中，朝來俄已綠茸茸。',32,'全唐诗/poet.song.70000.json','["幾片空田白水中，朝來俄已綠茸茸。", "自憐於此留居久，兩見插禾勤老農。"]'),
('e5542e82-3b80-4a25-b653-c29b164e8a54','佛前筍  其一','鄒浩','宋','宋诗','song-poetry','','[]','基構于今政十年，不容山竹暗行鞭。',32,'全唐诗/poet.song.70000.json','["基構于今政十年，不容山竹暗行鞭。", "森然五筍自何出，盛矣文邦相與傳。"]'),
('bd6a1b7f-33f9-4808-9706-f62f8a6b7e0d','佛前筍  其二','鄒浩','宋','宋诗','song-poetry','','[]','和氣潛通無間斷，佛光回照有因緣。',32,'全唐诗/poet.song.70000.json','["和氣潛通無間斷，佛光回照有因緣。", "恩書不遠歸期近，已覺斑衣色倍鮮。"]'),
('2fcf3619-4ae9-4b0f-b7e8-3c960f82b19d','寫黄庭  其一','鄒浩','宋','宋诗','song-poetry','','[]','來仙閣上道生成，芝滿丹田鬰鬰青。',32,'全唐诗/poet.song.70000.json','["來仙閣上道生成，芝滿丹田鬰鬰青。", "不爲換鵝爲物役，焚香閒自寫黄庭。"]'),
('2435d663-05b0-4f37-8223-0f68d8747f06','寫黄庭  其二','鄒浩','宋','宋诗','song-poetry','','[]','黄庭窈窈在吾身，洒掃塵氛集萬神。',32,'全唐诗/poet.song.70000.json','["黄庭窈窈在吾身，洒掃塵氛集萬神。", "但自精誠如一日，莫愁金闕不高真。"]'),
('8f65764e-bc02-4cdc-9941-532189d54a0a','寫黄庭  其三','鄒浩','宋','宋诗','song-poetry','','[]','高真元是世間人，能密樞機到上清。',32,'全唐诗/poet.song.70000.json','["高真元是世間人，能密樞機到上清。", "天地有終吾不老，環剛猶得度羣生。"]'),
('8f85798e-5d54-4053-8184-c7dae476ca90','寫黄庭  其四','鄒浩','宋','宋诗','song-poetry','','[]','羣生何事日營營，浪以三元作五兵。',32,'全唐诗/poet.song.70000.json','["羣生何事日營營，浪以三元作五兵。", "未及殘人先自賊，幾時重得見升平。"]'),
('567d6886-25bc-4498-94cd-b5b15c98b85d','寫黄庭  其五','鄒浩','宋','宋诗','song-poetry','','[]','升平無象亦無名，翼翼巍巍拱玉宸。',32,'全唐诗/poet.song.70000.json','["升平無象亦無名，翼翼巍巍拱玉宸。", "流澤自周人自樂，普天同入萬年春。"]'),
('dd32f09a-4bb8-4269-bcfb-a3571c28e3ce','榕樹','鄒浩','宋','宋诗','song-poetry','','[]','榕樹能容故得名，枝條環布若高城。',32,'全唐诗/poet.song.70000.json','["榕樹能容故得名，枝條環布若高城。", "何當種滿彌天去，永使青青芘萬生。"]'),
('294a1b02-98b8-4667-b2a2-e2239b3d2ec4','寄陽行先','鄒浩','宋','宋诗','song-poetry','','[]','曾以高風入冕旒，未聞釋耒起南州。',64,'全唐诗/poet.song.70000.json','["曾以高風入冕旒，未聞釋耒起南州。", "當緣我罪投荒遠，亦使君身得滯留。", "萬卷功名閒處立，一瓢境界静中收。", "它年太史無虚美，卓行還能與祖侔。"]'),
('89a9c4d3-c11d-4243-84fb-b28f7fd6f6a7','聞王呂二公罷郡皆得宮觀','鄒浩','宋','宋诗','song-poetry','','[]','庚子同災知幾人，二公華顯獨超倫。',64,'全唐诗/poet.song.70000.json','["庚子同災知幾人，二公華顯獨超倫。", "比聞貶責祠宮去，始信推移運數均。", "勢冷有官猶是貴，居閒無禄未爲貧。", "須知削籍投荒者，惟望歸歟作幸民。"]'),
('bd35df99-35a2-4f67-8837-c629433d9d8d','以常寧鉛鑪合供政首座因用舊韻發一笑','鄒浩','宋','宋诗','song-poetry','','[]','十年流落見無由，誰識江東有趙州。',32,'全唐诗/poet.song.70000.json','["十年流落見無由，誰識江東有趙州。", "憑仗爐煙寄消息，定中應亦展眉頭。"]'),
('0c0c9438-f101-404a-bfc9-5a7946f63aab','聞政公住庵將成輙以只麽名之并寄絕句','鄒浩','宋','宋诗','song-poetry','','[]','縱横參了祖師禪，聊唱還鄉信此緣。',32,'全唐诗/poet.song.70000.json','["縱横參了祖師禪，聊唱還鄉信此緣。", "粥飯年來一齊足，不妨和束带刀眠。"]'),
('956fee77-764d-4b95-8efd-3e5b581a637b','招政首座','鄒浩','宋','宋诗','song-poetry','','[]','高歌一曲破還鄉，只麽隨緣是道塲。',32,'全唐诗/poet.song.70000.json','["高歌一曲破還鄉，只麽隨緣是道塲。", "已向承天設雙榻，待師同快竹風涼。"]'),
('a0eab6b7-2467-4d36-bf6a-5e5e322b4e73','有感','鄒浩','宋','宋诗','song-poetry','','[]','真訣由來甚易明，惟人用志不精誠。',32,'全唐诗/poet.song.70000.json','["真訣由來甚易明，惟人用志不精誠。", "從今謹事先生語，何患無階朝玊清。"]'),
('a236d3c2-1acc-4287-99ee-56b73b04aa29','紀夢','鄒浩','宋','宋诗','song-poetry','','[]','夢如符節自然合，吉事有開期必先。',32,'全唐诗/poet.song.70000.json','["夢如符節自然合，吉事有開期必先。", "天地無私人主聖，孤臣從此望歸田。"]'),
('83d90c2c-33b9-4e1e-849a-c5a9c577940d','母氏誕生之日得家書喜不自勝形於鄙句','鄒浩','宋','宋诗','song-poetry','','[]','萱草留春瑞氣長，二年吳越杳相望。',64,'全唐诗/poet.song.70000.json','["萱草留春瑞氣長，二年吳越杳相望。", "鑪煙正起依南極，鄉信俄來自北堂。", "委曲備聞逾獲寶，歡欣遙想盛稱觴。", "人心天意端如此，行矣歸寧慰壽康。"]'),
('204e80a8-83e0-4b78-a47a-f2452c2b8585','讀林醇中書','鄒浩','宋','宋诗','song-poetry','','[]','天下蒼生如我何，故人猶祝保天和。',64,'全唐诗/poet.song.70000.json','["天下蒼生如我何，故人猶祝保天和。", "奉親志意得歸路，報國功名還釣簑。", "已分息心隨飲啄，不應平地起風波。", "璚瑤欲報安能報，空向秦淮悵望多。"]'),
('5dd9d1bd-230e-4e57-a68c-c04176673928','讀錢濟明書','鄒浩','宋','宋诗','song-poetry','','[]','無書可借即捐書，日月雲煙見未除。',64,'全唐诗/poet.song.70000.json','["無書可借即捐書，日月雲煙見未除。", "言與不言俱是着，損之又損亦非如。", "琴邊酩酊何關酒，濠上從容豈在魚。", "爲報冰華老居士，吾今無欠亦無餘。"]'),
('92f93c17-6eee-47f0-82dc-ada1e5571b40','讀袁柬之書','鄒浩','宋','宋诗','song-poetry','','[]','人生游藝亦多端，莫若醫書可縱觀。',64,'全唐诗/poet.song.70000.json','["人生游藝亦多端，莫若醫書可縱觀。", "曾向千金深有得，孰云三界果無安。", "忘懷已自袪災瘴，寄語尤知篤歲寒。", "敢不拜嘉勤輔助，保全歸去奉親歡。"]'),
('be4eddd5-201f-4e6f-8bfc-c4ec38aefeb5','讀從外祖書','鄒浩','宋','宋诗','song-poetry','','[]','善如平路惡如巇，底事前人浪自疑。',64,'全唐诗/poet.song.70000.json','["善如平路惡如巇，底事前人浪自疑。", "方寸但令無愧怍，彼蒼何慮有偏私。", "流言聳動知公旦，削迹奇窮見仲尼。", "事事存心惟節慎，大哉斯語是吾師。"]'),
('910b0afa-52ee-41aa-aec0-3d454cf3e95c','紀夢','鄒浩','宋','宋诗','song-poetry','','[]','玉色照清都，孤臣亦侍書。',48,'全唐诗/poet.song.70000.json','["玉色照清都，孤臣亦侍書。", "叨蒙一筆賜，恩似五年初。", "竄逐雖云遠，精誠自不疏。", "皇心定垂惻，行獲奉安輿。"]'),
('b59a9d77-8d41-4b21-bc99-221ebb99d12f','客惠團茶','鄒浩','宋','宋诗','song-poetry','','[]','久矣去清班，無因預匪頒。',48,'全唐诗/poet.song.70000.json','["久矣去清班，無因預匪頒。", "殊方得高義，使我失愁顔。", "月滿浮雲散，龍飛瑞氣還。", "炎氛自辟易，歸路見鄉關。"]'),
('a2bcb845-64d6-4c4e-9d3b-2c90fa497562','移夾竹桃','鄒浩','宋','宋诗','song-poetry','','[]','將謂輕紅間老青，元來一本自然成。',64,'全唐诗/poet.song.70000.json','["將謂輕紅間老青，元來一本自然成。", "葉如桃葉回環布，枝似竹枝羅列生。", "蘭助珍羞香不斷，萱留喜意色方明。", "更移此本家園去，歲歲花時獻壽觥。"]'),
('12e07600-fea5-41a7-b494-b707d5d5287f','聞茉莉香  其一','鄒浩','宋','宋诗','song-poetry','','[]','日收炎照沈沈去，月放凉光冉冉回。',32,'全唐诗/poet.song.70000.json','["日收炎照沈沈去，月放凉光冉冉回。", "茉莉一如知我意，併從軒外送香來。"]'),
('3577adff-bdea-4a9d-b0a6-dc8f69e9ce79','聞茉莉香  其二','鄒浩','宋','宋诗','song-poetry','','[]','青琅玕裏白玫瑰，不受塵氛天自開。',32,'全唐诗/poet.song.70000.json','["青琅玕裏白玫瑰，不受塵氛天自開。", "最好夜凉初雨過，清香習習向人來。"]'),
('a14843d3-4969-4767-ae05-db1bebc2aafd','閒步','鄒浩','宋','宋诗','song-poetry','','[]','不出柴門半月强，偶隨鷗鷺到池塘。',32,'全唐诗/poet.song.70000.json','["不出柴門半月强，偶隨鷗鷺到池塘。", "荷花蓮葉薫風裏，一似去年無限香。"]'),
('cbf2d7dd-bdee-4ac0-b72f-1ca86d50b6dc','鍳華亭','鄒浩','宋','宋诗','song-poetry','','[]','羣芳移自嶺南州，要使兒童慎厥修。',64,'全唐诗/poet.song.70000.json','["羣芳移自嶺南州，要使兒童慎厥修。", "看取逐時花爛熳，即知當日罪拘留。", "黄茅瘴裏誠難脱，紫極光中偶見收。", "汝輩但將吾作鍳，勿愁忠孝不優游。"]'),
('d6a11ef1-8386-4a64-85eb-43d35d8c5c76','戲綵堂  其一','鄒浩','宋','宋诗','song-poetry','','[]','歸田日月有光輝，相與承顔家正肥。',64,'全唐诗/poet.song.70000.json','["歸田日月有光輝，相與承顔家正肥。", "萱草叢高明戶牖，棣華枝盛照庭闈。", "年年歲歲歡常在，子子孫孫志弗違。", "從此鄉評知品目，風流不愧老萊衣。"]'),
('520f6bec-706f-4081-bf44-5a63d5727cd0','戲綵堂  其二','鄒浩','宋','宋诗','song-poetry','','[]','不着朝衣着綵衣，歡然膝下永相依。',64,'全唐诗/poet.song.70000.json','["不着朝衣着綵衣，歡然膝下永相依。", "兄兄弟弟同真樂，物物人人共息機。", "三釡晨昏歸省定，一時裘馬任輕肥。", "長爲不施其親者，免被無窮有識譏。"]'),
('d3320d9b-1726-46ca-b898-ee7a6357b082','讀莊子人間世','鄒浩','宋','宋诗','song-poetry','','[]','巵言吾久得南華，每一開編一歎嗟。',64,'全唐诗/poet.song.70000.json','["巵言吾久得南華，每一開編一歎嗟。", "塵表物從何處去，人間世自莫能加。", "不知養虎但生事，未始有回真作家。", "此意于今妙相契，却慚書讀謾盈車。"]'),
('d2cc2007-2b24-4ca7-bbdc-e67ed289e0e9','偶書','鄒浩','宋','宋诗','song-poetry','','[]','未始有回無不可，焉能□□亦何傷。',32,'全唐诗/poet.song.70000.json','["未始有回無不可，焉能□□亦何傷。", "得師雖晚猶堪救，萬事紛紛付兩忘。"]'),
('c8d44a71-848b-4833-9454-1e8cb2466e1a','聞愈清老遊天台','鄒浩','宋','宋诗','song-poetry','','[]','不作寒巖枯木身，又隨雲起别蕪城。',64,'全唐诗/poet.song.70000.json','["不作寒巖枯木身，又隨雲起别蕪城。", "大方廣寺果隨喜，苦集滅人應奉迎。", "山色何如霍山色，溪聲孰似偃溪聲。", "莫教却被阿蘭笑，此箇老翁猶相生。"]'),
('e970b081-5c0e-40c5-b611-ba084acf2eb1','岑老書云遠老法堂上草深一丈矣','鄒浩','宋','宋诗','song-poetry','','[]','建隆無復舊行蹤，石塔開堂得遠公。',64,'全唐诗/poet.song.70000.json','["建隆無復舊行蹤，石塔開堂得遠公。", "衣掛六銖收法界，草深一丈見家風。", "也知是汝遠獅子，不分饒他岑大蟲。", "何日揚州船子去，木蘭花裏問真空。"]'),
('f3c1deaa-048b-44fa-8606-592a14c79239','寄上方安老','鄒浩','宋','宋诗','song-poetry','','[]','西亭會面即移船，跡掃青青翠竹前。',64,'全唐诗/poet.song.70000.json','["西亭會面即移船，跡掃青青翠竹前。", "目擊已知心照了，對談何必日留連。", "禪堂仙閣誰三界，嶺月淮雲自一天。", "偶此詩成更吟咏，飛來鷗鷺亦欣然。"]'),
('dbfaefab-326b-4add-808c-19f935f9de95','敬超先  其一','鄒浩','宋','宋诗','song-poetry','','[]','此地憑熊幾使君，敬公名姓獨超羣。',64,'全唐诗/poet.song.70000.json','["此地憑熊幾使君，敬公名姓獨超羣。", "不因健筆曾推美，縱使忘形豈得聞。", "詞翰莫窺真體要，江山猶带舊風雲。", "我來訪古惟高義，追想區區只自勤。"]'),
('12740526-589a-4df2-b4d8-dd630857112e','敬超先  其二','鄒浩','宋','宋诗','song-poetry','','[]','拾遺流落困埃塵，海內忘形有使君。',64,'全唐诗/poet.song.70000.json','["拾遺流落困埃塵，海內忘形有使君。", "長似漢中情義篤，不同常侍死生分。", "一時燥濕知難變，萬里經營想更勤。", "管鮑不忘公亦在，高風猶得後人聞。"]'),
('1811a5f7-8198-45ce-92ea-df6930ed08fe','寄子發','鄒浩','宋','宋诗','song-poetry','','[]','梅花春裏送君行，忽已芙蕖照眼明。',64,'全唐诗/poet.song.70000.json','["梅花春裏送君行，忽已芙蕖照眼明。", "握手定須酬故約，憑欄猶切念高情。", "下帷静與忘言會，扇枕凉隨喜氣生。", "只恐懸懸亦知我，有時清夢到昭平。"]'),
('32344da7-1cfa-435c-ae25-8cbd3153df4d','寄蔣彦回','鄒浩','宋','宋诗','song-poetry','','[]','澄庵一别兩炎風，回矚瀟湘興莫窮。',64,'全唐诗/poet.song.70000.json','["澄庵一别兩炎風，回矚瀟湘興莫窮。", "木聳雲山常獻瑞，鼎收龍虎妙成功。", "精神迥出拘攣外，日月都歸笑傲中。", "聞說芝園轉增勝，杖藜行欲遶芳叢。"]'),
('57ae7919-39dc-403e-b307-d1da5df1e5b0','寄朱彦明','鄒浩','宋','宋诗','song-poetry','','[]','義薄雲霄世幾人，零陵邑宰迥超倫。',64,'全唐诗/poet.song.70000.json','["義薄雲霄世幾人，零陵邑宰迥超倫。", "能明聖主恢洪造，曾是童兒謁紫宸。", "衡嶽深蟠心不動，重湖閎寫惠常均。", "别來眉宇知何似，日冀恩還得款親。"]'),
('47e3c4df-8d03-4683-87a2-25758da4d712','寄霞老','鄒浩','宋','宋诗','song-poetry','','[]','聞說高山寺，崇寧賜額新。',48,'全唐诗/poet.song.70000.json','["聞說高山寺，崇寧賜額新。", "長爲祝聖地，無復寓居人。", "佛殿焚修肅，僧窗掛搭頻。", "西來祖師意，從此出埃塵。"]'),
('80a09d99-4225-4040-823d-0bd9401f0652','伯和見過','鄒浩','宋','宋诗','song-poetry','','[]','參軍跋馬瘴江濱，一笑相逢意轉親。',64,'全唐诗/poet.song.70000.json','["參軍跋馬瘴江濱，一笑相逢意轉親。", "偶復面論前日事，恍疑身是隔生人。", "風隨玉麈傾新蓋，暑避冰姿返舊輪。", "八卦森森照歸路，爲君留飲判經旬。"]'),
('c03e56fc-4094-4d82-a6e6-b11c7eef24e5','貫道','鄒浩','宋','宋诗','song-poetry','','[]','沈冥誰復似當時，九陌塵中偶得之。',64,'全唐诗/poet.song.70000.json','["沈冥誰復似當時，九陌塵中偶得之。", "潔已已能成玉雪，爲人猶自作蓍龜。", "門前車馬喧喧過，室內乾坤默默知。", "一語不隨人事變，與君陳闊豈無期。"]'),
('23556505-38e8-4f72-bbf6-58238229c0b7','寄道林琳老','鄒浩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','寶所從來指道林，人間天上總回心。',64,'全唐诗/poet.song.70000.json','["寶所從來指道林，人間天上總回心。", "自他初不毫端隔，悲智常隨願力深。", "風带洞庭供爽籟，雲携紫蓋獻層陰。", "會須一瓣旃檀去，四句偈聞師子音。"]'),
('11840d59-6a8e-439f-b679-95ccc9f51484','寄祁陽義明','鄒浩','宋','宋诗','song-poetry','','[]','散軒蕭散萬緣空，寂寂爐煙駐曉風。',64,'全唐诗/poet.song.70000.json','["散軒蕭散萬緣空，寂寂爐煙駐曉風。", "賓主不知誰合散，江山何許自西東。", "有時黄卷倚龕外，無數碧雲生句中。", "好是心如大圓鏡，光能照我路岐通。"]'),
('3b9dcdfa-bf87-4d3f-a1f9-2af62605efaf','寄長沙何子玉','鄒浩','宋','宋诗','song-poetry','','[]','一甌難忘雪雲輕，濯盡氛埃徹骨清。',64,'全唐诗/poet.song.70000.json','["一甌難忘雪雲輕，濯盡氛埃徹骨清。", "瑞氣遶龍應滿意，薫風留日正多情。", "黄金照地人間肅，白鶴飛泉物外鳴。", "只待五湖歸興動，扁舟擘浪去尋盟。"]'),
('af12d941-e732-4648-9dcb-44e064450e19','寄公安令孫仲恭','鄒浩','宋','宋诗','song-poetry','','[]','得君寧獨爲葭莩，兩度湘中睠我殊。',64,'全唐诗/poet.song.70000.json','["得君寧獨爲葭莩，兩度湘中睠我殊。", "兵擁渡江猶繾綣，颿催離寺尚躊蹰。", "萊公廟北民歌魯，賈傅城東地入吳。", "會面不知何日再，但觀休顯繼龍圖。"]'),
('1055d640-d161-46ec-80d9-8b6ca27f3b75','寄華光仁老','鄒浩','宋','宋诗','song-poetry','','[]','越州刺史越州僧，曾是龍華同會人。',64,'全唐诗/poet.song.70000.json','["越州刺史越州僧，曾是龍華同會人。", "偶向祝融峰下過，便從香積鉢中親。", "毫端寶刹重重現，句裏藏機一一新。", "正是連天鴈回日，此心先已到江濱。"]'),
('f6fdf79b-e403-41f1-8b32-1a2f38cad2b8','敷文','鄒浩','宋','宋诗','song-poetry','','[]','赦書該得盡量移，君到衡陽適及期。',64,'全唐诗/poet.song.70000.json','["赦書該得盡量移，君到衡陽適及期。", "將謂南徐須近便，那知北望尚覊縻。", "人情既久應相好，氣候無它亦自宜。", "造物此心君會否，少留同我返茅茨。"]'),
('12295c9b-9e26-4ba7-ab25-0fbfdaa065e9','聖欽','鄒浩','宋','宋诗','song-poetry','','[]','人生相得貴知心，况復鴒原有斷金。',64,'全唐诗/poet.song.70000.json','["人生相得貴知心，况復鴒原有斷金。", "但使連墻非異趣，何須會面乃同襟。", "藥囊警動蒼生念，茗椀招回梁甫吟。", "早晚鱸魚促歸去，爲君聊駐馬駸駸。"]'),
('8eb60de3-89cd-4f19-a82c-1fc9322b7fa1','正彦','鄒浩','宋','宋诗','song-poetry','','[]','東堂當日偶差肩，屈指今逾二十年。',64,'全唐诗/poet.song.70000.json','["東堂當日偶差肩，屈指今逾二十年。", "君作長官鄰邑內，我爲遷客此江邊。", "時乖出處宜安土，道在窮通莫問天。", "只恐頖宮真拜勑，無因重獲奉周旋。"]'),
('d46eddc7-e1a9-4793-afbf-823f3ee2e66c','送米  其一','鄒浩','宋','宋诗','song-poetry','','[]','甑中如見欲生塵，不待人言廪自傾。',64,'全唐诗/poet.song.70000.json','["甑中如見欲生塵，不待人言廪自傾。", "雖阻負歸同子路，且知書帖異貞卿。", "鄰僧市井應無迹，野雀階除亦有情。", "却想萬鍾安享者，孰云天地極均平。"]'),
('871e3f51-2663-4d7f-9d8b-0f96eef580ee','送米  其二','鄒浩','宋','宋诗','song-poetry','','[]','鼓腹從今得果然，不須稱美道州前。',64,'全唐诗/poet.song.70000.json','["鼓腹從今得果然，不須稱美道州前。", "一簞頗異山雌意，滿鉢還同香積天。", "糝作藜羮誇舉挾，剖爲釣餌戲沉淵。", "只疑好事傳將去，飯顆興嘲有謫仙。"]'),
('e199d063-5dd9-478d-809c-cb64de4e06cf','送米  其三','鄒浩','宋','宋诗','song-poetry','','[]','數畝非無負郭田，川途修阻故蕭然。',64,'全唐诗/poet.song.70000.json','["數畝非無負郭田，川途修阻故蕭然。", "得君遠勝子輿友，使我非無漂母憐。", "未擬更求佳傳報，且先分當酒家錢。", "親朋只願長相見，歸飽豐穰不計年。"]'),
('2d634448-ecc3-4e49-b373-cbfa000e8a95','食荔枝','鄒浩','宋','宋诗','song-poetry','','[]','曾向新州食荔枝，黄堂酒罷即言歸。',32,'全唐诗/poet.song.70000.json','["曾向新州食荔枝，黄堂酒罷即言歸。", "含香温玉還相遇，定是恩光照客衣。"]'),
('07b57751-6855-48c3-a021-462f4e9f368f','種荔枝','鄒浩','宋','宋诗','song-poetry','','[]','高堂懷核謾栽培，一一紅根破綠苔。',32,'全唐诗/poet.song.70000.json','["高堂懷核謾栽培，一一紅根破綠苔。", "携入鄉邦吾第一，風流知自嶺南來。"]'),
('e3872975-d20b-4454-aab7-b29de543ed32','遺酒','鄒浩','宋','宋诗','song-poetry','','[]','載酒來過亦可憐，持盃先已口流涎。',64,'全唐诗/poet.song.70000.json','["載酒來過亦可憐，持盃先已口流涎。", "香浮八桂風光勝，波動兼金月影圓。", "共醉有時依竹臥，獨醒無復愧漁船。", "此中天地尤安穩，莫向塵埃盛處傳。"]'),
('13af0bf2-1c35-4f91-9e28-b686d2624a72','道人徐清自南來彦和瑩中才叔並令寄聲','鄒浩','宋','宋诗','song-poetry','','[]','吉語傳來喜可知，豈無神物共扶持。',64,'全唐诗/poet.song.70000.json','["吉語傳來喜可知，豈無神物共扶持。", "但憐四載遭三黜，偶與三公作四夔。", "海上颶風應驟息，嶺邊炎瘴亦潛衰。", "相從會有還歸日，却向江鄉話此時。"]'),
('4ab84cdc-2803-4012-b367-8de583e2e59e','灘聲','鄒浩','宋','宋诗','song-poetry','','[]','江流隨落復隨生，巧作灘聲入戶庭。',32,'全唐诗/poet.song.70000.json','["江流隨落復隨生，巧作灘聲入戶庭。", "六律五音無不有，人誰如我飽曾聽。"]'),
('f65e4701-7026-4383-a1bc-c05bde913533','喜雨','鄒浩','宋','宋诗','song-poetry','','[]','午夢初殘日正炎，坐來滂沛瀉高簷。',32,'全唐诗/poet.song.70000.json','["午夢初殘日正炎，坐來滂沛瀉高簷。", "凉生几席心如水，聊拂塵編理舊籤。"]'),
('2f415741-1f3a-4498-bd0d-d9552a752cc6','思聊齋','鄒浩','宋','宋诗','song-poetry','','[]','頖宮聊爾耳，卒歲亦優游。',48,'全唐诗/poet.song.70000.json','["頖宮聊爾耳，卒歲亦優游。", "昔已騰佳譽，今應屬勝流。", "竹聲鏘密雪，桂影弄高秋。", "爲爾猶牽思，天涯一轉頭。"]'),
('6aaaf971-5d23-4eb8-9729-4b785e9fc70e','寄鄧德甫','鄒浩','宋','宋诗','song-poetry','','[]','高山頂上偶相逢，千尺孤松霜雪中。',64,'全唐诗/poet.song.70000.json','["高山頂上偶相逢，千尺孤松霜雪中。", "不可親疏真道廣，未嘗喜愠信心空。", "衡門笑詠塵方遠，太學聲名日自隆。", "行就車頭艤歸楫，擬將周易問窮通。"]'),
('08d10577-ff91-4d6b-816a-56b2d11d3a31','偶書','鄒浩','宋','宋诗','song-poetry','','[]','吟罷新詩復自謠，欣然一笑静中超。',32,'全唐诗/poet.song.70000.json','["吟罷新詩復自謠，欣然一笑静中超。", "鳴鷄吠犬芭蕉外，欲與論心不可招。"]'),
('e3728166-55c1-40b7-ba7c-15c76197b83b','寄元老  其一','鄒浩','宋','宋诗','song-poetry','','[]','琴邊聊現宰官身，回憶來仙尚有情。',64,'全唐诗/poet.song.70000.json','["琴邊聊現宰官身，回憶來仙尚有情。", "鳥鵲遠從簷外集，鯉魚俄向眼中明。", "閒將永日供黄卷，静納薫風擢紫英。", "更得香山巧相對，一如眉宇照人清。"]'),
('b8b590f2-ad7a-4fe3-87c9-92bb7ff877eb','寄元老  其二','鄒浩','宋','宋诗','song-poetry','','[]','欲知别後事如何，門巷苔生雀可羅。',64,'全唐诗/poet.song.70000.json','["欲知别後事如何，門巷苔生雀可羅。", "偏稱解衣槃礴臝，真爲静處薩婆訶。", "鬼神密護爐中藥，風雨深藏壁上梭。", "惟是葛藤猶入念，有時西望笑呵呵。"]'),
('a88e1bd4-2766-48c2-b93a-a0e8579e93a2','得廉彦書','鄒浩','宋','宋诗','song-poetry','','[]','九曲池邊見老僧，君爲前導啟重扃。',64,'全唐诗/poet.song.70000.json','["九曲池邊見老僧，君爲前導啟重扃。", "十年空憶揚州夢，萬里遙瞻長者形。", "龍斷冥心同委吏，天涯隨分作孤星。", "何當鳴指相逢去，珍重楞伽四卷經。"]'),
('3a3cf4c8-c82e-4a19-a4ca-1192f82b4daf','元老寄惠香山','鄒浩','宋','宋诗','song-poetry','','[]','毗耶居士有神功，斷取香山置掌中。',64,'全唐诗/poet.song.70000.json','["毗耶居士有神功，斷取香山置掌中。", "五分普令薫法界，一時倶送與仙翁。", "巖頭雲澹暉暉日，洞口煙横細細風。", "可但吾心今莫逆，香巖於此獲圓通。"]'),
('cc18a40e-0e7d-496d-9593-72587707a671','道正移爇𦰡來','鄒浩','宋','宋诗','song-poetry','','[]','仙家春色不曾空，亦有𧄒𦰡占暖風。',64,'全唐诗/poet.song.70000.json','["仙家春色不曾空，亦有𧄒𦰡占暖風。", "丹桂葉舒推重碧，蟠桃花發避深紅。", "儘教带土培軒外，行欲移根過浙中。", "最好高堂歸獻壽，年年光映棣花叢。"]'),
('1dccf52e-6cc7-4a2c-8e7a-dcb654fcf11d','題慈德寺頤堂爲長老宗顥作','鄒浩','宋','宋诗','song-poetry','','[]','龍隱巖前忽轉頭，翛然瓶錫此淹留。',64,'全唐诗/poet.song.70000.json','["龍隱巖前忽轉頭，翛然瓶錫此淹留。", "十方法界元無限，一片心田自有秋。", "草木曲躬歸白足，江山依位拱青眸。", "我來不問西來意，獨喜茶香啜滿甌。"]'),
('dbc84508-6204-492d-b11c-57bfee66498f','白龍洞','鄒浩','宋','宋诗','song-poetry','','[]','洞門寂寂晝常陰，誰識行天濟物心。',64,'全唐诗/poet.song.70000.json','["洞門寂寂晝常陰，誰識行天濟物心。", "金翅影沉超永劫，玉毫光現契圓音。", "滂沱普潤三千界，靉靆濃興一萬尋。", "天子六龍方在御，不應頭角閟幽深。"]'),
('84aebb26-a506-441a-9bff-d49283dddba3','簡何秀才求龍眼栽','鄒浩','宋','宋诗','song-poetry','','[]','頃年曾食荔枝奴，補益令人智有餘。',32,'全唐诗/poet.song.70000.json','["頃年曾食荔枝奴，補益令人智有餘。", "聞說君家多此木，可能分榦入吾廬。"]'),
('1b17eef1-11c2-4cdc-a2e7-73a301759a8f','汩羅','鄒浩','宋','宋诗','song-poetry','','[]','忠潔云亡幾百秋，汨羅江水湛清流。',32,'全唐诗/poet.song.70000.json','["忠潔云亡幾百秋，汨羅江水湛清流。", "是非折衷無夫子，直至如今口未休。"]'),
('f55c31c0-d39a-441a-b930-048edc5c127a','讀郭有道傳','鄒浩','宋','宋诗','song-poetry','','[]','隱不違親與俗通，危言覈論絕胸中。',32,'全唐诗/poet.song.70000.json','["隱不違親與俗通，危言覈論絕胸中。", "紛紛禁錮知名者，何事全無有道風。"]'),
('e5e89812-2510-473d-9c04-0f7f7642a0b5','聞市中遺火殆盡  其一','鄒浩','宋','宋诗','song-poetry','','[]','市井纔如一小虚，更堪回禄掃成墟。',32,'全唐诗/poet.song.70000.json','["市井纔如一小虚，更堪回禄掃成墟。", "從今匕箸知何有，百煎江流瀹野蔬。"]'),
('52208adf-7a86-4932-aec1-c2889149e957','聞市中遺火殆盡  其二','鄒浩','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','錐刀利害日相摩，生火由來勢自多。',32,'全唐诗/poet.song.70000.json','["錐刀利害日相摩，生火由來勢自多。", "咫尺長江水何限，不能飛灑奈炎何。"]'),
('7552282a-12f0-4fb7-a54f-36037802a94f','聞市中遺火殆盡  其三','鄒浩','宋','宋诗','song-poetry','','[]','何暇從容白丈人，火邊綆缶定紛紛。',32,'全唐诗/poet.song.70000.json','["何暇從容白丈人，火邊綆缶定紛紛。", "徙薪曲突非無策，自是當時藐不聞。"]'),
('4a9ad924-176a-4528-aa07-0e9ee4110816','來仙閣','鄒浩','宋','宋诗','song-poetry','','[]','偶向人間作謫仙，翛然來此住經年。',64,'全唐诗/poet.song.70000.json','["偶向人間作謫仙，翛然來此住經年。", "君臣鼎內重相合，日月壺中獨自圓。", "過惡已除丹簡上，姓名猶在紫霞前。", "一朝駕却飛鸞去，留得風聲舉世傳。"]'),
('7144a0a9-4455-41b5-8a7d-5a91d6d7a6a5','玉虚觀','鄒浩','宋','宋诗','song-poetry','','[]','山腰制作邇來新，斧鑿纔終便掩門。',64,'全唐诗/poet.song.70000.json','["山腰制作邇來新，斧鑿纔終便掩門。", "獨殿紛紛羅杞棘，老君寂寂看鷄豚。", "煙凝疊嶂爲香火，風韻疏松作道言。", "借問羽衣何處去，一齊歸屋抱兒孫。"]'),
('0a662b4c-7228-4ff9-9f07-96fb92fbf820','存之','鄒浩','宋','宋诗','song-poetry','','[]','品目從來號智囊，保身何事缺隄防。',64,'全唐诗/poet.song.70000.json','["品目從來號智囊，保身何事缺隄防。", "青錢得謗由東府，白簡繩愆到北堂。", "朝散郎應無所惜，太夫人豈不憂傷。", "平生盡入禪師室，到此方知道力强。"]'),
('e6e627cb-b7c9-4616-9485-70266fa85e65','澹山','鄒浩','宋','宋诗','song-poetry','','[]','目擊何人妙得知，謾携斧子住巖隈。',64,'全唐诗/poet.song.70000.json','["目擊何人妙得知，謾携斧子住巖隈。", "銜花無復鳥興供，運木有時神倒栽。", "丈室每思雲外去，沱山長記雨中來。", "憑師更展慈悲力，早使回頭一笑開。"]'),
('6c7bd05a-9a81-479c-87da-acb6c9d4230c','大平','鄒浩','宋','宋诗','song-poetry','','[]','大施門開陸海中，一時緇素許參同。',64,'全唐诗/poet.song.70000.json','["大施門開陸海中，一時緇素許參同。", "縱横只見山河露，消息寧知車馬通。", "帝網重重含寶刹，法輪日日轉龍宮。", "何當去作龐居士，笑指庭花問祖風。"]'),
('d7a84802-cb92-48b1-813e-f92890876e45','勉蕭尉秀實别刻磨崖','鄒浩','宋','宋诗','song-poetry','','[]','忠義能令金石開，至今凛凛動昭回。',64,'全唐诗/poet.song.70000.json','["忠義能令金石開，至今凛凛動昭回。", "彼蒼欲作無窮計，此事欣逢不世才。", "浄掃煙霞留健筆，巧分鸞鳳過浯臺。", "亦宜愛日成君志，側席知名即詔來。"]'),
('d15dcfb7-c90d-469e-8853-e0c9ffaefbae','高山','鄒浩','宋','宋诗','song-poetry','','[]','莫道高山老古錐，歘令金碧照崔嵬。',64,'全唐诗/poet.song.70000.json','["莫道高山老古錐，歘令金碧照崔嵬。", "神通未必輸摩詰，眼浄方能識萬回。", "捧打室中紛似雨，鼓椎堂上吼如雷。", "天長地久君王壽，從此宗風亘未來。"]'),
('2be6f479-fc51-4b87-a843-b8242d910531','呂四  其一','鄒浩','宋','宋诗','song-poetry','','[]','市門風義有誰知，旋打長船待我歸。',32,'全唐诗/poet.song.70000.json','["市門風義有誰知，旋打長船待我歸。", "秋入江湖正瀟灑，歡然鳴艣去如飛。"]'),
('53723c00-9fdb-4b2d-9448-303cca6ed23f','呂四  其二','鄒浩','宋','宋诗','song-poetry','','[]','搖轉船頭順碧波，日行五百未爲多。',32,'全唐诗/poet.song.70000.json','["搖轉船頭順碧波，日行五百未爲多。", "三湘二浙雖遼遠，尚及家庭賞芰荷。"]'),
('7d01f448-423e-4188-a335-275bebc87ebb','呂四  其三','鄒浩','宋','宋诗','song-poetry','','[]','平生親友謾紛紛，有幾書來寂寞濱。',32,'全唐诗/poet.song.70000.json','["平生親友謾紛紛，有幾書來寂寞濱。", "二十萬錢捐不惜，可憐湖外有斯人。"]'),
('36758940-3a8d-4301-9dd0-ba9313a47310','呂四  其四','鄒浩','宋','宋诗','song-poetry','','[]','鴻鴈嗈嗈正北飛，爲傳消息到庭闈。',32,'全唐诗/poet.song.70000.json','["鴻鴈嗈嗈正北飛，爲傳消息到庭闈。", "不須過作風波慮，已有新船穩送歸。"]'),
('69552c53-13ad-41bc-ac27-0559df594c5d','呂四  其五','鄒浩','宋','宋诗','song-poetry','','[]','瀟湘起柁出江湖，日日乾坤展畫圖。',32,'全唐诗/poet.song.70000.json','["瀟湘起柁出江湖，日日乾坤展畫圖。", "白酒紅魚對妻子，鴟夷還似此行無。"]'),
('1db7da6b-2c02-4c76-849b-fe28829d7174','聞王若愚除桂帥','鄒浩','宋','宋诗','song-poetry','','[]','鸞臺鳳閣並門居，同荷先皇奬眷殊。',64,'全唐诗/poet.song.70000.json','["鸞臺鳳閣並門居，同荷先皇奬眷殊。", "諫草悠悠空皎日，年華忽忽幾青蒲。", "朝廷擇帥君來越，鄉里容身我念吳。", "萬事循環總如此，目前何必較榮枯。"]'),
('294d5729-d1e5-46b5-9640-721ea402e243','寄清老','鄒浩','宋','宋诗','song-poetry','','[]','自來漁父好家風，一片瀟湘晚釣中。',64,'全唐诗/poet.song.70000.json','["自來漁父好家風，一片瀟湘晚釣中。", "伊昔放言知莫逆，于今親到得參同。", "金章寂寂殘初夢，汀草依依照短篷。", "德秀雖亡次山在，悵回青眼送飛鴻。"]'),
('d6f2b722-9009-45cf-b809-a55d2c32f6a6','覽鏡戲作  其一','鄒浩','宋','宋诗','song-poetry','','[]','寒時驟熱熱時寒，一等陰陽幾百般。',32,'全唐诗/poet.song.70000.json','["寒時驟熱熱時寒，一等陰陽幾百般。", "髮脱面黄肌肉痩，北人應作嶺蠻看。"]'),
('657708aa-33d5-4860-915f-4183d032f288','覽鏡戲作  其二','鄒浩','宋','宋诗','song-poetry','','[]','赤脚蠻中過一年，受持讀誦日精専。',32,'全唐诗/poet.song.70000.json','["赤脚蠻中過一年，受持讀誦日精専。", "只應果滿同諸佛，丈六金身色瑩然。"]'),
('1b547018-065a-4e9d-9890-0d978424a08e','元禮','鄒浩','宋','宋诗','song-poetry','','[]','來往憧憧多故人，幾能於此欵柴門。',64,'全唐诗/poet.song.70000.json','["來往憧憧多故人，幾能於此欵柴門。", "紅蓮綠水還初興，青草黄茅得細論。", "陡覺炎氛開日月，坐令爽氣滿乾坤。", "匪朝恩錫歸田去，只恐煩君費酒樽。"]'),
('e58b9a98-a1eb-40e8-abad-ca74a5aa14d5','元禮乘漁船見訪作此戲之','鄒浩','宋','宋诗','song-poetry','','[]','一棹翛然一幅巾，汀鷗集處亦逡巡。',32,'全唐诗/poet.song.70000.json','["一棹翛然一幅巾，汀鷗集處亦逡巡。", "功名正逐天機露，不似釣魚船上人。"]'),
('4f77f7f7-c00e-4452-8c6b-e5be1b6c5a3e','九日追和去年所作','鄒浩','宋','宋诗','song-poetry','','[]','茱萸黄菊占秋光，休歎佳時在瘴鄉。',32,'全唐诗/poet.song.70000.json','["茱萸黄菊占秋光，休歎佳時在瘴鄉。", "飲罷此身歸有日，明明天子正當陽。"]'),
('a65632f7-37a1-45e8-8664-673012ed3139','清華閣','鄒浩','宋','宋诗','song-poetry','','[]','泉石清華世豈知，蕭然無是亦無非。',32,'全唐诗/poet.song.70000.json','["泉石清華世豈知，蕭然無是亦無非。", "二年於此陪鷗鷺，收得閒中勳業歸。"]'),
('764555ba-57d0-4b69-a041-ba886f6deee2','讀論語','鄒浩','宋','宋诗','song-poetry','','[]','仲尼初不離靈臺，請業門人日日來。',32,'全唐诗/poet.song.70000.json','["仲尼初不離靈臺，請業門人日日來。", "一念回光是論語，何須塵簡面前開。"]'),
('59ed7bbf-0ab8-46c0-80dc-597897c00a4c','謝仁老寄所畫李長者出山相五首  其一','鄒浩','宋','宋诗','song-poetry','','[]','虎腰黄卷動昭回，無數人天心眼開。',32,'全唐诗/poet.song.70000.json','["虎腰黄卷動昭回，無數人天心眼開。", "不是機鋒妙相契，是渠那肯出山來。"]'),
('73b73a24-3785-4272-81a4-0f465e9eac43','謝仁老寄所畫李長者出山相五首  其二','鄒浩','宋','宋诗','song-poetry','','[]','香雲郁郁覆江城，來現開元長者身。',32,'全唐诗/poet.song.70000.json','["香雲郁郁覆江城，來現開元長者身。", "八十卷經都論了，却將無說示常人。"]'),
('786835f5-b6e9-4527-ac8e-ecb78b9c6b84','謝仁老寄所畫李長者出山相五首  其三','鄒浩','宋','宋诗','song-poetry','','[]','碧潭秋霽禪師筆，白月天空論主形。',32,'全唐诗/poet.song.70000.json','["碧潭秋霽禪師筆，白月天空論主形。", "是幻是真分不得，爲人重說互嚴經。"]'),
('09dd7013-9ca6-409a-aacc-9ef74249a0f4','謝仁老寄所畫李長者出山相五首  其四','鄒浩','宋','宋诗','song-poetry','','[]','貝葉卷文無表示，於菟曳尾不求憐。',32,'全唐诗/poet.song.70000.json','["貝葉卷文無表示，於菟曳尾不求憐。", "昻藏豈是維摩詰，終日相從也默然。"]'),
('40fddb42-21d2-46ce-a86c-81f2f3b25459','謝仁老寄所畫李長者出山相五首  其五','鄒浩','宋','宋诗','song-poetry','','[]','一真境界孰能參，賴有斯人作指南。',32,'全唐诗/poet.song.70000.json','["一真境界孰能參，賴有斯人作指南。", "更賴殷勤招喚得，不知流落在煙嵐。"]'),
('e6aa8abf-0d72-4c5a-8a3c-2b06eb42fbed','欽道','鄒浩','宋','宋诗','song-poetry','','[]','誰謂南方世乏人，斯人見義若風生。',64,'全唐诗/poet.song.70000.json','["誰謂南方世乏人，斯人見義若風生。", "吉凶禍福略無惜，父子弟兄同此情。", "袖裏珠光携合浦，胸中潭影到昭平。", "它年野史誰操筆，定以青編著姓名。"]'),
('7db2d6cd-f2be-4d4b-b49c-69a4bd3db1bf','讀張氏金塘阡表','鄒浩','宋','宋诗','song-poetry','','[]','大筆從來不妄褒，特於阡表勇揮毫。',64,'全唐诗/poet.song.70000.json','["大筆從來不妄褒，特於阡表勇揮毫。", "當年種德已如此，今日里門宜自高。", "雲带洞山常藹藹，雨鍾明水轉滔滔。", "追榮更有豐碑在，行矣巍然壓巨鼇。"]'),
('d0d08433-b78c-4125-9d3e-744aea25a9b2','聞周仲修復致仕','鄒浩','宋','宋诗','song-poetry','','[]','繼述嘉謀聖主知，拂衣緣底便言歸。',64,'全唐诗/poet.song.70000.json','["繼述嘉謀聖主知，拂衣緣底便言歸。", "往而能返非難事，安不忘危是識機。", "西子扁舟藏國艶，鱸魚一筯出江肥。", "公乎有地相容否，纔脱拘攣去似飛。"]'),
('79e0657c-2835-4e21-8be6-1a2fddfa7b09','聞朱世英再知江寧府','鄒浩','宋','宋诗','song-poetry','','[]','歸領真祠未幾時，牙兵重展舊旌旗。',64,'全唐诗/poet.song.70000.json','["歸領真祠未幾時，牙兵重展舊旌旗。", "向來孰不歌來暮，今去歡然釋去思。", "竹馬渡江騰駿足，甘棠拂戶動高枝。", "鍾山只恐違初興，徑入鵷行侍玉墀。"]'),
('b8e9b61c-841b-4a84-9014-07f7fe07fc50','示長卿二絕  其一','鄒浩','宋','宋诗','song-poetry','','[]','懾處炎荒已二年，親朋書問亦茫然。',32,'全唐诗/poet.song.70000.json','["懾處炎荒已二年，親朋書問亦茫然。", "獨君風義能終始，不管煙嵐肯着鞭。"]'),
('80ee9e75-1f89-464a-8135-fc3d96fcb591','示長卿二絕  其二','鄒浩','宋','宋诗','song-poetry','','[]','一别和州二十年，山長水闊去無緣。',32,'全唐诗/poet.song.70000.json','["一别和州二十年，山長水闊去無緣。", "因君說起外家事，特地欄邊心悵然。"]'),
('937d016b-9fd5-4a31-a053-587eb9cd3606','示二黄','鄒浩','宋','宋诗','song-poetry','','[]','摩尼超出衲衣中，五色隨方照不窮。',32,'全唐诗/poet.song.70000.json','["摩尼超出衲衣中，五色隨方照不窮。", "八萬四千清浄眼，一齊開了見真空。"]'),
('c825cf6b-6b11-4f1a-87be-dec69cf57bdb','夜聞鳴桹  其一','鄒浩','宋','宋诗','song-poetry','','[]','鳴桹聲響五更初，恰似京城叩木魚。',32,'全唐诗/poet.song.70000.json','["鳴桹聲響五更初，恰似京城叩木魚。", "夢裏猶疑趁朝晚，幾回驚起攬衣裾。"]'),
('85bded55-17bb-4e10-a1b6-ff8bc54df3c7','夜聞鳴桹  其二','鄒浩','宋','宋诗','song-poetry','','[]','漁人於我本無情，我自情生夢裏驚。',32,'全唐诗/poet.song.70000.json','["漁人於我本無情，我自情生夢裏驚。", "驚起却眠方記得，新條不得到京城。"]'),
('e1d13e2c-fa2f-47f9-9bc5-ac16076ed17c','書喜','鄒浩','宋','宋诗','song-poetry','','[]','仲冬月吉吉可知，日南長至恩光期。',64,'全唐诗/poet.song.70000.json','["仲冬月吉吉可知，日南長至恩光期。", "一陽火復驗內揵，八陛圓壇嚴上儀。", "玉輅回鑾天倍喜，金鷄肆赦人均禧。", "倚門朝夕可寛念，綵衣歸去今其時。"]'),
('445b918e-55fb-4e45-bbf6-a3d94fe9c462','喜晴','鄒浩','宋','宋诗','song-poetry','','[]','一陽初欲與時亨，便覺羣陰不敢行。',64,'全唐诗/poet.song.70000.json','["一陽初欲與時亨，便覺羣陰不敢行。", "寒雨斷飛天皎潔，冷雲收翳日晶明。", "泥乾屐齒都無阻，氣協花心倍有情。", "天運回旋吾道長，欣欣此際孰能名。"]'),
('d714f105-2500-4878-bd94-bb1831ed42fd','仙宮廟','鄒浩','宋','宋诗','song-poetry','','[]','千仞巉巖一徑通，可捫天處是仙宮。',64,'全唐诗/poet.song.70000.json','["千仞巉巖一徑通，可捫天處是仙宮。", "嬋娟並席誰家子，縹緲吹衣萬竅風。", "初月淡籠眉拂拂，晚雲低遶鬢𩮀𩮀。", "邦人不復知端的，但說常能助歲功。"]'),
('277836ef-a522-4367-b8d2-dde5f9636df4','周御史廟','鄒浩','宋','宋诗','song-poetry','','[]','忠言直節動天聰，名在昇平北斗中。',64,'全唐诗/poet.song.70000.json','["忠言直節動天聰，名在昇平北斗中。", "陰德久宜家有後，光靈今與國無窮。", "庭前烏集當年柏，門外風生舊日驄。", "公不世情應我顧，一觴聊復以誠通。"]'),
('4ffda166-2f6a-4166-9148-cf2cd15914fd','龍興觀有感','鄒浩','宋','宋诗','song-poetry','','[]','自罷龍興節，人間幾歲窮。',48,'全唐诗/poet.song.70000.json','["自罷龍興節，人間幾歲窮。", "偶觀塵榜暗，追感御爐穹。", "萬事遺高躅，三清肅下風。", "鈞天在何許，猶冀夢魂通。"]'),
('7407ef4d-fadd-491b-86be-5962c6639d6e','枯荷','鄒浩','宋','宋诗','song-poetry','','[]','萬頃菱荷一一荒，駢頭相倚卧池塘。',64,'全唐诗/poet.song.70000.json','["萬頃菱荷一一荒，駢頭相倚卧池塘。", "追惟弄日搖深綠，不謂凌風折敗黄。", "饑鴈飛銜投遠渚，寒魚浮觸動斜陽。", "那知凛凛梢雲者，自有松筠傲雪霜。"]'),
('3e15cb9f-85fd-489a-ad29-98e734c50621','閒步','鄒浩','宋','宋诗','song-poetry','','[]','冬來風雨併，今日偶晴明。',48,'全唐诗/poet.song.70000.json','["冬來風雨併，今日偶晴明。", "况是親朋集，聊將笑語行。", "青雲隨步武，朱鷺入逢迎。", "無限欣然思，都隨指顧生。"]'),
('dc6cd5e1-974c-48f5-a366-add6d53afeea','泛舟  其一','鄒浩','宋','宋诗','song-poetry','','[]','乘興扁舟過趙村，滿家灘上水連雲。',32,'全唐诗/poet.song.70000.json','["乘興扁舟過趙村，滿家灘上水連雲。", "欣然便欲尋源去，織女機邊日未曛。"]'),
('8e70f9c1-c8ea-4e18-98da-4cbc54feeb25','泛舟  其二','鄒浩','宋','宋诗','song-poetry','','[]','風浄一奩水鏡，雲開兩行山屏。',28,'全唐诗/poet.song.70000.json','["風浄一奩水鏡，雲開兩行山屏。", "白鷺亦知人意，飛來佇立寒汀。"]'),
('18aa0f98-3df4-4698-a044-98a751bbe87e','登鵬高亭基','鄒浩','宋','宋诗','song-poetry','','[]','野燒無蹤知幾年，故亭遺址尚依然。',64,'全唐诗/poet.song.70000.json','["野燒無蹤知幾年，故亭遺址尚依然。", "巍巍穩據山千仞，渺渺前當水一川。", "地展雲衣深固護，天回松蓋巧周旋。", "重興棟宇非難事，坐使風光集綺筵。"]'),
('5c938637-094c-47d7-b7ca-63439a469baa','銅池','鄒浩','宋','宋诗','song-poetry','','[]','勻疊灘頭碎石，滿添江面清流。',28,'全唐诗/poet.song.70000.json','["勻疊灘頭碎石，滿添江面清流。", "聊向箇中兒戲，不知何處塵浮。"]'),
('844165ba-1f85-49ea-b74a-0ff3a4e7a87a','示長卿','鄒浩','宋','宋诗','song-poetry','','[]','君與我同庚子生，連年憂患亦縱横。',64,'全唐诗/poet.song.70000.json','["君與我同庚子生，連年憂患亦縱横。", "天高休說不可問，心下直須深自明。", "運屬時雍人正樂，祀嚴郊報禮初成。", "滌瑕蕩垢知多少，行矣欣欣木再榮。"]'),
('d932f157-ad91-49c4-a558-e0deb6e13ab0','送長卿  其一','鄒浩','宋','宋诗','song-poetry','','[]','有口如鉗方鮮語，無心似水始能思。',32,'全唐诗/poet.song.70000.json','["有口如鉗方鮮語，無心似水始能思。", "盃中一片閒天地，占得新陽君與知。"]'),
('c149c4b9-e22a-4c51-ad32-165c1a427c19','送長卿  其二','鄒浩','宋','宋诗','song-poetry','','[]','陽朔千山與萬山，生綃圖寫北人看。',32,'全唐诗/poet.song.70000.json','["陽朔千山與萬山，生綃圖寫北人看。", "君今欵段穿雲去，莫厭崎嶇行路難。"]'),
('cfa9489c-b24d-487b-9077-88ca911e1ead','陽朔路','鄒浩','宋','宋诗','song-poetry','','[]','雲裏峰巒千萬重，中間一路與天通。',32,'全唐诗/poet.song.70000.json','["雲裏峰巒千萬重，中間一路與天通。", "新陽已約爲前導，回我車輪朝帝宮。"]'),
('121556e9-443e-4847-a41e-87412d5295d4','寄長卿','鄒浩','宋','宋诗','song-poetry','','[]','烏銜霽色朝迎馬，蟾吐澄輝夜照眠。',32,'全唐诗/poet.song.70000.json','["烏銜霽色朝迎馬，蟾吐澄輝夜照眠。", "日月於君已如此，不須星曆問行年。"]'),
('e37a77af-289c-4dec-a14c-4a2d9c841867','偶書','鄒浩','宋','宋诗','song-poetry','','[]','朝天坊裏朝天客，拱北軒中拱北人。',32,'全唐诗/poet.song.70000.json','["朝天坊裏朝天客，拱北軒中拱北人。", "惟有蒼蒼知此意，只應潛爲啟嚴宸。"]'),
('f6776a4b-8050-42be-b471-fae61f1f2123','寄參寥  其一','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲岫庵頭掛鉢囊，旃檀一瓣自馨香。',64,'全唐诗/poet.song.70000.json','["雲岫庵頭掛鉢囊，旃檀一瓣自馨香。", "建隆消息天然别，妙總流通筆放光。", "南嶺梅花空自得，西湖漚鳥宛相望。", "師如水浄吾如月，照入清泠知有方。"]'),
('5ef681fd-189f-4b93-a966-39d481100596','寄參寥  其二','鄒浩','宋','宋诗','song-poetry','','[]','上東門外解船時，赴感汝陰師未歸。',64,'全唐诗/poet.song.70000.json','["上東門外解船時，赴感汝陰師未歸。", "松麈對談能幾日，瘴鄉孤坐但忘機。", "珠騰甓社淮南冷，山折成都蜀道非。", "屬耳朱絃誰莫逆，只應袖手看鴻飛。"]'),
('e032c6ea-a163-4093-95df-bccc5c86f59a','喜捷應方成','鄒浩','宋','宋诗','song-poetry','','[]','上醫醫國有誰知，且集方書捷用之。',32,'全唐诗/poet.song.70000.json','["上醫醫國有誰知，且集方書捷用之。", "疾苦一齊安樂後，自然遭遇太平時。"]'),
('7a2436cc-75ed-4d45-9649-256f9f56d445','他處梅自十月已開爛熳獨此今方作花睹之欣然  其一','鄒浩','宋','宋诗','song-poetry','','[]','驚怪江梅獨未開，含芳元是待冬來。',32,'全唐诗/poet.song.70000.json','["驚怪江梅獨未開，含芳元是待冬來。", "新陽夙駕無多日，已向枝頭各自催。"]'),
('67455785-bba2-45db-8960-aa6e8c3bdb3b','他處梅自十月已開爛熳獨此今方作花睹之欣然  其二','鄒浩','宋','宋诗','song-poetry','','[]','東君消息到梅梢，滿眼輕盈漸解苞。',32,'全唐诗/poet.song.70000.json','["東君消息到梅梢，滿眼輕盈漸解苞。", "遶樹更忙須百匝，行看新様插雲髾。"]'),
('cb9894b0-607d-4ef5-b225-19ad429fcb3c','他處梅自十月已開爛熳獨此今方作花睹之欣然  其三','鄒浩','宋','宋诗','song-poetry','','[]','梅將喜信自天來，光動書樓趁暖開。',32,'全唐诗/poet.song.70000.json','["梅將喜信自天來，光動書樓趁暖開。", "花比去年真箇好，一齊欣送我儂回。"]'),
('0d983ceb-f66e-4082-afa6-cebedb6486bc','治梅圃  其一','鄒浩','宋','宋诗','song-poetry','','[]','只有今年對此花，此花欣送我還家。',32,'全唐诗/poet.song.70000.json','["只有今年對此花，此花欣送我還家。", "呼童掃溉放花出，作意相從歸去誇。"]'),
('1d8f73c2-87fb-430b-ac37-f86a5c77aa95','治梅圃  其二','鄒浩','宋','宋诗','song-poetry','','[]','中間籬障壓根蟠，四面荆榛逼樹攅。',32,'全唐诗/poet.song.70000.json','["中間籬障壓根蟠，四面荆榛逼樹攅。", "今日削除隨手浄，放梅高出紫雲端。"]'),
('65509a24-78d6-43ba-a00b-da1271b7b3a4','放竹鷄','鄒浩','宋','宋诗','song-poetry','','[]','鼓翅出樊籠，雙飛意氣同。',48,'全唐诗/poet.song.70000.json','["鼓翅出樊籠，雙飛意氣同。", "便鳴泥滑滑，深應竹叢叢。", "善也還天性，時哉屬歲豐。", "弋人情已得，寧復墮機中。"]'),
('d0843d13-52d0-4ef2-b534-e8cccb7ab6db','拱梅亭','鄒浩','宋','宋诗','song-poetry','','[]','陸沉無復似當年，高壓雲根氣象全。',64,'全唐诗/poet.song.70000.json','["陸沉無復似當年，高壓雲根氣象全。", "四面山川趨指顧，一時草木避蕃鮮。", "垂簷鼎實須歸帝，起檻龍香必動天。", "自我發揮人共樂，風流從此映來仙。"]'),
('ea4d7ad3-7265-4012-a05c-c6e9b89f88dd','懷長卿  其一','鄒浩','宋','宋诗','song-poetry','','[]','香醅新撥一尊濃，准擬君來笑語同。',32,'全唐诗/poet.song.70000.json','["香醅新撥一尊濃，准擬君來笑語同。", "緣底留連過初約，憑欄日日望歸蓬。"]'),
('3053a470-cb7c-48fb-9214-7d5ce9e7ba93','懷長卿  其二','鄒浩','宋','宋诗','song-poetry','','[]','深情知在霈恩邊，肯爲閒花醉後顛。',32,'全唐诗/poet.song.70000.json','["深情知在霈恩邊，肯爲閒花醉後顛。", "不是看山駐陽朔，即應倚擔待長船。"]'),
('3d5aaee6-af3a-4bc4-8635-d008733e927d','小樹','鄒浩','宋','宋诗','song-poetry','','[]','一株短短八九寸，四面青青千百枝。',32,'全唐诗/poet.song.70000.json','["一株短短八九寸，四面青青千百枝。", "作供佛前偕瑞竹，移根石上入銅池。"]'),
('5c65d4b6-32cd-4874-a7f1-a9fd4a2ccac8','小雨','鄒浩','宋','宋诗','song-poetry','','[]','梅圃初成塵土飛，早來煙雨便霏微。',32,'全唐诗/poet.song.70000.json','["梅圃初成塵土飛，早來煙雨便霏微。", "天時人事欣相得，可騐蒙恩朝夕歸。"]'),
('09fc02e4-4688-44db-8a77-45bf2c0554e6','聞吳聖取還朝','鄒浩','宋','宋诗','song-poetry','','[]','庚子頻年憂患同，君依墳土我飄蓬。',64,'全唐诗/poet.song.70000.json','["庚子頻年憂患同，君依墳土我飄蓬。", "聞君已復雲霄上，顧我須逃瘴霧中。", "學校他年齊出處，朝廷今日異窮通。", "敝廬歸去無他事，惟願時和歲歲豐。"]'),
('712b7b84-5ae8-45d0-921c-99d522fe27ef','燈花甚奇','鄒浩','宋','宋诗','song-poetry','','[]','草赦今朝鎖北門，燈花來報我蒙恩。',64,'全唐诗/poet.song.70000.json','["草赦今朝鎖北門，燈花來報我蒙恩。", "巧當樓閣中間立，高出光明幾次繁。", "遼絕雖然如異域，生成本不間孤根。", "此身曲荷乾坤力，仰答洪私它日論。"]'),
('7931c1c6-b3bd-4ca9-b214-10408a866f96','山禽','鄒浩','宋','宋诗','song-poetry','','[]','一鳥飛從何處來，歸去歸去聲聲催。',64,'全唐诗/poet.song.70000.json','["一鳥飛從何處來，歸去歸去聲聲催。", "爐烟正自山閣起，天意俄從雲路開。", "三年至日阻爲壽，萬里膝下今當回。", "迎祥拜貺不勝喜，滿引賀酒千百杯。"]'),
('fae7ac8c-b6b2-4756-b939-a5d790a6501e','用老杜至日懷太白韻懷諸弟','鄒浩','宋','宋诗','song-poetry','','[]','羅拜爲親壽，遙知亦我思。',48,'全唐诗/poet.song.70000.json','["羅拜爲親壽，遙知亦我思。", "陽生萱草色，心入棣華詩。", "帝澤來非久，萊衣戲不遲。", "爲言多置酒，歸趁賞花期。"]'),
('dea02374-e460-4a1b-8dc6-a44a55f34b90','懷舊','鄒浩','宋','宋诗','song-poetry','','[]','辛巳年冬導駕行，朝從太廟出青城。',64,'全唐诗/poet.song.70000.json','["辛巳年冬導駕行，朝從太廟出青城。", "雪迎天仗徐徐舞，日向龍顔淡淡明。", "不待銜枚人自肅，惟觀夾道喜相仍。", "今朝倍復如初盛，遙拱神京空此誠。"]'),
('38acc58e-934c-4f4d-bb22-c973280de319','至日依韻和老杜五首  其一','鄒浩','宋','宋诗','song-poetry','','[]','歲月驚如弩發牀，千官壇下又成行。',64,'全唐诗/poet.song.70000.json','["歲月驚如弩發牀，千官壇下又成行。", "燔柴香藹六變樂，奠玉殷勤三上香。", "當日珮綪躬進酒，兹辰目斷望垂裳。", "端誠舞蹈無因預，空想中天瑞氣長。"]'),
('ee3600ee-480a-453d-bb86-ffb9e43f2ed9','至日依韻和老杜五首  其二','鄒浩','宋','宋诗','song-poetry','','[]','蠻風吹鬢鬢毛斑，非復登樓舊日顔。',64,'全唐诗/poet.song.70000.json','["蠻風吹鬢鬢毛斑，非復登樓舊日顔。", "上主亦應憐久竄，孤臣尤切望今還。", "金鷄歡動欄杆外，綵服光生骨肉間。", "歸去此恩何以報，惟將香火祝南山。"]'),
('d00ac379-8366-4188-95ef-b8b0047f460e','至日依韻和老杜五首  其三','鄒浩','宋','宋诗','song-poetry','','[]','黄宮初氣重氤氲，喜色朝來便着人。',64,'全唐诗/poet.song.70000.json','["黄宮初氣重氤氲，喜色朝來便着人。", "知有歸期親望我，更無它事我思親。", "堂前獻壽開金盞，嶺外蒙恩戴玉宸。", "一笑承顔勝六印，功名豈復羡儀秦。"]'),
('8a44b1f5-15a4-48a2-9ea9-326104261e3d','至日依韻和老杜五首  其四','鄒浩','宋','宋诗','song-poetry','','[]','當關無復守門催，欲曉雞聲喚起來。',64,'全唐诗/poet.song.70000.json','["當關無復守門催，欲曉雞聲喚起來。", "一炷壽香瞻白髮，三盃賀酒寫紅灰。", "看棚尚倚天街柳，恩信先通桂嶺梅。", "但喜奉身歸膝下，自餘皆是魯禽杯。"]'),
('0e0efc8c-b4cd-4164-86dd-0eef4464eff2','至日依韻和老杜五首  其五','鄒浩','宋','宋诗','song-poetry','','[]','慚愧君恩似日長，終然傾否肇三陽。',64,'全唐诗/poet.song.70000.json','["慚愧君恩似日長，終然傾否肇三陽。", "休思往事追華貫，且喜餘生脱瘴鄉。", "俛仰自知誠自幸，尊卑相守免相望。", "外炎內熱從兹盡，别是人間一味凉。"]'),
('49f7e839-3593-41bd-96a9-1986517f89aa','同仲亶長卿觀梅','鄒浩','宋','宋诗','song-poetry','','[]','雨後江山欲放春，更無一點舊風塵。',32,'全唐诗/poet.song.70000.json','["雨後江山欲放春，更無一點舊風塵。", "對花若不飲一盞，却恐梅花解笑人。"]'),
('75657aac-f55c-46b7-a1f5-71fd501800a9','同長卿梅下飲茶','鄒浩','宋','宋诗','song-poetry','','[]','不置一杯酒，惟煎兩碗茶。',24,'全唐诗/poet.song.70000.json','["不置一杯酒，惟煎兩碗茶。", "須知高意别，用此對梅花。"]'),
('bf2c38b7-b181-4d63-bca7-e35311018530','張糾惠吳洞簦','鄒浩','宋','宋诗','song-poetry','','[]','茶選修仁方破碾，簦分吳洞忽當筵。',32,'全唐诗/poet.song.70000.json','["茶選修仁方破碾，簦分吳洞忽當筵。", "君謨遠矣知難作，試取一瓢江水煎。"]'),
('dffd2177-c40a-4fea-8803-5f6b1d3fae8d','次韻和答稷臣見貽之句','鄒浩','宋','宋诗','song-poetry','','[]','瘴癘侵凌鬢欲華，鳳凰飛詔下天涯。',64,'全唐诗/poet.song.70000.json','["瘴癘侵凌鬢欲華，鳳凰飛詔下天涯。", "有知病骨將枯日，忽遇靈丹躡彩霞。", "赫赫千齡方啓運，熙熙六合共爲家。", "此恩碎首知難報，空感來篇似永嘉。"]'),
('98a41bc2-ff50-4d99-aca0-b06b7df77b22','次韻和李學文所示二篇  其一','鄒浩','宋','宋诗','song-poetry','','[]','材氣無雙是隴西，扁舟還指舊山溪。',64,'全唐诗/poet.song.70000.json','["材氣無雙是隴西，扁舟還指舊山溪。", "非關呂覽難更字，要使班輸别造梯。", "塵外光陰歸作者，道中消息在寥兮。", "它年峻捷黄金榜，路入三吳手重携。"]'),
('6f238838-4669-43d6-9d9b-0824ab9de7cf','次韻和李學文所示二篇  其二','鄒浩','宋','宋诗','song-poetry','','[]','大明端拱赭衣紅，正想豪英入彀中。',64,'全唐诗/poet.song.70000.json','["大明端拱赭衣紅，正想豪英入彀中。", "但使學優迎命達，莫將年少歎途窮。", "三秋水闊魚依藻，一日天高鶴出籠。", "持我此篇歸獻壽，蒼梧歡動曉來風。"]'),
('7929a6bc-8a5a-4494-95db-c3a864d06c6a','移漢陽','鄒浩','宋','宋诗','song-poetry','','[]','漢陰丈人渾沌修，漢陽居士逍遙遊。',32,'全唐诗/poet.song.70000.json','["漢陰丈人渾沌修，漢陽居士逍遙遊。", "中分漢水共天地，能别此心惟白鷗。"]'),
('237c95c5-6220-41f8-982a-189362e33b98','畫山  其一','鄒浩','宋','宋诗','song-poetry','','[]','幾年密與畫山鄰，今日歸航駐水濱。',32,'全唐诗/poet.song.70000.json','["幾年密與畫山鄰，今日歸航駐水濱。", "天亦有心酬我願，歛雲收霧日光新。"]'),
('a07e158f-09f4-49f7-a996-5bcffc40d69e','畫山  其二','鄒浩','宋','宋诗','song-poetry','','[]','三峰闊展映天長，大巧由來未易量。',32,'全唐诗/poet.song.70000.json','["三峰闊展映天長，大巧由來未易量。", "我欲移歸殿前去，萬年千載對君王。"]'),
('887a5e0a-1181-4991-96fa-4b19b87863da','畫山  其三','鄒浩','宋','宋诗','song-poetry','','[]','掃成屏障幾千春，洗雨吹風轉更明。',32,'全唐诗/poet.song.70000.json','["掃成屏障幾千春，洗雨吹風轉更明。", "應是天工醉時筆，重重粉墨尚縱横。"]');
